var ALL_Q=[{"id": 1, "section": "马克思主义基本原理", "type": "单选题", "number": 1, "stem": "作为中国共产党和社会主义事业指导思想的马克思主义是指（", "options": {"A": "中国化的马克思主义", "B": "马克思恩格斯以及列宁学说的体系和中国化的马克思主义", "C": "马克思恩格斯创立的基本理论、基本观点和学说的体系", "D": "马克思恩格斯和列宁的学说体系"}, "answer": "B", "explanation": "此题考查的知识点是作为中国共产党和社会主义事业指导思想的马克思主义的含义。中国共产党的指导思想是广义的马克思主义，包括：马克思恩格斯的基本理论、观点方法；列宁的继承和发展；毛泽东思想和中国特色社会主义理论体系即中国化的马克思主义。显然B是最全面的答案。"},{"id": 2, "section": "马克思主义基本原理", "type": "单选题", "number": 2, "stem": "马克思主义产生的经济社会条件是（）。", "options": {"A": "资本主义固有矛盾的发展", "B": "资本主义生产力和生产关系之间的矛盾", "C": "工人阶级与资本家阶级之间的阶级矛盾的加剧", "D": "社会化大生产同生产资料资本家私人占有之间的矛盾的激化"}, "answer": "A", "explanation": "此题考查的知识点是马克思主义产生的经济、社会历史条件。资本主义固有矛盾的发展，为马克思主义的产生提供了经济社会的条件和基础。选项BCD都是选项A的内容展开，所以正确的选项为AO0思想政治工亻乍人员晋升职称政氵台理论考试复习材料000应马克思主义最重要的理论品质是（A.吐故纳新B.科学严谨〖答案]DC.博大精深坚持一切从实际出发，理论联系实际，实事求是，在实践中检验真理和发展真理，是马克思主义最重要的理论品质。这种与时俱进的理论品质是160多年来马克思主义始终保持蓬勃生命力的关键所在。这种品质是马克思主义理论本质的反映，是人类认识发展规律的具体体现，是理论创新的内在要求。“马克思主义具有与时俱进的理论品质”，这是江泽民同志在庆祝中国共产党成立80周年大会上的重要讲话中所作出的一个极其重要的科学论断。这个论断既是马克思主义诞生以来160多年历史经验的科学总结，又有鲜明的现实针对性和理论意义。这一科学论断突出地强调了马克思主义是伴随着时代、形势的发展而发展的，是一个对马克思主义科学性的新概括。马克思主义这种与时俱进的理论品质是通过两种基本的形式表现出来的。第一种形式，是后人与时俱进，对前人的"},{"id": 3, "section": "马克思主义基本原理", "type": "单选题", "number": 4, "stem": "马克思主义哲学解决哲学基本问题的出发点是〈）。", "options": {"A": "物质第一性，精神第二性", "B": "理论和实践的关系", "C": "实践", "D": "自然和社会的关系"}, "answer": "C", "explanation": ""},{"id": 4, "section": "马克思主义基本原理", "type": "单选题", "number": 5, "stem": "马克思把黑格尔的辩证法称为（", "options": {"A": "“合理内核”", "B": "“基本内核”", "C": "精髓", "D": "核」心"}, "answer": "A", "explanation": ""},{"id": 5, "section": "马克思主义基本原理", "type": "单选题", "number": 6, "stem": "马克思主义产生以前，长期占统治地位的历史观是（）。", "options": {"A": "唯物史观", "B": "唯心史观", "C": "激变论", "D": "庸俗进化论"}, "answer": "B", "explanation": ""},{"id": 6, "section": "马克思主义基本原理", "type": "单选题", "number": 7, "stem": "马克思主义产生的经济社会历史条件是（）。", "options": {"A": "无产阶级作为独立的政治力量登上历史舞台", "B": "马克思、恩格斯完成了世界观的转变", "C": "马克思、恩格斯汲取了人类文明的优秀成果", "D": "资本主义社会的发展和基本矛盾的显现"}, "answer": "D", "explanation": "马克思主义的产生，是众多因素合力促成的结果。A项是马克思主义产生的现实需要；B项是马克思主义产生的主观条件；C项是马克思主义的理论来源。只有D项契合题干的设问。"},{"id": 7, "section": "马克思主义基本原理", "type": "单选题", "number": 8, "stem": "马克思主义产生的现实需要是（）。", "options": {"A": "无产阶级作为独立的政治力量登上历史舞台", "B": "马克思、恩格斯完成了世界观和阶级立场的转变", "C": "马克思、恩格斯汲取了人类文明的优秀成果", "D": "资本主义社会的相当发展和基本矛盾的显现"}, "answer": "A", "explanation": ""},{"id": 8, "section": "马克思主义基本原理", "type": "单选题", "number": 9, "stem": "马克思从资产阶级古典政治经济学家那里继承的最重要的思想是（）。", "options": {"A": "唯物论", "B": "辩证法", "C": "劳动价值论", "D": "剩余价值学说"}, "answer": "C", "explanation": ""},{"id": 9, "section": "马克思主义基本原理", "type": "单选题", "number": 10, "stem": "马克思主义的阶级基础是（）。", "options": {"A": "无产阶级反对资产阶级的斗争", "C": "无产阶级", "D": "无产阶级政党"}, "answer": "C", "explanation": "&工农联盟D.无产阶级政党A是马克思主义产生的实践基础；B是无产阶级专政的阶级基础；D是无产阶级革命的领导力量。"},{"id": 10, "section": "马克思主义基本原理", "type": "单选题", "number": 11, "stem": "马克思主义中国化的本质是（）。", "options": {"A": "马克思主义科学性的体现", "B": "一个以中国国情为基础的全新理论", "C": "用现成的马克思主义理论直接解答、解决中国的现实问题", "D": "用马克思主义基本理论指导中国革命和建设，并在这个过程中发展马克思主义"}, "answer": "D", "explanation": "此题考查的知识点是马克思主义在实践中的发展。马克思主义中国化的本质就是要考虑中国革命和建设的特殊性，用马克思主义基本理论指导中国革命和建设，在这个过程中发展马克思主义、与时俱进。选项A不够准确，选项BC本身错误，所以正确答案是DO"},{"id": 11, "section": "马克思主义基本原理", "type": "单选题", "number": 12, "stem": "马克思主义最根本的世界观和方法论是（）。", "options": {"A": "辩证唯物主义和历史唯物主义", "B": "唯物论和辩证法", "C": "科学社会主义", "D": "政治经济学"}, "answer": "A", "explanation": ""},{"id": 12, "section": "马克思主义基本原理", "type": "单选题", "number": 13, "stem": "马克思主义最鲜明的政治立场是（）·", "options": {"A": "推翻资本主义社会", "B": "建立无产阶级专政", "C": "建立生产资料公有制", "D": "致力于实现最广大人民的根本利益"}, "answer": "D", "explanation": ""},{"id": 13, "section": "马克思主义基本原理", "type": "单选题", "number": 14, "stem": "马克思主义最崇高的社会理想是（）。", "options": {"A": "推翻资本主义社会", "B": "实现共产主义社会", "C": "建立生产资料公有制", "D": "建立无产阶级专政"}, "answer": "B", "explanation": ""},{"id": 14, "section": "马克思主义基本原理", "type": "多选题", "number": 1, "stem": "作为一个完整的科学体系》马克思主义理论体系的三个组成部分是（卜？0。", "options": {"A": "马克思主义政治学", "B": "马克思主义政治经济学", "C": "马克思主义哲学", "D": "科学社会主义"}, "answer": "BCD", "explanation": ""},{"id": 15, "section": "马克思主义基本原理", "type": "多选题", "number": 2, "stem": "国古典哲学、英国古典政治经济学和法国、英国空想社会主义是马克思主义直接的理论来源。属于德国古典哲学、英国古典政治经济学和法国、英国空想社会主义代表人物的有（）。", "options": {"A": "苏格拉底和托马斯·莫尔", "B": "圣西门和傅立叶", "C": "黑格尔和费尔巴哈", "D": "亚当．斯密和大卫．李嘉图"}, "answer": "BCD", "explanation": ""},{"id": 16, "section": "马克思主义基本原理", "type": "多选题", "number": 3, "stem": "马克思、恩格斯之所以能鸲实现社会主义思想从空想到科学的飞跃，是因为他们独创了（", "options": {"A": "劳动价值论", "B": "剩余价值学说", "C": "历史唯物主义", "D": "辩证法"}, "answer": "BC", "explanation": ""},{"id": 17, "section": "马克思主义基本原理", "type": "多选题", "number": 4, "stem": "马克思主义的科学性和革命性可以概括为（", "options": {"A": "辩证唯物主义和历史唯物主义是马克思主义最根本的世界观和方法论", "B": "最广大人民的根本利益是马克思主义最鲜明的政治立场", "C": "一切从实际出发，实事求是，在实践中检验和发展真理是马克思主义最重要的理论品质", "D": "实现共产主义是马克思主义最崇高的社会理想"}, "answer": "ABCD", "explanation": "我们坚持马克思主义的基本立场、基本观点和基本方法，就是要辩证唯物主义和历史唯物主义的世界观和方法论，即马克思主义哲学，坚持实现最广大人民的根本利益的政治立场，坚持一切从实际出发，实事求是，在实践中检验真理和发展真理，把握和顺应人类社会发展的客观规律，不断推进中国特色社会主义事业的发展，、为实现共产主义的崇高社会理想而奋斗。马克思主义哲学是无产阶级科学的世界观和方法论，马克思、下篇练习题恩格斯在实践的基础上创立了马克思主义哲学，它的全部理论来自于实践，又经过实践的检验，所以我们说它的理论具有科学性。故选项A应选。马克思主义是在无产阶级革命实践中产生、发展起来的，是无产阶级根本利益的科学表现。马克思主义是“改变世界”的科学、指导全人类解放的科学。如果说无产阶级是人类解放的“心脏”，那么马克思主义就是人类解放的“头脑\"。这说明马克思主义具有革命性。故选项B应选。选项C说的是马克思主义与时俱进的理论品质，与时俱进的理论品质是马克思主义始终保持生命力的关键所在，这种属性是马克思主义理论本质的反映，马克思主义理论的本质属性就在于它的彻底的科学性、坚定的革命性和自觉的实践性，而彻底的科学性是最根本的"},{"id": 18, "section": "马克思主义基本原理", "type": "单选题", "number": 1, "stem": "恩格斯第一次明确指出：全部哲学，特别是近代哲学的重大的基本问题是", "options": {"A": "哲学与人类的关系问题", "B": "人与自然界的关系问题", "C": "思维和存在的关系问题", "D": "主体和客体的关系问题"}, "answer": "C", "explanation": ""},{"id": 19, "section": "马克思主义基本原理", "type": "单选题", "number": 2, "stem": "根据对哲学基本问题第一方面的回答，哲学可分为（", "options": {"A": "唯物主义和唯心主义", "B": "可知论和不可知论", "C": "辩证法和形而上学", "D": "唯物史观和唯心史观"}, "answer": "A", "explanation": ""},{"id": 20, "section": "马克思主义基本原理", "type": "单选题", "number": 3, "stem": "在唯物主义发展过程中，出现了三种基本形态：朴素唯物主义、形而上学唯物主义和辩证唯物主义。以下哪项是区分唯物主义三种形态的重要依据（）·", "options": {"A": "一元论还是二元论", "B": "世界是否统一于物质", "C": "世界是否可知", "D": "对物质认识的不同深度和广度"}, "answer": "D", "explanation": ""},{"id": 21, "section": "马克思主义基本原理", "type": "单选题", "number": 4, "stem": "有一副对联，上联是“橘子洲，洲旁舟，舟行洲不行”；下联是“天心阁，阁中鸽，鸽飞阁不飞”。这形象地说明了运动和静止是相互依存的，静止是（）·", "options": {"A": "运动的普遍状态", "B": "运动的内在原因", "C": "运动的衡量尺度", "D": "运动的存在方式"}, "answer": "C", "explanation": ""},{"id": 22, "section": "马克思主义基本原理", "type": "单选题", "number": 5, "stem": "“对事物从客体的或直观的形式去理解，而不是把它们当做人的感性活动，当做实践去理解。\"这是（）。", "options": {"A": "客观唯心主义的观点", "C": "辩证唯物主义的观点", "D": "形而上学唯物主义的观点"}, "answer": "D", "explanation": "&主观唯心主义的观点D.形而上学唯物主义的观点此题考查的知识点是形而上学唯物主义。题干中的这句话出自马克思的《关于费尔巴哈的提纲》。“从客体的或直观的形式去理解”即不从实践的角度、主体的角度去理解现实，不理解主体人在实践活动、认识活动中的能动性。这是形而上学唯物主义的观点。所以本题的正确选项是D。"},{"id": 23, "section": "马克思主义基本原理", "type": "单选题", "number": 6, "stem": "“理在事先。”这一观点属于（）。", "options": {"A": "辩证唯物主义", "B": "历史唯物主义", "C": "主观唯心主义", "D": "客观唯心主义·"}, "answer": "D", "explanation": "此题考查的知识点是客观唯心主义。客观唯心主义认为世界的本原是人之外的某种神秘莫测的精神力量，其常用“理”“理念”和“绝对精神”来表述。本题中的“理”便属于客观精神。所以本题的正确选项是D。"},{"id": 24, "section": "马克思主义基本原理", "type": "单选题", "number": 7, "stem": "宋朝画家文与可的住宅周围有很多竹子。他一年四季注意观察竹子的变化，对竹子的形状，姿态有着透彻的了解，因而画出的竹子生动逼真。有诗人称赞他：“与可画竹时，胸中有成竹。”这一事实体现的哲学道理是（）。", "options": {"A": "意识是物质长期发展的产物", "B": "意识是人脑的机能", "C": "意识是对客观世界的反映", "D": "物质具有不依赖于意识的客观实在性"}, "answer": "C", "explanation": "此题考查的知识点是意识的能动作用。从题干中可以看出，文与可之所以能画出生动逼真的竹子，是他长期观察，对竹子有透彻理解的结果。这说明人脑不会自动产生意识，只有当客观事物作用于人的感觉器官，并反映到人脑之后，才能形成意识，也就是说，意识是对客观世界的能动反映。A项是意识的起源，B项是意识的本质，D项是物质的特性，均不符合。正确答案是co"},{"id": 25, "section": "马克思主义基本原理", "type": "单选题", "number": 8, "stem": "休谟说：“感觉是人和世界之间的屏障。”这一观点是（）·", "options": {"A": "唯心主义的观点", "B": "辩证法的观点", "C": "可知论的观点", "D": "不可知论的观点"}, "answer": "D", "explanation": ""},{"id": 26, "section": "马克思主义基本原理", "type": "单选题", "number": 9, "stem": "哲学中的物质范畴是对物质世界多样性和统一性所作的最高概括。自然科学中具体的物质形态和物质结构随着科学的发展而不断变化，但无论出现怎样的情形，都不可能改变马克思主义哲学关于物质范畴的唯一特性。物质的唯一特性是（）。", "options": {"A": "运动性", "B": "客观实在性", "C": "时空特性", "D": "可知性"}, "answer": "B", "explanation": ""},{"id": 27, "section": "马克思主义基本原理", "type": "单选题", "number": 10, "stem": "“世界上除了运动着的物质之外，什么也没有\"》这是（）。一33一", "options": {"A": "否认精神性存在的唯心主义观点", "B": "主张世界统一于物质的辩证唯物主义观点", "C": "否认静止的诡辩论观点", "D": "把人的意识铧成某种特殊的“精细物质”的机械唯物主义观点"}, "answer": "B", "explanation": "此题考查的知识点是世界的物质统一性。列宁提出：“世界上除了运动着的物质，什么也没有，而运动着的物质只有在空间和时间中运动。”列宁的这句话说明，世界上的一切事物和现象，包括意识现象，归根到底都是物质的表现形态；世界上的一切变化和发展，其原因都在于物质世界自身，即世界是多样性的物质统一。所以，本题的正确选项是BO11·马克思指出：“观念的东西不外是移入人的头脑并在人的头脑中改造过的物质的东西而已。\"这表明（A.意识是客观存在的主观映像B.人脑是意识的源泉C.意识是人脑分泌出来的D.观念的东西和物质的东西没有本质区别〖答案〗A此题考查的知识点是意识的本质。题干中“移人”“改造”“物质”几个关键词，说明物质决定意识，意识是人脑对物质的能动反映。意识的内容是客观的，形式是主观的，是客观内容和主观形式的有机统一。A选项正确。选项B属于唯心主义的观点，正确说法是“实践是认识的来源\"；选项c是恩格斯当年批评过的庸俗唯物主义观点；D选项不是马克思主义的观点。"},{"id": 28, "section": "马克思主义基本原理", "type": "单选题", "number": 12, "stem": "对物质和物质具体形态之间关系表述正确的是（）。", "options": {"A": "第一性和第二性的关系", "C": "整体和部分的关系", "D": "具体和抽象的关系"}, "answer": "B", "explanation": "&共性和个性的关系D.具体和抽象的关系此题考查的知识点是物质和物质具体形态的关系。物质的具体形态由于自然界物质运动的形式及结构功能不同，其表现形态是无限多样和不可穷尽的。在物质世界中，每一个具体的物质形态都有自己的规定性，都有自己特殊的质，彼此有别，由此形成物质世界的多样性。物质概念抽象的是物质具体形态的共性，即物质是从万事万物中概括抽象出来的，物质存在于具体物质形态中，而物质的具体形态是物质的具体表现，二者之间是共性与个性的关系，抽象与具体的关系。正确答案是BO选项D顺序说反了，应为抽象和具体的关系，与题干物质和物质的具体形态呼应。"},{"id": 29, "section": "马克思主义基本原理", "type": "单选题", "number": 13, "stem": "相对论原理证明，物质的质量与能量的统一是可以计算的，时空的性质不仅取决一34．于物质的运动，而且更重要的是取决于物质分布本身。这说明（", "options": {"A": "主观的时空观念必然是空洞的抽象", "B": "时空可以脱离物质而存在", "C": "时空只是物质存在的形式", "D": "物质运动是时空的形式"}, "answer": "C", "explanation": "解析此题考查的知识点是时空是物质运动的存在形式。相对论原理说明：时空不能离开物质而存在，必须依赖于物质才有意义，时空是物质运动的存在形式。选项B不符合题意；选项D颠倒了物质运动和时空的关系；选项A与此题无关，所以本题选"},{"id": 30, "section": "马克思主义基本原理", "type": "单选题", "number": 14, "stem": "人在心情愉快时，会感到“光阴似箭”．心情抑郁时，则感到“度日如年\"。这表明（", "options": {"A": "时间是人在主观上的感觉", "B": "人们的时间观念具有可变性", "C": "时间具有不可知性", "D": "时间随人的感觉的变化而变化"}, "answer": "B", "explanation": ""},{"id": 31, "section": "马克思主义基本原理", "type": "单选题", "number": 15, "stem": "20世纪70年代，印度发现了脱离人类社会而由狼抚育并与狼共同生活的“狼孩”。科学家发现，“狼孩\"没有意识，这一事实说明意识的产生（）。", "options": {"A": "不仅是自然界长期发展的产物，而且是社会的产物", "B": "不仅是物质现象而且是社会现象", "C": "是社会的产物，而不是自然界发展的产物", "D": "不仅反映自然界而且反映社会"}, "answer": "A", "explanation": "此题考查的知识点是人类意识的起源和本质。从意识的起源来看，意识是物质世界高度发展的产物，它既是自然界长期发展的产物，又是社会的直接产物。在意识的产生过程中，，起了决定性作用。劳动为意识的产生提供了客观的需要和可能，而劳动一开始就是社会性的活动。社会性的劳动促使了语言的产生，语言的产生对于意识的形成具有决定意义。狼孩没有意识正说明了这一点。正确答案是AO"},{"id": 32, "section": "马克思主义基本原理", "type": "单选题", "number": 16, "stem": "“动中有静，静中有动\"包含的哲学道理是（）。", "options": {"A": "运动和静止的辩证统一", "B": "物质和运动的辩证统一", "C": "形而上学和诡辩论的统一", "D": "唯物论和辩证法的统一"}, "answer": "A", "explanation": ""},{"id": 33, "section": "马克思主义基本原理", "type": "单选题", "number": 17, "stem": "在实践的基本形式中，最终起决定作用的是（）·", "options": {"A": "物质生产劳动", "B": "政治实践", "C": "处理社会关系的实践", "D": "科学实验"}, "answer": "A", "explanation": ""},{"id": 34, "section": "马克思主义基本原理", "type": "单选题", "number": 18, "stem": "在马克思主义看来，实践是（）。", "options": {"A": "人们社会生活中的一切活动", "B": "人们能动地认识世界的精神活动", "C": "人能适应夕卜界环境的本能活动", "D": "人们能动地改造世界的客观物质性活动"}, "answer": "D", "explanation": "〔解析此题考查的知识点是实践的本质含义。马克思主义认为：实践是人类能动地改造世界的客观物质性活动。由此看来，选项A的外延过大，选项BC与马克思主义的实践观不符。所以本题的正确选项为DO"},{"id": 35, "section": "马克思主义基本原理", "type": "单选题", "number": 19, "stem": "一些地方的人们掠夺性的滥挖草原上的干草，以获得一定的经济效益，却破坏了草原植被，造成土地沙漠化，一遇到大风》沙尘暴铺天盖地，给人们带来巨大灾难，这些挖甘草的人们（", "options": {"A": "只看到事物的客观性，没有看到人们的主观能动性", "B": "只看到事物的绝对运动，没有看到事物的相对静止", "C": "只看到眼前的直接联系，没有看到长远的间接联系", "D": "只看到物与物之间的联系，没有看到人与人之间的联系"}, "answer": "C", "explanation": "此题考查的知识点是联系的多样性。宇宙间的一切事物都处于普遍联系之中，这要求我们必须从事物固有的联系出发，对多种联系进行具体分析，用以指导我们的实践。人们只要眼前的经济利益，说明看到了直接联系；不顾破坏生态环境带来的危害，说明人们忽视了间接联系，所以正确答案是co选项ABD均为相近的迷惑项，都不符合题意。"},{"id": 36, "section": "马克思主义基本原理", "type": "单选题", "number": 20, "stem": "马克思主义的活的灵魂是（", "options": {"A": "实事求是", "B": "矛盾分析法", "C": "唯物史观", "D": "具体问题具体分析·"}, "answer": "D", "explanation": ""},{"id": 37, "section": "马克思主义基本原理", "type": "单选题", "number": 21, "stem": "“燕子低飞蛇过道，必有大雨到\"这句吾包含的主要哲学道理是（）·", "options": {"A": "世界是普遍联系的", "B": "世界是永恒发展的", "C": "世界是物质的", "D": "矛盾具有普遍性解析]此题考查的知识点是事物的普遍联系。题干谚语说的是燕子、蛇的活动方式与气象变化之间的联系，显然，其说明的是世界是普遍联系的（A）。选项BD与题干内容无关。选项C不够准确。所以，最能说明题意的是选项A"}, "answer": "A", "explanation": ""},{"id": 38, "section": "马克思主义基本原理", "type": "单选题", "number": 22, "stem": "“沉舟侧畔千帆过，病树前头万木春。”“芳林新叶催陈叶，流水前波让后波£'这两句诗包含的哲学道理是（）·", "options": {"A": "矛盾是事物发展的动力", "B": "事物是本质和现象的统一", "C": "事物的发展是量变和质变的统一", "D": "新事物代替旧事物是事物发展的总趋势"}, "answer": "D", "explanation": "此题考查的知识点是发展的实质。发展是新事物的产生和旧事物的灭亡。新事物必然战胜旧事物，这是由新事物的本质特点和事物发展的辩证本性决定的。就本题来说，四个选项全部正确，但最能体现这两首诗的最佳选项是D。因为“沉舟”和“病树”“陈叶”和“后波”都是旧事物的代表，而“千帆过”和“万木春”“新叶”和“前波”则代表新事物的发展趋势，所以本题选D。"},{"id": 39, "section": "马克思主义基本原理", "type": "单选题", "number": 23, "stem": "唯物辩证法的实质和核心是（）。", "options": {"A": "对立统一规律", "B": "质量互变规律", "C": "否定之否定规律", "D": "联系和发展"}, "answer": "A", "explanation": ""},{"id": 40, "section": "马克思主义基本原理", "type": "单选题", "number": 24, "stem": "矛盾的两种基本属性是（）·", "options": {"A": "普遍性和特殊性", "B": "同一性和斗争性", "C": "对抗性和非对抗性", "D": "可知性和不可知性"}, "answer": "B", "explanation": "（解析此题考查的知识点是矛盾及其同一性和斗争性。矛盾就是对立统一，就是同一．思想政治工作人员晋升职称政氵台理论考试复习材料00E的性和斗争性的关系，同一性和斗争性是矛盾的基本属性。所以本题的正确选项是BO"},{"id": 41, "section": "马克思主义基本原理", "type": "单选题", "number": 25, "stem": "在自然界，没有上，就无所谓下；在社会中，没有先进，就无所谓落后；在认识中，没有正确，就无所谓错误。这说明（", "options": {"A": "矛盾双方是互相排斥的", "B": "矛盾双方是相互渗透的", "C": "矛盾双方是相互依存的", "D": "矛盾双方是相互转化的"}, "answer": "C", "explanation": ""},{"id": 42, "section": "马克思主义基本原理", "type": "单选题", "number": 26, "stem": "'居安思危'这句成讠吾体现的哲学道理是（）。", "options": {"A": "矛盾双方在一定条件下可以互相转化", "B": "矛盾既具有普遍性又具有特殊性", "C": "内因和外因共同作用下推动事物的发展", "D": "事物发展是量变和质变的统一"}, "answer": "A", "explanation": "此题考查的知识点是矛盾的同一性。“安”与“危”作为对立着的双方，在一定条件下互相转化。所以本题的正确选项是AO"},{"id": 43, "section": "马克思主义基本原理", "type": "单选题", "number": 27, "stem": "毛泽东在《矛盾论》中认为，矛盾问题的精髓是（）。", "options": {"A": "矛盾的同一性和斗争性的关系", "C": "矛盾普遍性和特殊性的辩证关系", "D": "内因和外因的关系"}, "answer": "C", "explanation": "B，主要矛盾和次要矛盾的关系D.内因和外因的关系此题考查的知识点是矛盾问题的精髓。矛盾问题的精髓就是共性和个性的关系，即矛盾晋性和特殊性的关系。正确答案是co"},{"id": 44, "section": "马克思主义基本原理", "type": "单选题", "number": 28, "stem": "“一个志在有大成就的人，他必须知道限制自己。反之，那些什么事都想做的人，其实什么事都不能做，而终归于失败。”这段话告诉我们（", "options": {"A": "要学会分清事物矛盾的性质", "B": "要懂得对事物进行矛盾分析", "C": "要具体矛盾具体分析", "D": "要抓主要矛盾，不要平均使用力量"}, "answer": "D", "explanation": ""},{"id": 45, "section": "马克思主义基本原理", "type": "单选题", "number": 29, "stem": "辩证否定的实质是“扬弃”，其基本含义是（）。．38．练习题", "options": {"A": "抛弃", "B": "既克服又保留", "C": "纯粹的否定", "D": "事物中好的方面和坏的方面的组合"}, "answer": "B", "explanation": ""},{"id": 46, "section": "马克思主义基本原理", "type": "单选题", "number": 30, "stem": "唯物辩证法的否定之否定规律揭示了事物发展的〈", "options": {"A": "方向和道路", "B": "形式和状态", "C": "结构和功能", "D": "源泉和动力"}, "answer": "A", "explanation": "此题考查的知识点带有一定的综合性。唯物辩证法三大规律所揭示的内容是各不相同的：对立统一规律揭示的是事物发展的源泉和动力，量互变规律揭示的是事物存在的形式和状态，否定之否定親律揭示的是事物发展的方向和道路。所以本题正确选项为AO"},{"id": 47, "section": "马克思主义基本原理", "type": "单选题", "number": 31, "stem": "把不同事物区分开来的依据是（）。", "options": {"A": "事物的度", "B": "事物的内在规定性", "C": "事物的属性", "D": "事物的量"}, "answer": "B", "explanation": ""},{"id": 48, "section": "马克思主义基本原理", "type": "单选题", "number": 32, "stem": "部分质变是指（）。", "options": {"A": "质变过程中有量的扩张，在总的量变过程中有局部或阶段性的质变", "C": "量变是质变的必要准备", "D": "量变的客观性和普遍性"}, "answer": "B", "explanation": "此题考查的知识点是部分质变的内涵。部分质变分为阶段性部分质变和局部性部分质变两种形式。阶段性部分质变是指事物的根本性质未变，而比较次要的性质发生了变化，从而使事物的发展呈现阶段性。局部性部分质变是指事物全局的性质未变，而其中某些部分发生了性质的变化。正确答案是BO"},{"id": 49, "section": "马克思主义基本原理", "type": "单选题", "number": 33, "stem": "“大海捞针\"是一种（）。", "options": {"A": "现实的可能性", "B": "抽象的可能性", "C": "现实性", "D": "不可能性"}, "answer": "B", "explanation": ""},{"id": 50, "section": "马克思主义基本原理", "type": "单选题", "number": 34, "stem": "“如果偶然性不起任何作用的话，那么世界历史就会带着非常神秘的性质。'这一论断体现了（", "options": {"A": "必然性比偶然性重要", "B": "偶然性比必然性重要", "C": "偶然性对事物发展的重要作用", "D": "偶然性是科学的敌人"}, "answer": "C", "explanation": "此题考查的知识点是偶然性的作用。偶然性是指并非确定发生的，可以出现，可以不出现，可以这样出现或那样出现的不确定趋势。偶然性产生于非根本矛盾和外部条件。偶然性是不稳定的、暂时的、不确定的，是事物发展中的个别表现。偶然性对事物的发展不起决定作用，但是对事物的发展具有重要的影响作用。正确答案是C。"},{"id": 51, "section": "马克思主义基本原理", "type": "单选题", "number": 35, "stem": "有人认为：“如果事物的表现形式和事物的本质会直接合二为一，一些科学家就都成为多余的了。\"这一命题（）。", "options": {"A": "夸大了现象和本质的区别", "B": "否认了现象和本质的区别", "C": "揭示了现象和本质的区别", "D": "夸大了现象和本质的统一"}, "answer": "C", "explanation": ""},{"id": 52, "section": "马克思主义基本原理", "type": "单选题", "number": 36, "stem": "有一则箴言：溪水和岩石的斗争中，胜利的总是溪水，不是因为力量，而是因为坚持。\"“坚持就是胜利\"的哲理在于（", "options": {"A": "肯定中包含着否定的因素", "C": "必然性通过偶然性开辟道路", "D": "有其因必有其果"}, "answer": "B", "explanation": "围量变必然引起质变D.有其因必有其果此题考查的知识点是对质量互变规律的理解和运用。本题关键词是“坚持”和“胜利”，“坚持”是一个量的积累过程，“胜利”是坚持的结果，其所蕴含的哲理是量变达到一定程度必然引起质变（B）。选项D与题干相关，但该选项主要说明的是溪水与岩石之间的因果关系，不是“坚持就能胜利”所蕴含的哲理，属于干扰力极强的选项。所以，正确选项是"},{"id": 53, "section": "马克思主义基本原理", "type": "单选题", "number": 37, "stem": "主观辩证法与客观辩证法的关系是（）。", "options": {"A": "反映与被反映的关系", "B": "唯心主义与唯物主义的关系", "C": "抽象与具体的关系", "D": "唯心辩证法与唯物辩证法的关系"}, "answer": "A", "explanation": ""},{"id": 54, "section": "马克思主义基本原理", "type": "单选题", "number": 38, "stem": "恩格斯说'历史从哪里开始，思想进程也应当从哪里开始。而思想进程的进一步发展不过是历史过程在抽象的、理论上前后一贯的形式上的反映；这种反映是经过修正的，然而是按照现实的历史过程本身的规律修正的。\"这段话表明（", "options": {"A": "历史是由理论推演出来的", "B": "历史是理论的基础，理论是历史经过修正的再现", "C": "历史进程与逻辑进程是完全一致的", "D": "理论反映的是历史过程的全部内容"}, "answer": "B", "explanation": ""},{"id": 55, "section": "马克思主义基本原理", "type": "单选题", "number": 39, "stem": "从抽象上升到具体的思维方法的逻辑起点是（）。", "options": {"A": "客观事物", "B": "社会实践", "C": "感性认识", "D": "思维抽象"}, "answer": "D", "explanation": ""},{"id": 56, "section": "马克思主义基本原理", "type": "单选题", "number": 40, "stem": "我国战国时代哲学家荀子说：“天彳亍有常，不为尧存》不为桀亡。”荀子的这句话说明了（", "options": {"A": "社会规律的客观性", "B": "规律的平等性", "C": "规律是可以认识的", "D": "规律的能动作用"}, "answer": "A", "explanation": ""},{"id": 57, "section": "马克思主义基本原理", "type": "单选题", "number": 41, "stem": "社会规律和自然规律的区别在于（）。", "options": {"A": "是否具有客观性", "B": "是否具有强制性", "C": "是否具有稳定性", "D": "是否能够离开人类的实践活动而存在"}, "answer": "D", "explanation": "／此题考查的知识点是自然规律和社会规律的区别。只要是规律，就有客观性、稳定性和强制性的特点。社会规律不同于自然规律之处在于，其必须通过人们有意识有目的的实践体现出来，离开了人类的实践活动，即脱离了人类社会，社会规律将无法存在，而自然规律可以脱离人类社会而存在。所以，正确选项是DO"},{"id": 58, "section": "马克思主义基本原理", "type": "单选题", "number": 42, "stem": "马克思说：人在“劳动过程结束时得到的结果，在这个过程开始时就已经在劳动者的表象中存在着，即已经观念地存在着。\"人的活动的整个过程，就是围绕着“观念地存在着\"的目标和蓝图而进行的。这说明了（", "options": {"A": "人比动物具有更好的记忆力0意识具有能动作用", "B": "观念的作用是不能够忽略的", "D": "人的劳动过程的特殊性"}, "answer": "C", "explanation": ".观念的作用是不能够忽略的D.人的劳动过程的特殊性〔解析此题考查的知识点是意识的能动作用。从马克思的这句话中可以看出：在人的意识中，不仅预先规定了活动的目标，而且为实现这一目标又预先规定了活动的方式和步骤。这就是同一定的目的性相联系的活动的计划性，从而体现了意识的能动作用。正确选项是"},{"id": 59, "section": "马克思主义基本原理", "type": "单选题", "number": 43, "stem": "由于社会历史是由有意识有目的活动着的人创造的，因此（）。", "options": {"A": "社会规律是由人所创造的", "B": "人们可以改造或者消灭社会规律", "C": "社会发展规律只能通过人的自觉活动起作用人的活动都体现社会规律", "D": "人的活动都体现社会规律"}, "answer": "C", "explanation": "此题考查的知识点是社会发展的规律性和人的自觉活动。社会规律是通过人的活动表现的，社会历史发展具有客观规律性、必然性和因果制约性。A项的错误在于社会规律不是由人所创造的，它否认了社会规律的客观性。B项的错误在于人不能改造或者消灭规律。D项的错误在于并非所有人的活动都体现社会规律。正确答案是CO"},{"id": 60, "section": "马克思主义基本原理", "type": "单选题", "number": 44, "stem": "对感性材料“去粗取精、去伪存真、由此及彼、由表及里的改造制作功夫”，说明意识具有（）。", "options": {"A": "目的性和计划性c能动创造性", "B": "对生理活动的控制作用", "D": "指导实践改造世界的作用"}, "answer": "C", "explanation": "此题考查的知识点是意识能动作用的表现，是一道理解性试题，难度较大。四个选项都是意识能动作用的表现，但是只有AC两个选项与题干有关。本题考查的核心是对感性材料的“改造制作功夫”，这是典型的创造性的体现，只有创造性才能“改造制作”。同时，对感性材料加工制作的过程，也就是由感性认识上升到理性认识，由认识现象到认识本质的过程。而这一过程也恰好说明意识具有能动创造性。因而C选项正确。很多考生将题干的核心单纯地放在了“去粗取精、去伪存真，由此及彼、由表及里”的目的性上，因而会误认为A选项正确。B选项，对生理活动的调节在题干中没有体现，故不选。D选项，指导实践改造世界也与题干无关，题干所说是从感性认识上升为理性认识，还在认识范围内，还没有指导实践，所以也不能选。"},{"id": 61, "section": "马克思主义基本原理", "type": "单选题", "number": 45, "stem": "客观规律性与主观能动性统一的基础是（）。", "options": {"A": "实践", "B": "规律", "C": "意识", "D": "人"}, "answer": "A", "explanation": "B，规律c.意识此题考查的知识点是乖是客观规律性与主观能动性统一的基础。尊重事物发展的规律与发挥人的主观能动性是辩证统一的。而实践是客观规律性与主观能动性统一的基础。所以本题选AO"},{"id": 62, "section": "马克思主义基本原理", "type": "单选题", "number": 46, "stem": "中国跨过资本主义发展阶段直接进入社会主义社会后，在社会主义建设问题上，中国人民经过反复实践和探索，又走上了建设中国特色社会主义的成功之路。这一事实说", "options": {"A": "社会历史规律具有决定作用", "B": "主体的选择可以不受社会历史规律的制约", "C": "在社会历史发展问题上，主体没有选择的自由", "D": "社会发展是历史决定性与主体选择性的有机统一"}, "answer": "D", "explanation": "此题考查的知识点是社会历史趋向与主体选择的关系。社会历史发展具有规律性，但并不因此而否定主体人在可能性空间内的选择。题干中“跨过”和“中国特色社会主义”表明主体选择在社会发展中的作用。选项A正确，但与题意不符。选项BC本身就是错昃的。所以，本题的正确选项是DO"},{"id": 63, "section": "马克思主义基本原理", "type": "单选题", "number": 47, "stem": "中国古代哲学家荀子说：“心不在焉，则白黑在前而目不见，雷鼓在侧而耳不闻。”这段话表明人的意识具有（）。", "options": {"A": "客观性", "C": "对象性", "D": "任意性"}, "answer": "B", "explanation": "埸能动性C.对象性D.任意性此题考查的知识点是意识的能动作用。“心不在焉”强调的是意识的能动作用。所以只有B是符合题意的正确选项。．思想政治工亻乍人员晋升职称台理论考试复习材料"},{"id": 64, "section": "马克思主义基本原理", "type": "单选题", "number": 48, "stem": "相信“意念移物\"，甚至相信可以用意念来直接改变物质结构，就是（", "options": {"A": "主张精神主宰客观物质世界的主观唯心论", "B": "主张精神是脱离人脑独立存在的客观唯心论", "C": "认为人的思想是特殊物质的机械唯物主义", "D": "认为人具有主观能动性的实践唯物主义"}, "answer": "A", "explanation": "此题考查的知识点是主观唯心主义和客观唯心主义的区别。题干指的是主观唯心主义对意识能动作用的夸大。所以A是符合题意的正确选项。"},{"id": 65, "section": "马克思主义基本原理", "type": "单选题", "number": 49, "stem": "《坛经》中记载：“时有风吹幡动，一僧曰风动，一僧曰幡动，议论不已·惠能进曰：不是风动，不是幡动，仁者心动·”这段话表明惠能关于运动的基本观点是（）·", "options": {"A": "运动是物质的根本属性", "B": "运动与物质是不可分割的", "C": "精神运动是物质运动的一种形式", "D": "精神是运动的主体"}, "answer": "D", "explanation": "．运动与物质是不可分割的D.精神是运动的主体此题考查的知识点是物质和运动的关系。物质和运动是不可分割的。一方面，运动是物质的存在方式和根本属性，物质是运动着的物质，脱离运动的物质是不存在的，想不运动的物质。．將导致形而上学另一方面，物质是一切运动变化和发展过程的实在基础和承担者，世界上没有离开物质的运动，任何形式的运动都有它的物质主体，设想无物质的运动，将导致唯心主义。惠能所说即是精神的运动，属于唯心主义运动观。所以选项D是符合题意的正确选项。ABC是唯物主义的运动观，是正确说法，但不符合题意。"},{"id": 66, "section": "马克思主义基本原理", "type": "单选题", "number": 50, "stem": "实践高于（理论的）认识，是因为实践具有（）。", "options": {"A": "普遍性", "B": "绝对性", "C": "客观实在性", "D": "直接现实性"}, "answer": "D", "explanation": "[解析}此题考查的知识点是实践的基本特征。实践是物质性的活动，具有直接现实也构成实践活动的要素都是可感知的客观实在，实践的结果都是客观的，实践的水平、广度、深度和发展过程，都受着客观条件的制约和客观规律的支配。因此，实践是同主观认识活动相区别的感性物质活动。实践高于理论的认识就在于实践具有直接现实性。实践可以把主观的东西变为客观的东西，用客观同认识加以比较，就能检验出理论的认识是否具有真理性。所以只有D是正确选项。"},{"id": 67, "section": "马克思主义基本原理", "type": "单选题", "number": 51, "stem": "列宁对辩证唯物主义物质范畴的定义是通过（）。", "options": {"A": "物质与意识的关系界定的", "B": "个别与一般的关系界定的", "C": "哲学与具体科学的关系界定的", "D": "认识与实践的关系界定的"}, "answer": "B", "explanation": ".个别与一般的关系界定的D.认识与实践的关系界定的此题考查的知识点是马克思主义物质观。马克思主义哲学从物质与惹识的辩证关系上，对物质概念作出了全面的科学的规定。列宁指出：“物质是标志客观实在的哲学范畴，这种客观实在是人感觉到的，它不依赖于我们的感觉而存在，为我们的感觉所复写、摄影、反映。”可见，列宁是从物质与意识的关系上来把握物质的。物质的唯一特性是客观实在性，它存在于人的意识之外，可以为人的意识所反映。A是正确选项。"},{"id": 68, "section": "马克思主义基本原理", "type": "单选题", "number": 52, "stem": "\"运动应当从它的反面即从静止找到它的量度\"，因为静止是（）。", "options": {"A": "运动的根本属性和存在方式", "B": "过去运动的结果和未来运动的出发点", "C": "运动的原因和根据", "D": "运动的基础和承担者"}, "answer": "B", "explanation": "此题考查的知识点是运动和为祉一，静止是运动的特殊状态，静止是相对的有条件的，是间断性和连续性的统一，是过去运动的结果和未来运动的出发点。所以只有B选项是正确选项。"},{"id": 69, "section": "马克思主义基本原理", "type": "单选题", "number": 53, "stem": "先有工程设计图，然后施工建成大厦·这一事实说明（", "options": {"A": "意识产生物质", "B": "意识转化为物质", "C": "意识决定物质", "D": "意识创造物质"}, "answer": "B", "explanation": "此题考查的知识点是物质和意识的关系以及意识的能动性。ACD选项明显属于唯心主义观点，是错误选项。工程设计图体现了意识活动的目的性和计划性，通过施工实践把意识活动的目的性和计划性转化为现实。转化的关键是实践环节。意识的能动作用是在物质的决定作用的前提下进行的。所以只有B选项是正确选项。"},{"id": 70, "section": "马克思主义基本原理", "type": "单选题", "number": 54, "stem": "“人不能两次踏进同一条河流\"和“人一次也不能踏进同一条河流·”这两种说法", "options": {"A": "都是辩证法的观点", "B": "都是诡辩论的观点", "C": "前者是辩证法的观点，后者是诡辩论的观点", "D": "前者是诡辩论的观点，后者是辩证法的观点"}, "answer": "C", "explanation": "此题考查的知识点是运动和静止的关系。\"人不能两次踏进同一条河流\"是古希腊哲学家赫拉克利特提出的辩证法的观点；\"人一次也不能踏进同一条河流\"是其弟子克拉底鲁提出的，是夸大绝对运动否定相对静止所导致的相对主义诡辩论观点。所以只有C选项是正确选项。"},{"id": 71, "section": "马克思主义基本原理", "type": "单选题", "number": 55, "stem": "唯物辩证法的是扌旨（）。", "options": {"A": "一切前后相继的现象之间的联系", "B": "一切同时并存的现象之间的联系", "C": "引起和被引起的现象之间的联系", "D": "反映和被反映的现象之间的联系0思想政治工亻乍人员晋升职称政氵台理论考试复习材料"}, "answer": "C", "explanation": "此题考查的知识点是唯物辩证法基本范畴中的原因和结果。原因是引起一定现象的现象，结果是被引起的现象。只有这迴垣这引帥关系因果爹。因果联系一定是前后相继的，但是前后相继的联系，并不都是因果联系，只有引起和被引起的才是，所以A项是错误的；同时并存的现象没有前后相继的特点，肯定不是因果联系，所以，B项是错误的；D项反映和被反映的联系不是因果联系，所以，D项也是错误的。"},{"id": 72, "section": "马克思主义基本原理", "type": "单选题", "number": 56, "stem": "区分事物发展过程中量变和质变的根本标志是（）。", "options": {"A": "事物的变化是否迅速", "B": "事物的变化过程中是否有部分质变", "C": "事物的变化是否超过度的范围", "D": "事物的变化是否显著"}, "answer": "C", "explanation": "此题考查的知识点是量变质变规律。任何事物都是质和量的统一体，作为质和量之统一的度，就是事物保持自己质的量的限度、范围。量变和质变是事物发展变化的两种形式，量变和质变各有不同的特点，然而，只有事物的变化是否超出度的范围，才是区分量变和质变的根本标志。所以，只有c项才是正确的答案。"},{"id": 73, "section": "马克思主义基本原理", "type": "单选题", "number": 57, "stem": "哲学上的物质范畴与自然科学上的物质范畴的关系是（）。", "options": {"A": "本原和派生的关系", "B": "普遍和特殊的关系", "C": "本质和现象的关系", "D": "形式和内容的关系"}, "answer": "B", "explanation": ""},{"id": 74, "section": "马克思主义基本原理", "type": "单选题", "number": 58, "stem": "辩证唯物主义认为事物发展的规律是（）。", "options": {"A": "思维对事物本质的概念和反映", "B": "用来整理感性材料的思维形式", "C": "事物内在的本质的必然的稳定的联系", "D": "事物联系和发展的基本环节"}, "answer": "C", "explanation": "此题考查的知识点是规律的含义。规律是事物运动发展过程中本质的、必然的、稳定的联系。故选项c正确。A是理性认识的含义。B是康德的唯心主义观点。D是“范畴\"的含义。"},{"id": 75, "section": "马克思主义基本原理", "type": "单选题", "number": 59, "stem": "在工作中防止“过”或“不及”的关键在于（）。", "options": {"A": "抓住事物的主要矛盾", "B": "认识事物的量", "C": "确定事物的质", "D": "把握事物的度"}, "answer": "D", "explanation": ""},{"id": 76, "section": "马克思主义基本原理", "type": "单选题", "number": 60, "stem": "在哲学史中我们可以看到，各种唯心主义派别之间的差异和矛盾，常常有利于唯物主义的发展，这一事实说明（", "options": {"A": "矛盾一方克服另一方促使事物发展", "B": "矛盾一方的发展可以为另一方的发展提供条件", "C": "矛盾双方中每一方的自身矛盾，可以为另一方的发展所利用", "D": "矛盾双方的融洽促使事物发展"}, "answer": "C", "explanation": "此题考查的知识点是矛盾的同一性和斗争性在事物发展中的作用。由于矛盾双方相互依存、互为存在的条件，矛盾双方可以利用对方的发展使自己获得发展；矛盾同一性使对立双方相互利用，相互吸引对方有利于自身的因素而得到发展；矛盾双方的内在同一性规定着事物转化的可能和发展的基本趋势。ABD项不是矛盾同一性和斗争性在事物发展中的作用，是错误选项；只有c项符合矛盾同一性和斗争性在事物发展中的作用。"},{"id": 77, "section": "马克思主义基本原理", "type": "单选题", "number": 61, "stem": "事物内部的肯定方面和否定方面的对立统一运动，从表现形式上看〈）。", "options": {"A": "是事物自我完善和发展的过程", "B": "是新事物战胜旧事物的过程0一是螺旋式上升或波浪式前进的过程", "D": "是不断周而复始的循环过程"}, "answer": "C", "explanation": "解析〕此题考查的知识点是否定之否定规律。否定之否定规律揭示了事物发展的方向和道路，是事物的发展呈现出螺旋式上升或波浪式前进的总趋势。只有C选项是符合否定之否定规律的正确选项。"},{"id": 78, "section": "马克思主义基本原理", "type": "单选题", "number": 62, "stem": "孔子在《论语》中讲到：\"出门如见大宾，使民如承大祭。己所不欲，勿施于人。\"己所不欲，勿施于人\"所蕴含的哲理是（）。", "options": {"A": "矛盾的同一性和斗争性", "B": "矛盾的普遍性和特殊性", "C": "主要矛盾和次要矛盾", "D": "内部矛盾和外部矛盾"}, "answer": "A", "explanation": "B，矛盾的普遍性和特殊性D.内部矛盾和外部矛盾此题考查的知识点是矛盾的基本属性同一性和斗争性。“己所不欲，勿施于人”所体现的哲理就是要善于从对立面的角度看问题，即从对立中把握同一，从同一中把握对立。即矛盾的同一性和斗争性原理。"},{"id": 79, "section": "马克思主义基本原理", "type": "单选题", "number": 63, "stem": "．动者恒动，静者恒静。”这一说法属于（）。", "options": {"A": "辩证法的观点", "B": "形而上学的观点", "C": "诡辩论的观点", "D": "唯心主义的观点"}, "answer": "B", "explanation": ""},{"id": 80, "section": "马克思主义基本原理", "type": "单选题", "number": 64, "stem": "“庖丁解牛”“游刃有余\"“揠苗助长”“苗枯田荒\"，它们的共同启示是（),", "options": {"A": "现象是规律的外在表现形式C／尊重规律是取得成功的基础", "B": "人在规律面前是无能为力的", "D": "解放思想是取得成功的条件"}, "answer": "C", "explanation": ""},{"id": 81, "section": "马克思主义基本原理", "type": "单选题", "number": 65, "stem": "如果要开一张包治百病的药方，或者拟定一个适用于一切情况的一般准则，那是很荒谬的。因为这种做法违背了（", "options": {"A": "任何事物都包含矛盾的原理", "B": "不同的矛盾用不同方法解决的原理", "C": "事物之间普遍联系的原理", "D": "特殊性中包含着普遍性的原理"}, "answer": "B", "explanation": ""},{"id": 82, "section": "马克思主义基本原理", "type": "单选题", "number": 66, "stem": "我们党统一战线中的“又斗争又联合\"的策略和在改革开放中坚持“对外开放和独立自主、自力更生相统一”的方针的哲学依据是（）。", "options": {"A": "否定之否定规律对立统一规律", "B": "事物发展的过程论", "D": "质量互变规律"}, "answer": "C", "explanation": ""},{"id": 83, "section": "马克思主义基本原理", "type": "单选题", "number": 67, "stem": "在人与世界的相互作用中，人与世界同时得到了改变，并获得日益丰富的内容·造成这一变化的基础是（）。", "options": {"A": "自然界自身的运动人的实践活动", "B": "人的意识的能动作用", "D": "工具的制造与使用"}, "answer": "C", "explanation": ""},{"id": 84, "section": "马克思主义基本原理", "type": "单选题", "number": 68, "stem": "“忧心忡忡的穷人甚至对最美丽的风景都没有什么感觉\"“贩卖矿物的商人只看矿物的商业价值，他没有矿物学的感觉\"。这两句话（）。", "options": {"A": "表明人的意识不是对客观世界的反映", "B": "是主观唯心主义的观点，表明人的感觉具有主体性", "D": "是经验论的观点"}, "answer": "C", "explanation": "此题考查的知识点是意识的能动性和主体性。人与动物不同，动物被动机械地反映外界，而人则是积极主动地感觉、反映外界事物，即人具有主体差异性、主观能动性。不同的主体对同一事物由于不同的目的，在观察、感觉、反映时，其指向是不同的，因此所获得的认识也是不同的。因此，c选项正确。A选项自身表述错误；B选项，虽然因主体差异没能感受到风景和矿物的存在，但并未否认物质的存在，也未否认物质第一性，故不符合题意；D选项与题干无关。"},{"id": 85, "section": "马克思主义基本原理", "type": "单选题", "number": 69, "stem": "习近平总书记在党的二十大报告中指出：“坚持把国家和民族发展放在自己力量的基点上，坚持把中国发展进步的命运牢牢掌握在自己手中。\"这一论断蕴含的哲理是内因是事物发展变化的根据，决定着事物发展的基本趋势", "options": {"B": "人们在自己选定的条件下创造历史，要发扬历史主动精神", "C": "量变是质变的必要准备，质变是量变的必然结果", "D": "新事物在本质上优越于旧事物，具有强大生命力"}, "answer": "A", "explanation": ""},{"id": 86, "section": "马克思主义基本原理", "type": "多选题", "number": 1, "stem": "思维和存在的关系问题之所以是哲学的基本问题，其原因包括（", "options": {"A": "该问题是人类认识和改造世界不能回避的最基本问题", "B": "该问题是划分哲学中基本派别的依据", "C": "该问题是人类实际生活中的基本问题", "D": "该问题决定着人们思想和行动的出发点与方向"}, "answer": "ABCD", "explanation": "本题考查思维与存在关系问题作为哲学基本问题的原因或者说依据。该知识点是马克思主义基本原理第二章的一个基本内容。只需基本的记忆与理解，该题就可做对。"},{"section": "马克思主义基本原理", "type": "多选题", "stem": "根据对哲学基本问题第二方面的不同回答，哲学可以分为（）。", "options": {"A": "可知论", "B": "不可知论", "C": "唯物主义", "D": "唯心主义"}, "answer": "AB", "explanation": "【解析】哲学基本问题是思维和存在（意识和物质）的关系问题。哲学基本问题包括两个方面的内容：其一，思维和存在、意识和物质，究竟谁是世界的本原，即物质和意识何者是第一性、何者是第二性的问题；其二，思维和存在的同一性问题，即思维能否认识或正确认识存在的问题。根据对哲学基本问题第一方面的不同回答，哲学可划分为唯物主义和唯心主义两个对立的基本派别。根据对哲学基本问题第二方面的不同回答，哲学又可以划分为可知论和不可知论。 3．下列观点中属于唯心主义的有（）。 A. 感觉是人与外界事物之间的屏障 B. 形存则神存，形灭则神灭 C. 吾心便是宇宙，宇宙即是吾心 D. 存在就是被感知", "id": 87},{"section": "马克思主义基本原理", "type": "多选题", "stem": "我们之所以说马克思主义哲学是完备的唯物主义，是因为它在内容上实现了（）。", "options": {"A": "唯物主义和辩证法的高度统一", "B": "可知论与唯物论的高度统一", "C": "世界观和方法论的统一", "D": "唯物辩证的自然观和历史观的高度统一"}, "answer": "AD", "explanation": "【解析】马克思主义哲学的创立是哲学史上的伟大变革，其关键就在于，它以科学的实践观为基础，正确地解决了人与自然、人与社会即人与世界的关系，从而实现了唯物论和辩证法、唯物主义自然观和历史观的统一。因此，正确答案是 AD。", "id": 88},{"section": "马克思主义基本原理", "type": "多选题", "stem": "马克思主义哲学在哲学史上的伟大变革，表现在它实现了（）。", "options": {"A": "唯物主义和辩证法的统一", "B": "形式与内容的统一", "C": "唯物主义的自然观和历史观的统一", "D": "感性认识和理性认识的统一"}, "answer": "AC", "explanation": "【解析】该题考查马克思主义哲学创立的重大意义，或者说马克思主义哲学作为哲学史上伟大变革的表现。马克思主义哲学的产生实现了哲学内容上的革命，实现了“两个统一”，即实现了唯物主义与辩证法的统一、唯物主义自然观与历史观的统一。内容上，马克思主义哲学克服了旧哲学中唯物论与辩证法、自然观与历史观的分离，实现了唯物论与辩证法、唯物主义自然观与历史观的有机统一。因此选项 AC 符合题干要求。", "id": 89},{"section": "马克思主义基本原理", "type": "多选题", "stem": "客观实在性是物质的（）。", "options": {"A": "本质规定", "B": "根本属性", "C": "唯一特性", "D": "最高共性"}, "answer": "ACD", "explanation": "【解析】物质的本质规定、唯一特性和最高共性是客观实在性，所以 ACD 为正确。物质的根本属性是运动，所以 B 项错误。在大量记忆知识内容之后，清晰地界定各知识点之间的差异非常重要，否则就会造成混乱。", "id": 90},{"section": "马克思主义基本原理", "type": "多选题", "stem": "“物质”范畴是唯物主义世界观的基石。但辩证唯物主义和旧唯物主义对“物质”的定义存在差异。二者对“物质”范畴的认识是（）。", "options": {"A": "抽象和具体的关系", "B": "共性和个性的关系", "C": "普遍性和特殊性的关系", "D": "一般和特殊的关系"}, "answer": "ABCD", "explanation": "【解析】唯物主义经历了古代朴素唯物主义、近代形而上学唯物主义（以上二者合称旧唯物主义）、辩证唯物主义和历史唯物主义（现代辩证唯物主义）三种形态。三者的区别，也体现在对物质范畴的定义上。古代朴素唯物主义直观地将物质归结为一种或几种具体的实物，是一种天才但非科学的猜测。近代形而上学唯物主义将物质归结为物质的构成单 位——原子，混淆了自然科学的物质结构概念和哲学物质范畴的区别，经不起自然科学发展的检验，更不能说明社会生活的物质本质。现代辩证唯物主义从无限多样的物质现象中抽象出物质的共同本性，从哲学上进行了最高的概括。所以，新旧唯物主义“物质”的认识，是共性与个性的关系。在马克思主义哲学中，抽象和具体的关系、共性和个性的关系、普遍性和特殊性的关系、一般和特殊的关系，是相同的意思。", "id": 91},{"section": "马克思主义基本原理", "type": "多选题", "stem": "马克思主义哲学物质观的理论意义是（）。", "options": {"A": "坚持了唯物主义一元论，批判了唯心主义一元论和二元论", "B": "坚持了能动的反映论和可知论，批判了不可知论", "C": "体现了唯物论和辩证法的统一", "D": "坚持了唯物主义自然观和唯物主义历史观的统一"}, "answer": "ABCD", "explanation": "【解析】该题考查考生对马克思主义哲学物质观的意义的理解。这是关于物质观的基本知识点。马克思主义哲学物质观的意义主要表现在它坚持了唯物主义一元论；坚持了能动的反映论和可知论；体现了唯物论和辩证法的统一；体现了自然观和历史观的统一。因此正确答案是 ABCD。 10\\. 实践是客观物质活动，这体现在（）。 A. 实践的主体和客体是客观的 B. 实践的手段是客观的 C. 实践活动本身和结果是客观的 D. 实践受着客观条件的制约和客观规律的支配", "id": 92},{"section": "马克思主义基本原理", "type": "多选题", "stem": "爱因斯坦说：“想象比知识更重要，因为知识是有限的，而想象力概括着世界上的一切，推动着进步，并且是知识进化的源泉。”科学研究需要想象，而合理的、科学的想象（）。", "options": {"A": "充分发挥了人的思维潜能", "B": "要以一定的知识储备为基础", "C": "是意识能动性的一种具体表现", "D": "是主观形式和客观内容的统一"}, "answer": "ABCD", "explanation": "【解析】辩证唯物主义认为，意识的能动性，是主观形式和客观内容的统一。要充分发挥意识的主观能动性必须尊重客观规律，需要以一定的知识储备为基础。科学研究需要想象，而合理的、科学的想象就是以一定的知识储备为基础，是在主观形式和客观内容统一的基础上充分发挥人的思维潜能，是意识能动性的一种具体表现之一。因此，正确答案是ABCD。 14\\. 下列正确反映了辩证唯物主义运动观的是（）。 A. “风定花犹落，鸟鸣山更幽。” B. 天体运动是由于 “精通力学和几何学的上帝所给予的切线力推动的初速度，才在万有引力作用下运行”。 C. “从最小的东西到最大的东西，从沙粒到太阳……都处于无休止的运动和变化中” D. “事物和状态不过是我们的心灵所采取的一种观点，事物是不存在的，存在的只有流动”", "id": 93},{"section": "马克思主义基本原理", "type": "多选题", "stem": "“物质的两种存在形式离开了物质，当然都是无，都是只在我们头脑中存在的观念抽象”，这段话说明（）。", "options": {"A": "时间和空间是客观的", "B": "时间和空间只是离开物质的形式", "C": "时间和空间是绝对的，又是相对的", "D": "时间和空间是物质运动的存在形式"}, "answer": "AD", "explanation": "【解析】本题考查对时间和空间的认识。恩格斯的这段话表明时间和空间是客观的，是物质存在的形式。选项 B 是唯心主义的选项，是错误的。选项 C 是正确的表述，但与本题 的题干无关，不是题干所强调的含义，所以不选。 19\\. 下列有关实践的主体与客体的相互作用的叙述，正确的是（）。 A. 主体是一定社会关系中从事实践和认识活动的人 B. 客体是主体的实践和认识活动所指向的一切对象 C. 主体能够认识、利用、改造和欣赏客体 D. 客体本身的状况和规律又制约和限定着主体的所有活动", "id": 94},{"section": "马克思主义基本原理", "type": "多选题", "stem": "马克思主义认为，实践是（）。", "options": {"A": "能动地改造物质世界的客观物质性活动", "B": "人类有意识的活动", "C": "人的存在方式", "D": "人类社会的基础"}, "answer": "ABCD", "explanation": "【解析】本题考查对实践观点的正确记忆和理解。四个选项都是关于实践观点的正确表述，都属于辩证唯物主义的选项。这些都是关于实践的最基本知识点。 22\\. 实践的基本形式有（）。 A. 生产实践 B. 社会实践 C. 科学实验 D. 阶级斗争", "id": 95},{"section": "马克思主义基本原理", "type": "多选题", "stem": "联系的特点有（）。", "options": {"A": "客观性", "B": "具体性", "C": "中介性", "D": "普遍性"}, "answer": "ABCD", "explanation": "【解析】作为一个普遍的哲学范畴，联系是指事物内部各要素之间和事物之间相互影响、相互制约和相互作用的关系。联系具有一系列特点：联系具有客观性。事物的联系是事物本身所固有的，不是主观臆想的。因此，选项 A 正确。联系具有普遍性。事物联系的普遍性有三层含义。第一，事物内部的不同部分和要素是相互联系的，也就是说，事物具有内在的结构性，联系具有具体性。第二，任何事物都不能孤立存在，都同其他事物处于一定的相互联系之中。第三，整个世界是相互联系的统一整体。从无机界到有机界，从自然界到人类社会，任何事物都处于普遍联系、交互作用中，不存在完全孤立的东西。这种联系是需要一定中介的，故联系具有中介性。因此，正确答案是 ABCD。", "id": 96},{"section": "马克思主义基本原理", "type": "多选题", "stem": "辩证法的“过程论”的观点认为（）。", "options": {"A": "一切事物都有它的过去、现在和未来", "B": "世界是过程的集合体", "C": "一切事物都是作为过程而存在、作为过程而发展的", "D": "世界是既成事物的集合体"}, "answer": "ABC", "explanation": "【解析】本题考查对辩证的发展观与过程论的认识。唯物辩证法的发展观认为世界是永恒发展的，所以一切都是过程，一切事物都是作为过程而存在、作为过程而发展的，世界是过程的集合体。恩格斯指出：“世界不是既成事物的集合体，而是过程的集合体。”所以，答案是 ABC。而 D 项否认了事物的发展变化，是形而上学的观点。", "id": 97},{"section": "马克思主义基本原理", "type": "多选题", "stem": "对立统一规律是唯物辩证法的核心，这是因为（）。", "options": {"A": "它揭示了事物的普遍联系的根本内容和发展的内在动力", "B": "其他规律是由对立统一规律推演出来的", "C": "它是认识世界和改造世界的根本方法", "D": "它是理解辩证法其他规律和范畴的钥匙"}, "answer": "ACD", "explanation": "【解析】本题考查对立统一规律。选项 ACD 都从某一角度揭示了对立统一规律之所以是辩证法的核心的道理。选项 B 不符合辩证唯物主义的观点，辩证法的其他内容和对立统一规律不是推导和被推导的关系，所以排除 B。 27．下列选项属于矛盾同一性的有（）。 A. 同志间的相互帮助 B. 祸与福在一定条件下的相互转化 C. 磁铁南极和北极的相互依存 D. 两个事物的绝对同一", "id": 98},{"section": "马克思主义基本原理", "type": "多选题", "stem": "下列选项属于矛盾斗争性的表现的有（）。", "options": {"A": "革命阶级和反动阶级之间的斗争", "B": "各地区之间经济发展的不平衡", "C": "人民内部的各种意见分歧", "D": "不同学术观点之间的争议"}, "answer": "ABCD", "explanation": "【解析】矛盾的斗争性是矛盾着的对立面之间相互排斥、相互分离的性质和趋势。由于矛盾的性质不同，矛盾的斗争形式也不同，对于多种多样的斗争形式，可以区分为对抗性和非对抗性两种基本形式。“革命阶级和反动阶级之间的斗争”“各地区之间经济发展的不平衡”“人民内部的各种意见分歧”“不同学术观点之间的争议”都是矛盾斗争性的表现。因此，正确答案是 ABCD。", "id": 99},{"section": "马克思主义基本原理", "type": "多选题", "stem": "“道高一尺，魔高一丈”这个成语所蕴涵的哲理是（）。", "options": {"A": "矛盾双方中一方的自身矛盾，可以为另一方的发展所利用", "B": "矛盾双方在相互斗争中获得发展", "C": "矛盾双方向着自己的对立面转化而得到发展", "D": "矛盾双方可以相互吸收有利于自身的因素得到发展"}, "answer": "BD", "explanation": "【解析】“道高一尺，魔高一丈”体现了矛盾的斗争性。矛盾的斗争性是矛盾着的对立 面之间相互排斥、相互分离的性质和趋势。矛盾的斗争性在事物发展中的作用表现在：第一，矛盾双方的斗争促进矛盾双方力量的变化，党长争高，此消彼长，造成双方力量发展的不平衡，为对立面的转化、事物的质变创造条件，使矛盾双方在相互斗争中获得发展。第二，矛盾双方的斗争，是一种矛盾统一体向另一种矛盾统一体过渡的决定性力量。矛盾的相互排斥、否定促成旧的矛盾统一体破裂和新的矛盾统一体产生，从而使旧事物发展成为新事物，矛盾双方可以相互吸收有利于自身的因素得到发展。因此，正确答案是 BD。 30\\. 矛盾的解决方式主要有（）。 A. 矛盾双方形成协同运动的新形式 B. 矛盾一方克服另一方 C．矛盾双方同归于尽 D．矛盾双方融成一个新事物", "id": 100},{"section": "马克思主义基本原理", "type": "多选题", "stem": "有论者谈到工作的方法，形象地以弹钢琴为例说：“弹钢琴要十个指头都动作，不能有的动，有的不动。但是，十个指头同时按下去，那也不成调子。要产生好的音乐，十个指头的动作要有节奏，要互相配合。”这说明了（）。", "options": {"A": "对待工作要有主次，有重点", "B": "对待事物区别对待、具体问题具体分析", "C": "对待问题要有唯物辩证法的观点", "D": "事物发展是量变质变的相互转化"}, "answer": "ABC", "explanation": "【解析】本题考查对辩证法矛盾问题的理解。该弹钢琴的例子是选自1949年毛泽东的《党委会的工作方法》讲话。毛泽东用该例子来说明对待事物要坚持“两点论”和“重点论”的统一，要具体问题具体分析。要求干部工作要讲主次，有重点。毛泽东的这个例子生动地说明了唯物辩证法中矛盾问题的运用。这个问题与质变量变问题没有联系，所以选项D排除。 35\\. 关于矛盾的特殊性，理解正确的有（）。 A. 它决定事物的特殊本质 B．它在一定条件下向普遍性转化 C．矛盾着的事物及其各个方面均有其特点 D．人的认识从矛盾特殊性开始，科学认识就在于把握矛盾的特殊性", "id": 101},{"section": "马克思主义基本原理", "type": "多选题", "stem": "在事物发展过程中内因和外因的作用及其相互关系是（）。", "options": {"A": "内因只有在一定条件下才起到推动事物发展的作用", "B": "内因是事物变化的根据，是根本原因", "C": "外因是事物变化的条件", "D": "外因通过内因起作用"}, "answer": "BCD", "explanation": "【解析】本题考查矛盾规律的内因与外因关系原理。辩证法认为内因是事物变化发展的根据，外因是事物变化发展的条件，外因通过内因起作用。依据以上辩证法的观点，选项BCD符合要求。", "id": 102},{"section": "马克思主义基本原理", "type": "多选题", "stem": "否定之否定规律揭示了事物发展是（）。", "options": {"A": "自我完善的过程", "B": "直线前进过程和周而复始的循环过程", "C": "量变质变相统一的过程", "D": "前进性和曲折性相统一的过程"}, "answer": "AD", "explanation": "【解析】事物的辩证发展过程经过第一次否定，使矛盾得到初步解决。而处于否定阶段的事物仍然具有片面性，还要经过再次否定，即否定之否定，实现对立面的统一，使矛盾得到解决，事物的辩证发展就是经过两次否定、三个阶段，形成一个周期。否定之否定阶段仿佛是向原来出发点的“回复”，但这是在更高阶段上的“回复”，是“扬弃”的结果，是事物的自我完善过程。因此，选项 A 正确。事物发展是前进性和曲折性的统一。前进性体现在：每一次否定都是质变，都把事物推到新阶段；每一周期都是开放的，不存在不被否定的终点。曲折性体现在回复性上，其中有暂时的停顿和倒退，但是经过曲折终将为事物的发展开辟道路。这表明事物的发展不是直线式的前进而是螺旋式的上升。因此，选项 D 正确。正确答案是 AD。", "id": 103},{"section": "马克思主义基本原理", "type": "多选题", "stem": "1820 年，丹麦物理学家奥斯特在做实验时，突然发现电流的变化引起磁针的偏转。他抓住这一现象进行深入研究，最终揭示了电流的磁效应规律，为后来发明电动机奠定了理论基础。这一事例说明（）。", "options": {"A": "必然性是通过偶然性表现出来的", "B": "偶然性背后隐藏着必然性", "C": "偶然性决定着必然性", "D": "科学研究的目标是发现必然性，偶然性是科学的敌人"}, "answer": "AB", "explanation": "【解析】本题考查必然性与偶然性的辩证关系原理。该试题引用科学发现的事例来说明马克思主义的必然性与偶然性辩证关系原理。唯物辩证法认为，在必然性和偶然性的辩证关系中，必然性是隐藏在偶然性背后的支配力量，必然性决定着偶然性；但必然性是通过偶然性表现出来并为自己开辟道路，必然性体现在偶然性之中。所以选项 AB 表述正确，而 C 错误。科学研究的目标是发现必然性。但必然性隐藏在偶然性之中，科学就是要通过各种偶然性去发现必然性。“偶然性是科学的敌人”是错误的观点。所以 D 也不选。", "id": 104},{"section": "马克思主义基本原理", "type": "多选题", "stem": "毛泽东同志在 1956 年的词句中想象说：“更立西江石壁，截断巫山云雨，高峡出平湖。”近半个世纪后的今天，随着三峡工程的建设，当年诗人的想象变成了现实，这个例子说明（）。", "options": {"A": "可能一定可以变成现实", "B": "人们通过实践可以将意识变成客观现实", "C": "主观的东西一定存在于现实世界中", "D": "可能在一定条件下可以转化为现实"}, "answer": "BD", "explanation": "【解析】本题考查可能与现实、主观与客观的辩证关系，还有实践的作用原理。毛泽东的该词句来自1956年的《水调歌头·游泳》。可能并非一定可以转化为现实，可能只有在一定的条件下才会变成现实。实践的作用，就是将主观的东西变成现实的东西。所以BD正确，A不对。主观的东西，其内容和来源是现实世界的东西，但它本身不一定存在于现实世界中。主观的东西可能是对客观世界的歪曲的虚幻的反映，在客观世界中没有直接对应的原型。所以C不选。", "id": 105},{"section": "马克思主义基本原理", "type": "多选题", "stem": "关于现象和本质，以下理解正确的是（）。", "options": {"A": "任何本质都是通过现象表现出来", "B": "科学研究的任务是要通过现象发现本质", "C": "现象有真象和假象之分", "D": "即使假象也是本质的表现"}, "answer": "ABCD", "explanation": "【解析】本题在于考查对辩证法基本范畴现象与本质的记忆与理解。在本题中，所有选项都是关于现象与本质的正确表述。 41．在辩证思维方法中，逻辑与历史相统一方法的要求有（）。 A. 逻辑的次序与历史事实的顺序必须完全一致 B．逻辑的顺序必须以历史的顺序为基础 想政治工作人员晋升职称政治理论考试复习材料 C. 逻辑是历史的抽象与概括 D. 逻辑的顺序在一定条件下可以与历史的顺序不一致", "id": 106},{"section": "马克思主义基本原理", "type": "多选题", "stem": "马克思说：最蹩脚的建筑师从一开始就比最灵巧的蜜蜂高明的地方，是他在用蜂蜡建筑蜂房以前，已经在自己的头脑中把它建成了。这一命题表明（）。", "options": {"A": "意识总是先于物质而存在", "B": "人的实践活动要以理论为指导", "C": "在一定条件下，人的实践受理论的决定", "D": "人类的意识具有目的性和计划性"}, "answer": "BD", "explanation": "【解析】辩证唯物主义认为，人们做事要注意主观能动性和客观规律性的辩证统一。首先，要尊重客观规律。其次，在尊重客观规律的基础上，要充分发挥主观能动性。意识是能动的，具有目的性、计划性、创造性以及指导实践改造客观世界的作用和指导控制人的行为和生理活动的作用。因此，马克思说：最蹩脚的建筑师从一开始就比最灵巧的蜜蜂高明的地方，是他在用蜂蜡建筑蜂房以前，已经在自己的头脑中把它建成了。其原因是，人类的意识具有目的性和计划性；建筑师的实践活动要以理论为指导。因此，选项 B、选项 D 都正确。选项 A，意识总是先于物质而存在，和辩证唯物主义相悖。选项 C，在一定条件下，人的实践活动受理论的决定也是错误的，在任何时候，都是实践决定理论。因此，正确答案是 BD。 44\\. 下列关于主观能动性在实践中的作用，说法正确的有（）。 A. 主观能动性在实践活动中以一定的现实目的作为核心，以实现自身为归宿，并力图使外部世界按自身的尺度发生改变 B. 主观能动性不仅是实践活动的决定性前提，而且对物质的创造过程起着重大的作用 C. 人的实践活动区别于其他物质活动的本质特点就在于实践具有主体意识性 D. 实践中人的主体意识性体现为人可以克服客观规律", "id": 107},{"section": "马克思主义基本原理", "type": "多选题", "stem": "在实际生活中，下列说法会导致人们不能正确地发挥主观能动作用的是（）。", "options": {"A": "“人有多大胆，地有多大产”", "B": "“不怕做不到，就怕想不到”", "C": "“巧妇难为无米之炊”，因此“要从现实出发，不要从可能出发”", "D": "“宁可误一年，不冒一分险”"}, "answer": "ABD", "explanation": "【解析】选项 ABD 或者犯了主观唯心主义的错误，或者犯了形而上学的错误，因此，都会导致人们不能正确地发挥主观能动性。选项 C 是说物质第一性的观点，而不是意识的能动性问题，与题意不符。所以，正确答案是 ABD。 48．在我国当前的社会主义市场经济中，以尊重规律为借口，不敢锐意进取、积极创新的观点和做法犯的错误有（）。 A. 否认了唯物主义的基本前提 B. 贬低或否认了意识的能动作用 C. 犯了机械决定论的错误 D. 犯了形而上学唯物主义的错误", "id": 108},{"section": "马克思主义基本原理", "type": "多选题", "stem": "统筹兼顾，是我们党在长期社会主义建设实践中形成的重要历史经验，是我们党一贯坚持的科学有效的工作方法，这一方法的哲学依据是（）。", "options": {"A": "矛盾的普遍性和特殊性的辩证关系", "B": "主要矛盾和次要矛盾的辩证关系", "C": "矛盾的同一性和斗争性的辩证关系", "D": "世界是普遍联系的观点"}, "answer": "ABD", "explanation": "【解析】此题考查的知识点是联系和发展，对立统一规律。统筹兼顾是既要抓主要矛盾，又不忽视次要矛盾，统筹兼顾是注意事物之间的联系，统筹兼顾是把事物普遍性和特殊性结合起来考虑问题，所以正确选项是 ABD。", "id": 109},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "“十个明确”“十四个坚持”“十三个方面成就”“六个必须坚持”内在贯通、有机统一，共同构成了习近平新时代中国特色社会主义思想的科学体系。其中，构成了这一思想体系的四梁八柱，发挥着统摄作用的是（）。", "options": {"A": "“十个明确”", "B": "“十四个坚持”", "C": "“十三个方面成就”", "D": "“六个必须坚持”"}, "answer": "A", "explanation": "【解析】“十个明确”是习近平新时代中国特色社会主义思想的主体内容，集中体现了这一思想体系的主要观点和基本精神，构成了这一思想体系的四梁八柱，发挥着统摄作用。A正确。“十四个坚持”是习近平新时代中国特色社会主义思想的重要组成部分，是在治国理政各方面作出的理论分析和政策指导，构成了新时代坚持和发展中国特色社会主义的基本方略。“十三个方面成就”对新时代伟大实践进行了科学总结，全景式地展示了习近平新时代中国特色社会主义思想的理论与实践成果。“六个必须坚持”赋予了马克思主义世界观和方法论以新的时代内涵，彰显了习近平新时代中国特色社会主义思想的理论品格和鲜明特征。BCD错误。 2．以习近平同志为主要代表的中国共产党人，坚持把马克思主义基本原理同中国具体实际相结合、同中华优秀传统文化相结合，深刻总结并充分运用党成立以来的历史经验，从新的实际出发，创立了习近平新时代中国特色社会主义思想。习近平新时代中国特色社会主义思想中的主体内容是（）。 A. “两个确立” B. “十四个坚持” C. “十个明确” D. “十三个方面成就”", "id": 110},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党的二十大提出的“六个必须坚持”，是习近平新时代中国特色社会主义思想的世界观、方法论和贯穿其中的立场观点方法的重要体现。在这“六个必须坚持”中，必须坚持守正创新是（）。", "options": {"A": "根本价值立场", "B": "内在精神特质", "C": "鲜明理论品格", "D": "重要实践要求"}, "answer": "C", "explanation": "【解析】坚持人民至上是根本价值立场；坚持自信自立是内在精神特质；坚持守正创新是鲜明理论品格，体现了变与不变、继承与发展的内在联系；坚持问题导向是重要实践要求；坚持系统观念是基本思想和工作方法；坚持胸怀天下是中国共产党人的境界格局。C 正确，ABD 错误。", "id": 111},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平新时代中国特色社会主义思想是在（）被确立为党必须长期坚持的指导思想。", "options": {"A": "党的十八大", "B": "党的十九大", "C": "党的二十大", "D": "十九届五中全会"}, "answer": "B", "explanation": "【解析】党的十九大把习近平新时代中国特色社会主义思想确立为党必须长期坚持的指导思想并写入党章，实现了党的指导思想的与时俱进。 5\\. 中国特色社会主义进入新时代，我国社会主要矛盾已经转化为（）。 A. 人民日益增长的物质文化需要同落后的社会生产之间的矛盾 B. 人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾 C. 生产力与生产关系、经济基础与上层建筑之间的矛盾 D. 人口、资源、环境与经济发展之间的矛盾", "id": 112},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平新时代中国特色社会主义思想是马克思主义基本原理同中国具体实际相结合、同中华优秀传统文化相结合的重大成果，是坚持“两个结合”的光辉典范。习近平新时代中国特色社会主义思想创立的时代背景有（）。", "options": {"A": "世界百年未有之大变局加速演进", "B": "中华民族伟大复兴进入关键时期", "C": "中国式现代化全面推进拓展", "D": "中国共产党自我革命开辟新的境界"}, "answer": "ABCD", "explanation": "【解析】本题考查习近平新时代中国特色社会主义思想创立的时代背景。习近平新时代中国特色社会主义思想创立的时代背景：第一，世界百年未有之大变局加速演进；第二，中华民族伟大复兴进入关键时期；第三，中国式现代化全面推进拓展；第四，科学社会主义在21世纪的中国焕发新的蓬勃生机；第五，中国共产党自我革命开辟新的境界。因此，选项ABCD正确。", "id": 113},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "在文化传承发展座谈会上，习近平总书记系统总结了中华文明的五大突出特性，科学阐述了“两个结合”的历史逻辑、理论逻辑和实践逻辑。习近平总书记特别指出，“第二个结合”表明（）。", "options": {"A": "我们党对自我革命的认识达到了新高度", "B": "我们党对中国道路、理论、制度的认识达到了新高度", "C": "我们党的历史自信、文化自信达到了新高度", "D": "我们党在传承中华优秀传统文化中推进理论创新的自觉性达到了新高度"}, "answer": "BCD", "explanation": "【解析】本题考查“两个结合”。“两个结合”让中国特色社会主义道路有了更加宏阔深远的历史纵深，拓展了中国特色社会主义道路的文化根基，开辟了广阔的理论和实践创新空间，表明我们党对中国道路、理论、制度的认识达到了新高度，表明我们党的历史自信、文化自信达到了新高度，表明我们党在传承中华优秀传统文化中推进理论创新的自觉性达到了新高度。因此，选项 BCD 正确。选项 A，“自我革命”是党的自身建设问题，而“两个结合”是理论创新与发展的问题，二者不属于一个问题，故排除。 3．习近平新时代中国特色社会主义思想坚持科学社会主义基本原则，深刻总结和充分运用党百年奋斗的历史经验，根据时代和实践发展变化，科学回答了重大时代课题，以全新的视野深化了对共产党执政规律、社会主义建设规律、人类社会发展规律的认识。习近平新时代中国特色社会主义思想科学回答的重大时代课题是（）。 A. 新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会 主义 B. 建设什么样的社会主义现代化强国、怎样建设社会主义现代化强国 C. 建设什么样的长期执政的马克思主义政党、怎样建设长期执政的马克思主义政党 D. 实现什么样的发展、怎样发展 ##### 【答案】ABC 【解析】科学发展观创造性地回答了新形势下“实现什么样的发展、怎样发展”这一重大问题，D 不符合题意。ABC 正确。 4．以习近平同志为主要代表的中国共产党人，", "id": 114},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "历史和实践充分证明，只有社会主义才能救中国，只有社会主义才能发展中国，只有坚持和发展中国特色社会主义才能实现中华民族伟大复兴。一个国家实行什么样的主义，关键要看这个主义能否解决这个国家面临的（）。", "options": {"A": "社会性课题", "B": "政治性课题", "C": "历史性课题", "D": "文化性课题"}, "answer": "C", "explanation": "【解析】本题考查中国特色社会主义具有深厚的历史渊源。一个国家实行什么样的主义，关键要看这个主义能否解决这个国家面临的历史性课题。因此，选项 C 正确。选项 ABD，社会性、政治性和文化性都只是历史进程中的一个方面，不能代表历史的全部，故 不选。 2．科学社会主义诞生170多年来，人类社会发生了翻天覆地的变化，世界资本主义和社会主义都发生了很大变化，但是资本主义的基本矛盾没有变，工人阶级的历史使命没有变，科学社会主义的真理性没有变。科学社会主义基本原则是马克思主义的（）。 A. 活的灵魂 B. 核心内容 C. 基本立场 D. 基本方法", "id": 115},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党的基本路线明确了中国特色社会主义发展的历史方位、主体力量、兴国之要、立国之本、强国之路和奋斗目标，必须牢牢坚持、毫不动摇。实践证明，党的基本路线是（）。", "options": {"A": "坚持和发展中国特色社会主义的行动指南", "B": "我们党的生命线和根本工作路线", "C": "中国共产党的思想路线的核心", "D": "国家的生命线、人民的幸福线"}, "answer": "D", "explanation": "【解析】本题考查党的基本路线。党的基本路线是国家的生命线、人民的幸福线。因此，选项 D 正确。选项 A，党的基本理论是坚持和发展中国特色社会主义的行动指南，故不选。选项 B，群众路线是我们党的生命线和根本工作路线，故不选。选项 C，实事求是是中国共产党思想路线的核心，故不选。", "id": 116},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "“四个全面”战略布局，是新的时代条件下坚持和发展中国特色社会主义、推进改革开放和社会主义现代化建设的战略抉择。“四个全面”战略布局既有战略目标又有战略举措，每个“全面”之间具有紧密的内在逻辑，是一个整体战略部署的有序展开。在“四个全面”中居于引领地位的是（）。", "options": {"A": "全面深化改革", "B": "全面依法治国", "C": "全面从严治党", "D": "全面建设社会主义现代化国家"}, "answer": "D", "explanation": "【解析】全面建设社会主义现代化国家是战略目标，在“四个全面”中居于引领地位；全面深化改革、全面依法治国、全面从严治党是三大战略举措，为全面建设社会主义现代化国家提供重要保障。D 正确，ABC 错误。", "id": 117},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "改革开放以来我们取得一切成绩和进步的根本原因，归结起来就是：开辟了中国特色社会主义道路，形成了中国特色社会主义理论体系，确立了中国特色社会主义制度，发展了中国特色社会主义文化。其中，作为根本保障的是（）。", "options": {"A": "中国特色社会主义道路", "B": "中国特色社会主义理论体系", "C": "中国特色社会主义制度", "D": "中国特色社会主义文化"}, "answer": "C", "explanation": "【解析】改革开放以来我们取得一切成绩和进步的根本原因，归结起来就是：开辟了中国特色社会主义道路，形成了中国特色社会主义理论体系，确立了中国特色社会主义制度，发展了中国特色社会主义文化。其中，道路是实现途径，理论体系是行动指南，制度是根本保障，文化是精神力量，四者统一于中国特色社会主义伟大实践。C 正确。 6．中国特色社会主义进入新时代，是长期以来特别是党的十八大以来我们党领导人民不懈奋斗的必然结果，是我们党在科学把握形势和实践发展变化基础上作出的重大判断。新时代是我国发展新的历史方位，标志着中国特色社会主义事业进入了新的发展阶段。中国特色社会主义进入新时代重大判断的基本依据是（）。 A. 我国社会主要矛盾发生新变化 B. 党的主要任务发生新变化 C．中国和世界关系发生新变化 D．发展理念和思路发生新变化", "id": 118},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "历史和现实充分证明，我们党团结带领全国各族人民探索形成的党的基本理论、基本路线、基本方略是完全正确的，必须长期坚持、全面贯彻。我们党坚定信仰信念、把握历史主动的根本所在是（）。", "options": {"A": "高举中国特色社会主义伟大旗帜", "B": "坚信中国特色社会主义制度", "C": "拥有马克思主义科学理论指导", "D": "坚持人民至上"}, "answer": "C", "explanation": "【解析】本题考查党的基本理论。拥有马克思主义科学理论指导是我们党鲜明的政治品格和强大的政治优势，是我们党坚定信仰信念、把握历史主动的根本所在。因此，选项 C 正确。选项 A，党要在新的历史方位上实现新时代党的历史使命，最根本的就是要高举中国特色社会主义伟大旗帜，故不选。选项 B，坚信中国特色社会主义制度是当代中国发展进步的根本制度保障，故不选。选项 D，坚持人民至上是根本价值立场，体现了历史唯物主义群众史观，故不选。 ##### 多项选择题", "id": 119},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平总书记指出：“党的十一届三中全会是划时代的，开启了改革开放和社会主义现代化建设历史新时期。”改革开放以来我们取得一切成绩和进步的根本原因，归结起来就是（）。", "options": {"A": "开辟了中国特色社会主义道路", "B": "形成了中国特色社会主义理论体系", "C": "确立了中国特色社会主义制度", "D": "发展了中国特色社会主义文化"}, "answer": "ABCD", "explanation": "【解析】本题考查“四个自信”。改革开放以来我们取得一切成绩和进步的根本原因，归结起来就是：开辟了中国特色社会主义道路，形成了中国特色社会主义理论体系，确立了中国特色社会主义制度，发展了中国特色社会主义文化。因此，选项 ABCD 正确。 2．我国社会主要矛盾已经转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾，这改变了1981年中共十一届六中全会通过的《中国共产党中央委员会关于建国以来党的若干历史问题的决议》对主要矛盾的论述。其改变的主要依据是（）。 A. 我国社会生产力水平总体上有了显著提高 B. 人民不仅对物质文化生活提出更高的要求，而且对其他方面的要求日益增长 C. 我国仍处于并将长期处于社会主义初级阶段 D．影响满足人民日益增长的美好生活需要的因素很多，但主要是发展的不平衡不充分问题", "id": 120},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "党的十八大以来，我们党科学把握我国发展新的历史方位，作出中国特色社会主义进入新时代的重大政治判断。新时代的伟大变革，在党史、新中国史、改革开放史、社会主义发展史、中华民族发展史上具有里程碑意义。主要表现在（）。", "options": {"A": "走过百年奋斗历程的中国共产党在革命性锻造中更加坚强有力", "B": "中国人民的前进动力更加强大、奋斗精神更加昂扬、必胜信念更加坚定，焕发出更为强烈的历史自觉和主动精神", "C": "改革开放和社会主义现代化建设深入推进，书写了经济快速发展和社会长期稳 定两大奇迹新篇章", "D": "科学社会主义在 21 世纪的中国焕发出新的蓬勃生机，中国式现代化为人类实现现代化提供了新的选择"}, "answer": "ABCD", "explanation": "【解析】本题考查新时代的伟大变革的里程碑意义。第一，走过百年奋斗历程的中国共产党在革命性锻造中更加坚强有力；第二，中国人民的前进动力更加强大、奋斗精神更加昂扬、必胜信念更加坚定，焕发出更为强烈的历史自觉和主动精神；第三，改革开放和社会主义现代化建设深入推进，书写了经济快速发展和社会长期稳定两大奇迹新篇章，我国发展具备了更为坚实的物质基础、更为完善的制度保证，实现中华民族伟大复兴进入了不可逆转的历史进程；第四，科学社会主义在21世纪的中国焕发出新的蓬勃生机，中国式现代化为人类实现现代化提供了新的选择。因此，选项ABCD正确。 4\\. 中国特色社会主义进入新时代，我国社会主要矛盾已经转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。新时代我国社会主要矛盾的变化（）。 A. 是在社会主义初级阶段中发生的变化 B．是关系全局的历史性变化 C. 没有改变我国仍处于并将长期处于社会主义初级阶段的基本国情 D．正确反映了我国全面建成小康社会之后的新特点", "id": 121},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "“70后、80后、90后、00后，他们走出去看世界之前，中国已经可以平视这个世界了。”2021年全国两会期间，习近平总书记的一席话，令人感慨万千。坚定中国特色社会主义道路自信、理论自信、制度自信、文化自信，中国共产党和中国人民有着深厚的根基和底气，根基和底气在于我们有（）。", "options": {"A": "中国共产党的坚强领导", "B": "更为完善的制度保证、更为坚实的物质基础、更为主动的精神力量", "C": "连绵不绝的中华 5000 多年文明", "D": "广大的国土和世界第一人口大国的独特优势"}, "answer": "ABC", "explanation": "【解析】习近平指出：“当今世界，要说哪个政党、哪个国家、哪个民族能够自信的话，那中国共产党、中华人民共和国、中华民族是最有理由自信的。”我们有中国共产党的坚强领导，这是中国特色社会主义最本质的特征，是中国特色社会主义制度的最大优势；我们有新中国成立、改革开放以来特别是党的十八大以来形成的更为完善的制度保证、更为坚实的物质基础、更为主动的精神力量，时与势在我们一边，这是中国特色社会主义所独具的发展优势；我们有连绵不绝的中华5000多年文明，这是中国特色社会主义的文化根脉和突出优势，是我们在世界风云激荡中站稳脚跟的根基。因此ABC正确，D错误。", "id": 122},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "中国梦是国家的梦、民族的梦，也是每一个中国人的梦。“民惟邦本，本固邦宁”，国家的富强、民族的振兴都要以人民的权利得到保障、利益得到实现、幸福得到满足为条件。因此，国家富强、民族振兴的根本出发点和落脚点是（）。", "options": {"A": "人民幸福", "B": "政治民主", "C": "社会和谐", "D": "经济发达"}, "answer": "A", "explanation": "【解析】本题考查中国梦。人民幸福，就是要坚持以人民为中心，增进人民福祉，促进人的全面发展，朝着共同富裕方向稳步前进。人民幸福是国家富强、民族振兴的根本出发点和落脚点。因此，选项 A 正确。选项 BCD 不符合题意，故不选。 2．中国式现代化是一项前无古人的开创性、探索性事业，也是一个复杂的系统工程。推进现代化最坚实的根基、最深厚的力量是（）。 A. 中国特色社会主义道路 B. 人民群众 C. 斗争精神 D. 深化改革开放", "id": 123},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平指出：“中国式现代化，是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。”与西方现代化相比，中国式现代化的显著标志是（）。", "options": {"A": "人口规模巨大的现代化", "B": "全体人民共同富裕的现代化", "C": "人与自然和谐共生的现代化", "D": "走和平发展道路的现代化"}, "answer": "B", "explanation": "【解析】本题考查中国式现代化。西方现代化的最大弊端，就是以资本为中心而不是以人民为中心。中国式现代化是全体人民共同富裕的现代化，这是中国式现代化区别于西方现代化的显著标志。因此，选项 B 正确。选项 ACD，均属于 “中国式现代化的中国特色”，但并不是与西方现代化最显著的区别，故不选。 4．实现中华民族伟大复兴，就是中华民族近代以来最伟大的梦想。100多年来，中国共产党团结带领中国人民进行的一切奋斗、一切牺牲、一切创造，归结起来就是一个主题：实现中华民族伟大复兴。实现中华民族伟大复兴的中国梦，本质是（）。 A. 全面建成富强民主文明和谐美丽的社会主义现代化强国 B．使中华民族更加坚强有力地自立于世界民族之林，为人类作出新的更大的贡献 C. 坚持以人民为中心，增进人民福祉，促进人的全面发展，朝着共同富裕方向稳步前进 D. 国家富强、民族振兴、人民幸福", "id": 124},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面建成小康社会不是终点，而是新生活、新奋斗的起点。党的二十大进一步明确，从2020年到21世纪中叶可以分为两个阶段来安排。第一个阶段的奋斗目标是（）。", "options": {"A": "全体人民共同富裕基本实现", "B": "全面实现社会主义现代化", "C": "基本实现社会主义现代化", "D": "实现国家治理体系和治理能力现代化"}, "answer": "C", "explanation": "【解析】本题考查全面建成社会主义现代化强国。全面建成社会主义现代化强国总的战略安排分两步走：从2020年到2035年基本实现社会主义现代化；从2035年到21世纪中叶把我国建成富强民主文明和谐美丽的社会主义现代化强国。因此，选项C正确。选项AD，属于第二个阶段奋斗目标的具体任务，故不选。选项B，表述错误，故不选。 6．党的二十大报告指出，全党必须牢记“五个必由之路”，强调“这是我们在长期实践中得出的至关紧要的规律性认识，必须倍加珍惜、始终坚持。”在“五个必由之路”中，中国人民创造历史伟业的必由之路是（）。 A. 坚持党的全面领导 B. 中国特色社会主义 C. 贯彻新发展理念 D. 团结奋斗", "id": 125},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "在长期实践过程中，党领导人民不懈探索现代化道路，取得了社会主义现代化建设的伟大成就，用几十年时间走完了发达国家几百年走过的工业化历程。我国现代化建设的出发点和落脚点是（）。", "options": {"A": "完善和发展中国特色社会主义制度", "B": "增进民生福祉、促进社会公平", "C": "实现人民对美好生活的向往", "D": "实现高质量发展"}, "answer": "C", "explanation": "【解析】中国式现代化是全体人民共同富裕的现代化。这是中国式现代化区别于西方现代化的显著标志。必须把实现人民对美好生活的向往作为现代化建设的出发点和落脚点，C正确。完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化，是全面深化改革的总目标，故A错误。中国特色社会保障体系把增进民生福祉、促进社会公平作为根本出发点和落脚点，故B错误。高质量发展是全面建设社会主义现代化国家的首要任务，故D错误。 #### 多项选择题 1．习近平指出：“一百年来，中国共产党团结带领中国人民进行的一切奋斗、一切牺牲、一切创造，归结起来就是一个主题：实现中华民族伟大复兴。”实现中华民族伟大复兴的中国梦，本质是（）。 A. 国家富强 B. 民族振兴 C. 社会和谐 D. 人民幸福", "id": 126},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "全面建成小康社会，高质量完成了社会主义现代化建设“三步走”战略的第二步，使中华民族伟大复兴向前迈出新的一大步。如期全面建成小康社会（）。", "options": {"A": "兑现了党向人民、向历史作出的庄严承诺", "B": "标志着第一个百年奋斗目标胜利实现", "C": "极大彰显了中国特色社会主义制度的优势", "D": "践行了党为中国人民谋幸福、为中华民族谋复兴的初心使命"}, "answer": "ABCD", "explanation": "【解析】本题考查全面建成小康社会。如期全面建成小康社会，兑现了党向人民、向历史作出的庄严承诺，践行了党为中国人民谋幸福、为中华民族谋复兴的初心使命。如期全面建成小康社会，标志着第一个百年奋斗目标胜利实现，中华民族实现了从大幅落后于时代到大踏步赶上时代的新跨越。如期全面建成小康社会，极大彰显了中国特色社会主义制度的优势，极大提升了民族自信心自豪感，极大增强了实现中华民族伟大复兴的能量。因此，选项 ABCD 正确。", "id": 127},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "在漫长的历史长河中，人类创造和发展了多姿多彩的文明，构成了波澜壮阔的文明图谱。中国式现代化是我们党领导全国各族人民在长期探索和实践中历经千辛万苦、付出巨大代价取得的重大成果。中国式现代化（）。", "options": {"A": "是人类社会现代化的最高级形态", "B": "深深植根于中华优秀传统文化", "C": "借鉴吸收一切人类优秀文明成果", "D": "是一种全新的人类文明形态"}, "answer": "BCD", "explanation": "【解析】本题考查中国式现代化。中国式现代化，深深植根于中华优秀传统文化，体现科学社会主义的先进本质，借鉴吸收一切人类优秀文明成果，代表人类文明进步的发展方向，是一种全新的人类文明形态。因此，选项 BCD 正确。选项 A，中国式现代化开辟了人类文明的新形态，但不能说是人类社会现代化的最高级形态。每个国家都可以有适合自己的现代化模式，并不能说哪种模式是最高级的，故不选。 4．习近平指出：“中国式现代化，是我们为如何唤醒‘睡狮’、实现民族复兴这个重大历史课题所给出的答案。”中国式现代化是中国共产党领导人民长期探索和实践的重大成果。中国式现代化（）。 A. 深深植根于中华优秀传统文化 B. 体现科学社会主义的先进本质 C．借鉴吸收一切人类优秀文明成果 D．代表人类文明进步的发展方向", "id": 128},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "我国国家制度和国家治理体系具有多方面的显著优势，其中最大优势是（）。", "options": {"A": "发展生产力", "B": "全面深化改革开放", "C": "全过程人民民主", "D": "中国共产党领导"}, "answer": "D", "explanation": "【解析】本题考查中国共产党领导。我国国家制度和国家治理体系具有多方面的显著优势，其中最大优势是中国共产党领导。这一优势是带有统领性的根本优势，贯穿于中国特色社会主义制度和国家治理体系其他方面显著优势中。因此，选项 D 正确。选项 A，社会主义的根本任务是发展生产力，故不选。选项 B，全面深化改革开放是新时代坚持和发展中国特色社会主义的根本动力，故不选。选项 C，全过程人民民主是社会主义民主政治的本质属性，故不选。 2．党的领导，必须按照民主集中制原则，层层体现到治国理政的全过程各方面。党中央作出的决策部署，党的组织、宣传、统战、政法等部门要贯彻落实，人大、政府、政协、监委、法院、检察院、军队的党组织要贯彻落实，人民团体、企事业单位等的党组织也要贯彻落实。这体现了（）。 A. 党的领导是全面的 B. 党的领导是系统的 C. 党的领导是整体的 D. 党的领导是多样的", "id": 129},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "恩格斯强调：“没有权威，就不可能有任何的一致行动。”党保持团结统一和强大战斗力、不断取得胜利的关键所在是（）。", "options": {"A": "党中央集中统一领导", "B": "解放和增强社会活力", "C": "思想引领力", "D": "群众组织力"}, "answer": "A", "explanation": "【解析】本题考查维护党中央权威和集中统一领导。党中央集中统一领导是党的领导的最高原则，是党保持团结统一和强大战斗力、不断取得胜利的关键所在。因此，选项 A 正确。选项 B，解放和增强社会活力，是社会主义改革的内在要求和基本目的，也是新时代全面深化改革的关键所在，故不选。选项 C，思想引领力是保证全党全国各族人民思想统一、步调一致的坚实基础，故不选。选项 D，群众组织力是我们党坚如磐石、坚不可摧的力量根基，故不选。 #### 多项选择题 1\\. 习近平指出：“一定要认清，中国最大的国情就是中国共产党的领导。什么是中国特色？这就是中国特色。”中国共产党领导是（）。 A. 社会主义改革开放的出发点和落脚点 B. 人民当家作主的可靠保障 C．实现中华民族伟大复兴的根本保证 D．中国特色社会主义事业的坚强核心", "id": 130},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平指出：“中国特色社会主义制度是一个严密完整的科学制度体系，起四梁八柱作用的是根本制度、基本制度、重要制度，其中具有统领地位的是党的领导制度。”党的领导制度是（）。", "options": {"A": "国家治理体系和治理能力现代化的关键", "B": "中国特色社会主义制度体系的核心", "C": "党的领导核心地位的必然反映和内在要求", "D": "贯穿党治国理政全部活动的一条红线"}, "answer": "ABC", "explanation": "【解析】本题考查党的领导制度。党的领导制度是党的领导核心地位的必然反映和内在要求，明确了我国政治生活的领导关系、领导主体、领导对象，是中国特色社会主义制度体系的核心，是国家治理体系和治理能力现代化的关键，发挥着提纲挈领、无可替代的作用。因此，选项 ABC 正确。选项 D，坚持以人民为中心，是新时代坚持和发展中国特色社会主义的根本立场，是贯穿党治国理政全部活动的一条红线，故不选。 （五）坚持以人民为中心", "id": 131},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平指出：“人民是历史的创造者，人民是真正的英雄。波澜壮阔的中华民族发展史是中国人民书写的！博大精深的中华文明是中国人民创造的！历久弥新的中华民族精神是中国人民培育的！”这是因为，人民性是（）。", "options": {"A": "马克思主义的内在品质", "B": "马克思主义首要的和基本的观点", "C": "马克思主义的本质属性和鲜明品格", "D": "马克思主义的发展性的应有之义和必然要求"}, "answer": "C", "explanation": "【解析】本题考查人民是历史的创造者。人民性是马克思主义的本质属性和鲜明品格。坚持以人民为中心，是新时代坚持和发展中国特色社会主义的根本立场，是贯穿党治国理政全部活动的一条红线。因此，选项 C 正确。选项 AD，革命性是马克思主义的内在品质，是马克思主义的人民性、实践性和发展性的应有之义和必然要求，故不选。选项 B，实践观点是马克思主义首要的和基本的观点，故不选。 2．政治立场是一个政党观察、认识、处理政治问题的立足点，反映了这个政党的世界观、方法论和执政理念，体现了这个政党的根本属性。我们党的最大政治优势是（）。 A. 全过程人民民主 B. 人民当家作主 C. 勇于自我革命 D. 密切联系群众", "id": 132},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平指出：“群众路线是我们党的生命线和根本工作路线，是我们党永葆青春活力和战斗力的重要传家宝。”我们党是在同人民群众的密切联系中成长、发展、壮大起来的。贯彻党的群众路线的有效途径是（）。", "options": {"A": "调查研究", "B": "武装斗争", "C": "统一战线", "D": "党的建设"}, "answer": "A", "explanation": "【解析】本题考查坚持和贯彻党的群众路线。调查研究是获得真知灼见的源头活水，是贯彻党的群众路线的有效途径。因此，选项 A 正确。 4\\. 新时代坚持和发展中国特色社会主义的根本立场是（）。 A. 坚持以人民为中心 B. 坚持以经济建设为中心 C. 坚持四项基本原则 D. 坚持改革开放", "id": 133},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "群众路线是我们党始终坚持的根本工作方法。党的领导工作的正确方法就是将群众意见集中起来形成正确的决策，又到群众中宣传解释，将决策化为群众的行动，并在群众实践中检验这些决策是否正确。贯彻党的群众路线必须以知促行、以行促知，做到知行合一，其中，“知”是（）。", "options": {"A": "重点和关键", "B": "基础和前提", "C": "手段和目的", "D": "出发点和落脚点"}, "answer": "B", "explanation": "【解析】贯彻党的群众路线，“知”是基础、是前提，“行”是重点、是关键。必须以知促行、以行促知，做到知行合一，使群众路线落地稳、扎根深，融入经济社会发展全过程，贯穿到党的全部工作中。B 正确，ACD 错误。", "id": 134},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "实现现代化是近代以来中国人民孜孜以求的宏愿。中国共产党团结带领中国人民追求民族复兴的历史，也是一部不断探索现代化道路的历史。现代化的最终目标是实现( )。", "options": {"A": "中华民族伟大复兴", "B": "物质财富极大丰富", "C": "社会关系高度和谐", "D": "人自由而全面的发展"}, "answer": "D", "explanation": "【解析】推动全体人民共同富裕与促进人的全面发展是高度统一的。马克思主义政党的最高目标是实现共产主义，并把实现人的自由而全面发展作为共产主义的本质特征。习近平指出，现代化的最终目标是实现人自由而全面的发展。D 正确。物质财富极大丰富、消费资料按需分配，社会关系高度和谐、人们精神境界极大提高，是共产主义社会三个基本特征中的另外两个。ABC 错误。", "id": 135},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "坚持以人民为中心的发展思想，真正做到发展成果由人民共享，就必须落实到扎实推进全体人民共同富裕上，在推动共同富裕过程中促进人的全面发展。共同富裕是（）。", "options": {"A": "中国特色社会主义的重要物质基础和政治基础", "B": "中国特色社会主义的本质要求", "C": "中国特色社会主义制度的重要支柱", "D": "中国特色社会主义最本质的特征"}, "answer": "B", "explanation": "【解析】本题考查共同富裕。共同富裕是中国特色社会主义的本质要求，是中国式现代化的重要特征。因此，选项 B 正确。选项 A，国有企业是中国特色社会主义的重要物质基础和政治基础，是我们党执政兴国的重要支柱和依靠力量，故不选。选项 C，社会主义基本经济制度是中国特色社会主义制度的重要支柱，是新时代推动实现高质量发展的制度基础，故不选。选项 D，党的领导是中国特色社会主义最本质的特征，故不选。 #### 多项选择题 1\\. 人民立场是中国共产党的根本政治立场，是我们党区别于其他政党的显著标志。坚持人民立场，就要（）。 A. 始终牢记党的初心和使命 B. 尊重实践、尊重创造 C. 热爱人民、尊重人民、敬畏人民 D. 始终保持党同人民群众的血肉联系", "id": 136},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平指出：“开展调查研究就是走群众路线，没有调查就没有发言权，就没有决策权。”不论过去、现在和将来，我们都要坚持一切为了群众，一切依靠群众，从群众中来，到群众中去，把群众路线贯彻到治国理政全部活动之中。这是因为群众路线是（）。", "options": {"A": "我们党永葆青春活力和战斗力的重要传家宝", "B": "我们党认识世界和改造世界的根本要求", "C": "我们党的生命线和根本工作路线", "D": "我们党始终坚持的根本工作方法"}, "answer": "ACD", "explanation": "【解析】本题考查坚持和贯彻党的群众路线。群众路线是我们党的生命线和根本工作路线，是我们党永葆青春活力和战斗力的重要传家宝，是我们党始终坚持的根本工作方法。因此，选项 ACD 正确。选项 B，实事求是是中国共产党人认识世界、改造世界的根本要求，是中国共产党的思想路线，故不选。 3．共同富裕是中国特色社会主义的本质要求，是中国式现代化的重要特征。要从全局角度来把握共同富裕。共同富裕是（）。 A. 全体人民共同富裕 B．人民群众物质生活和精神生活都富裕 C．所有人都同时富裕 D．所有地区同时达到一个富裕水准", "id": 137},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "75 年前，毛泽东同志向世界庄严宣告了中华人民共和国的成立，中国人民从此站起来了。中华人民共和国成立以来，特别是改革开放以来，我们党领导人民创造了世所罕见的两大奇迹，这就是（）。", "options": {"A": "经济快速发展奇迹和生态环境改善奇迹", "B": "文化繁荣兴盛奇迹和社会长期稳定奇迹", "C": "文化繁荣兴盛奇迹和生态环境改善奇迹", "D": "经济快速发展奇迹和社会长期稳定奇迹"}, "answer": "D", "explanation": "【解析】本题考查改革开放是我们前进的重要法宝。中华人民共和国成立以来，特别是改革开放以来，我们党领导人民创造了世所罕见的两大奇迹：一是经济快速发展奇迹；二是社会长期稳定奇迹。因此，选项 D 正确。选项 A，生态环境改善进程正在加快，但部分地区依旧发展较慢，故不选。选项 BC，文化事业在 “文革” 期间有所影响，属于正在努力实现的目标，故不选。 3．新时代全面深化改革具有全面性、系统性、整体性的鲜明特点，必须将其作为一 个系统工程来把握。全面深化改革的总目标是（）。 A. 发展社会主义市场经济 B．完善和发展中国特色社会主义制度，推进国家治理体系和治理能力现代化 C. 巩固社会主义制度 D．实现中华民族伟大复兴", "id": 138},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面深化改革开放改什么、怎么改，这是一个带有根本性的问题。牢牢把握全面深化改革开放的正确方向，确保改革不改向、变革不变色，必须有利于进一步解放思想、进一步解放和发展社会生产力、进一步解放和增强社会活力。这“三个进一步解放”既是改革的目的，又是改革的条件。改革开放的鲜明特征和首要任务是（）。", "options": {"A": "解放思想", "B": "解放和发展社会生产力", "C": "解放和增强社会活力", "D": "以创新的思维和办法解决前进中的问题"}, "answer": "B", "explanation": "【解析】解放思想，是开启改革开放事业的思想前提，也是新时代全面深化改革开放的思想前提。解放和发展社会生产力，是改革开放的鲜明特征和首要任务，也是新时代贯彻新发展理念、构建新发展格局、推动高质量发展的必然要求。解放和增强社会活力，是社会主义改革的内在要求和基本目的，也是新时代全面深化改革的关键所在。B 正确，ACD 错误。 5\\. 正确处理好改革、发展、稳定的关系，是我国改革开放的一条重要经验。正确处理改革、发展、稳定关系的结合点是（）。 A. 不断开辟发展新领域、新赛道 B. 人的自由而全面的发展 C. 坚持守正创新 D. 改善人民生活", "id": 139},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面深化改革开放，不是某个领域某个方面的变革，而是涉及党和国家事业发展全局的体制机制变革。全面深化改革开放的主线是（）。", "options": {"A": "重要领域和关键环节改革", "B": "经济体制改革", "C": "制度建设", "D": "统筹改革、发展、稳定"}, "answer": "C", "explanation": "【解析】统筹推进各领域各方面改革开放，必须以全面深化改革总目标为引领，以制度建设为主线，以经济体制改革为重点，以重要领域和关键环节改革为突破口，使各方面改革协同推进、环环相扣、形成合力。C 正确，AB 错误。统筹改革、发展、稳定是全面深化改革开放要坚持的正确方法论之一，D 错误。 7\\. 中国特色社会主义制度的成熟定型是一个在改革中不断推进的过程。当前，我国发展还面临一系列突出矛盾和挑战，新时代坚持和发展中国特色社会主义的根本动力是（）。 A. 全面从严治党 B. 全面依法治国 C. 全面深化改革开放 D. 全面建设社会主义现代化国家", "id": 140},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面深化改革的总目标是完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化。这一总目标是一个内涵丰富的有机整体，两句话都讲，才是完整的、全面的。这一总目标的提出，标志着（）。", "options": {"A": "中国特色社会主义事业进入了新的发展阶段", "B": "党探索中国社会主义建设道路的良好开端", "C": "我国进入了一个新发展阶段", "D": "我们党对社会主义建设规律和改革开放规律认识的深化"}, "answer": "D", "explanation": "【解析】本题考查全面深化改革。全面深化改革总目标的提出，标志着我们党对社会主义建设规律和改革开放规律认识的深化，对于新时代统筹推进各领域各方面的改革，对于决胜全面建成小康社会、全面建设社会主义现代化国家、全面推进中华民族伟大复兴具有重大指导意义。因此，选项 D 正确。选项 A，新时代是我国发展新的历史方位，标志着中国特色社会主义事业进入了新的发展阶段，故不选。选项 B，《论十大关系》标志着党探索 中国社会主义建设道路的良好开端，故不选。选项 C，全面建成小康社会、实现第一个百年奋斗目标之后，我们要乘势而上开启全面建设社会主义现代化国家新征程，向第二个百年奋斗目标进军，这标志着我国进入了一个新发展阶段，故不选。 ##### 多项选择题 1\\. 党的十一届三中全会深刻把握党和国家前途命运，作出实行改革开放的历史性决策。改革开放是我们党的一次伟大觉醒，正是这个伟大觉醒孕育了我们党从理论到实践的伟大创造。改革开放是（）。 A. 坚持和发展中国特色社会主义的必由之路 B．党和人民大踏步赶上时代的重要法宝 C. 决定当代中国命运的关键一招 D．全面建设社会主义现代化国家的基础性、战略性支撑", "id": 141},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "全面深化改革开放必须有利于进一步解放思想、进一步解放和发展社会生产力、进一步解放和增强社会活力。习近平指出：“这‘三个进一步解放’既是改革的目的，又是改革的条件。”其中，解放和增强社会活力是（）。", "options": {"A": "社会主义改革的内在要求和基本目的", "B": "改革开放的鲜明特征和首要任务", "C": "新时代全面深化改革的关键所在", "D": "开启改革开放事业的思想前提"}, "answer": "AC", "explanation": "【解析】本题考查“三个进一步解放”。解放和增强社会活力，是社会主义改革的内在要求和基本目的，也是新时代全面深化改革的关键所在。因此，选项 AC 正确。选项 B，解放和发展社会生产力，是改革开放的鲜明特征和首要任务，故不选。选项 D，解放思想，是开启改革开放事业的思想前提，也是新时代全面深化改革开放的思想前提，故不选。 3．习近平指出，“中国将坚持实施更大范围、更宽领域、更深层次对外开放，坚持走中国式现代化道路，建设更高水平开放型经济新体制。”建设更高水平开放型经济新体制的举措有（）。 A. 要依托我国超大规模市场优势，以国内大循环吸引全球资源要素，提升贸易投 资合作质量和水平 B. 深化贸易投资领域体制机制改革，稳步扩大规则、规制、管理、标准等制度型开放 C. 推动货物贸易优化升级，创新服务贸易发展机制，发展数字贸易，加快建设贸易强国 D. 优化区域开放布局，实施自由贸易试验区提升战略，形成陆海内外联动、东西双向互济的开放格局", "id": 142},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "党的十八届三中全会通过的《中共中央关于全面深化改革若干重大问题的决定》，提出全面深化改革的总目标是完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化。国家治理体系和国家治理能力的关系是（）。", "options": {"A": "国家治理体系和国家治理能力是等同的", "B": "国家治理体系越完备国家治理能力就一定越强", "C": "通过好的国家治理体系能够提高国家治理能力", "D": "通过提高国家治理能力能够充分发挥国家治理体系的效能"}, "answer": "CD", "explanation": "【解析】国家治理体系和治理能力两者相辅相成。治理国家，制度是起根本性、全局性、长远性作用的，但没有有效的治理能力，再好的制度也难以发挥作用。同时，又不能把国家治理体系和国家治理能力等同起来，不是国家治理体系越完备，国家治理能力就越强。必须把国家治理体系和治理能力结合在一起，把两者当作一个相辅相成的有机整体，通过好的国家治理体系提高国家治理能力，通过提高国家治理能力充分发挥国家治理体系的效能。CD 正确。AB 错误。 5．全面深化改革开放是新时代坚持和发展中国特色社会主义的根本动力。改革开放只有进行时，没有完成时，停顿和倒退没有出路。改革开放永无止境，这是（）。 A. 社会基本矛盾运动规律的深刻反映 B．总结世界社会主义实践经验得出的重要结论 C. 推进党和人民事业发展的必然要求 D. 历史唯物主义的态度", "id": 143},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平总书记对新常态下中国经济的判断一针见血：“结构性问题最突出，矛盾的主要方面在供给侧。”推进供给侧改革是形势所迫，是问题倒逼的必然选择。改革攻坚，这个坎必须跨过去。供给侧结构性改革主要致力于（）。", "options": {"A": "注重短期调控", "B": "解决总量性问题", "C": "优化要素配置和调整生产结构", "D": "调节税收、财政支出、货币信贷"}, "answer": "C", "explanation": "【解析】本题考查供给侧结构性改革。供给侧改革重在解决结构性问题，注重激发经济增长动力，主要通过优化要素配置和调整生产结构来提高供给体系质量和效率，进而推动经济增长。因此，选项 C 正确。选项 ABD，需求侧管理重在解决总量性问题，注重短期调控，主要是通过调节税收、财政支出、货币信贷等来刺激或抑制需求，进而推动经济增长， 故不选。 3．进入21世纪，党中央根据经济发展的实际情况，进一步提出了继续推进西部大开发、振兴东北老工业基地、促进中部崛起、鼓励东部地区率先发展以及建设长江经济带的战略布局。这是为了（）。 A. 转变经济发展方式 B. 加快城镇化进程 C. 增强自主创新能力 D. 促进区域协调发展", "id": 144},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党的二十大作出教育优先发展的战略部署，要求2035年建成教育强国。这充分体现了在社会主义现代化强国建设中教育的基础性、先导性和全局性战略地位。发展教育的根本尺度是（）。", "options": {"A": "教育公平", "B": "人民满意", "C": "深化教育改革创新", "D": "服务高质量发展"}, "answer": "B", "explanation": "【解析】本题考查加快建设教育强国。人民满意是发展教育的根本尺度。加快建设教育强国，最终是办好人民满意的教育。因此，选项 B 正确。选项 A，教育公平是社会公平的 重要基础，只有不断促进教育发展成果更多更公平惠及全体人民，才能使每个人的成长成才道路更加宽广。选项 C，从教育大国到教育强国是一个系统性的跃升和质变，必须以改革创新为动力，主动超前布局、有力应对变局、奋力开拓新局。选项 D，服务高质量发展是建设教育强国的重要任务，要以教育高质量发展赋能经济社会可持续发展。", "id": 145},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党的二十大报告擘画了以中国式现代化全面推进中华民族伟大复兴的宏伟蓝图，提出“加快构建新发展格局，着力推动高质量发展”。其中，构建新发展格局的最本质特征是（）。", "options": {"A": "着力发展实体经济", "B": "推动产业链供应链优化升级", "C": "深化供给侧结构性改革", "D": "实现高水平的自立自强"}, "answer": "D", "explanation": "【解析】本题考查构建新发展格局。构建新发展格局的最本质的特征是实现高水平的自立自强。科技自立自强是我国经济生存和发展的基础，是畅通国内国际双循环、促进我国发展大局的关键。因此，选项 D 正确。选项 A，实体经济是一国经济的立身之本、财富之源，是构筑未来发展战略优势的重要支撑。要坚持把发展经济的着力点放在实体经济上，但这不是构建新发展格局的最本质特征。选项 B，建立稳定的产业链供应链，是稳固国内大循环主体地位、增强在国际大循环中带动能力的迫切需要。选项 C，深化供给侧结构性改革是构建新发展格局的主线。", "id": 146},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "我国以科技创新引领现代化产业体系建设，加快推进高水平科技自立自强，大力推进新型工业化，加强创新能力建设，加快新旧动能转换，推动传统产业转型升级，大力发展数字经济。实现高水平科技自立自强的重要支撑是（）。", "options": {"A": "建设教育强国", "B": "发展基础学科", "C": "完善体制机制", "D": "培养优秀人才"}, "answer": "A", "explanation": "【解析】本题考查加快建设教育强国。习近平总书记强调：“建设教育强国，是全面建成社会主义现代化强国的战略先导，是实现高水平科技自立自强的重要支撑，是促进全体人民共同富裕的有效途径，是以中国式现代化全面推进中华民族伟大复兴的基础工程。”因此，选项 A 正确。选项 BCD，与题意不符，故不选。 8．高质量发展，是能够很好满足人民日益增长的美好生活需要的发展。高质量发展的根本目的是（）。 A. 创新 B. 协调 C. 开放 D. 共享", "id": 147},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "“强国必先强农，农强方能国强。没有农业强国就没有整个现代化强国；没有农业农村现代化，社会主义现代化就是不全面的。”党中央着眼于全面建成社会主义现代化强国，作出全面推进乡村振兴、加快建设农业强国的战略部署。全面推进乡村振兴、建设农业强国的头等大事是（）。", "options": {"A": "保障粮食和重要农产品稳定安全供给", "B": "防止规模性返贫", "C": "发展生态低碳农业", "D": "加强农业基础设施建设"}, "answer": "A", "explanation": "【解析】本题考查全面推进乡村振兴。全面推进乡村振兴、建设农业强国的头等大事是保障粮食和重要农产品稳定安全供给。因此，选项 A 正确。选项 B，全面推进乡村振兴，要牢牢守住国家粮食安全和不发生规模性返贫“两条底线”。选项 CD，属于全面推进乡村振兴、建设农业强国的举措，但不是“头等大事”。 10\\. 推动高质量发展，必须以新发展理念为引领，深入推进发展方式、发展动力、发展领域、发展质量变革，实现更高质量、更有效率、更加公平、更可持续、更为安全的发展。实现高质量发展的保障是（）。 A. 坚持和完善社会主义基本经济制度 B. 贯彻新发展理念 C. 学习习近平经济思想 D. 进入新发展阶段", "id": 148},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面建成新发展格局任重道远，必须坚持问题导向和系统观念，着力破除制约加快构建新发展格局的主要矛盾和问题，不断扬优势、补短板、强弱项。要坚持把发展经济的着力点放在（）。", "options": {"A": "制度创新上", "B": "乡村振兴上", "C": "对外开放上", "D": "实体经济上"}, "answer": "D", "explanation": "【解析】实体经济是一国经济的立身之本、财富之源，是构筑未来发展战略优势的重要支撑。要坚持把发展经济的着力点放在实体经济上，推动资源要素向实体经济集聚、政策措施向实体经济倾斜、工作力量向实体经济加强，营造脚踏实地、勤劳创业、实业致富的发展环境和社会氛围，把实体经济做实、做强、做优。D 正确。 12\\. 加快建设以实体经济为支撑的现代化产业体系，关系我们在未来发展和国际竞争 中赢得战略主动。支撑我国国际竞争力的基石是（）。 A. 大力发展战略性新兴产业 B. 保持优势产业的领先地位 C. 构建优质高效的服务业新体系 D. 构建现代化基础设施体系", "id": 149},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "2023 年 2 月，中共中央、国务院印发了《数字中国建设整体布局规划》（简称《规划》）。《规划》明确指出，数字中国建设按照 “2522” 的整体框架进行布局，即夯实数字基础设施和数据资源体系 “两大基础”，推进数字技术与经济、政治、文化、社会、生态文明建设 “五位一体” 深度融合，强化数字技术创新体系和数字安全屏障 “两大能力”，优化数字化发展国内国际 “两个环境”。当前，建设数字中国，就要（）。", "options": {"A": "促进数字经济和实体经济深度融合", "B": "以数字化驱动生产生活和治理方式变革", "C": "培育壮大数字经济核心产业", "D": "对国外全面开放数据资源"}, "answer": "ABC", "explanation": "【解析】本题考查数字中国建设。中共中央、国务院印发的《数字中国建设整体布局规划》指出，建设数字中国是数字时代推进中国式现代化的重要引擎，必须强化系统观念和底线思维，全面提升数字中国建设的整体性、系统性、协同性，促进数字经济和实体经济 深度融合，以数字化驱动生产生活和治理方式变革，培育壮大数字经济核心产业。因此，选项 ABC 正确。选项 D，随着数据要素的广泛应用，越来越多的大数据已经成为推动经济高质量发展的新动能，有些数据不仅是国家和企业的核心机密，还涉及大量公民个人隐私，这些数据的安全和保护至关重要，不可能向国外全面开放。故不选。 2．党中央对公有制主体地位及其实现形式提出了一系列新的论断和阐述。国有资本、集体资本、非公有资本等交叉持股、相互融合的混合所有制经济，是基本经济制度的重要实现形式，有利于国有资本放大功能、保值增值、提高竞争力，有利于各种所有制资本取长补短、相互促进、共同发展。对此必须（）。 A. 实现公有制在经营方式和资产组织形式上的多样化 B. 把混合所有制作为公有制的主要实现形式 C. 让公有制经济控制所有经济领域和行业 D. 将公有制实现形式作为经济制度的本质属性来看待", "id": 150},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平总书记一向高度重视实体经济，作出了“实体经济是我国发展的本钱”“国家强大要靠实体经济”“把实体经济抓上去”等重要论断，体现了对经济发展规律的深刻认识。当前，我们要深刻认识实体经济发展环境新变化，主要包括（）。", "options": {"A": "结构性供需失衡问题被彻底扭转", "B": "制造业重新成为全球经济竞争的焦点", "C": "新工业革命给制造业发展带来深刻变革", "D": "我国制造业提质升级任务日益紧迫"}, "answer": "BCD", "explanation": "【解析】本题考查实体经济发展环境的新变化。我们要深刻认识实体经济发展环境新变化。首先，制造业重新成为全球经济竞争的焦点。其次，新工业革命给制造业发展带来深刻变革。最后，我国制造业提质升级任务日益紧迫。因此，选项 BCD 正确。选项 A，虽然 我国已经成为世界制造业第一大国，但与主要工业发达国家的制造业发展水平和制造强国建设目标相比，我国在技术创新、质量品牌、环境友好等方面还存在很大差距，结构性供需失衡问题日益凸显。故不选。 4．党的二十大报告强调：“未来五年是全面建设社会主义现代化国家开局起步的关键时期。”要想开辟发展新领域新赛道，不断塑造发展新动能新优势，就必须不断强化全面建设社会主义现代化国家的基础性、战略性支撑。必须坚持（）。 A. 创新是第一动力 B. 科技是第一生产力 C. 社保是第一兜底 D. 人才是第一资源", "id": 151},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "我国人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾在乡村最为突出，我国仍处于并将长期处于社会主义初级阶段的特征很大程度上表现在乡村。因此，实施乡村振兴战略，就是要（）。", "options": {"A": "坚持农业农村优先发展，坚持城乡融合发展，畅通城乡要素流动", "B": "加快建设农业强国，扎实推动乡村产业、人才、文化、生态、组织振兴", "C": "全方位夯实粮食安全根基，逐步把永久基本农田全部建成高标准农田", "D": "深化农村土地制度改革，赋予农民更加充分的财产权益"}, "answer": "ABCD", "explanation": "【解析】本题考查实施乡村振兴战略。针对“实施乡村振兴战略”，习近平总书记在党的二十大报告中指出，坚持农业农村优先发展，坚持城乡融合发展，畅通城乡要素流动；加快建设农业强国，扎实推动乡村产业、人才、文化、生态、组织振兴；全方位夯实粮食安全根基，逐步把永久基本农田全部建成高标准农田；深化农村土地制度改革，赋予农民更加充分的财产权益。因此，选项 ABCD 正确。 6．党的二十大报告提出，“加快构建以国内大循环为主体、国内国际双循环相互促进的新发展格局。”构建以国内大循环为主体、国内国际双循环相互促进的新发展格局，是根据我国发展阶段、发展环境、条件变化，特别是基于我国比较优势变化，审时度势作出的重大决策，是立足实现第二个百年奋斗目标、统筹发展和安全作出的战略决策，是把握未来发展主动权的战略部署，是（）。 A. 社会主义现代化强国的根基 B. 关系我国发展全局的重大战略任务 C. 新时代我国经济社会发展的鲜明主题 D. 推动高质量发展的战略基点", "id": 152},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "创新、协调、绿色、开放、共享的新发展理念相互贯通、相互促进，是具有内在联系的集合体。以下说法正确的有（）。", "options": {"A": "协调发展注重的是解决发展内外联动问题", "B": "绿色发展注重的是解决人与自然和谐共生问题", "C": "开放发展注重的是解决发展不平衡问题", "D": "共享发展注重的是解决社会公平正义问题"}, "answer": "BD", "explanation": "【解析】新发展理念具有丰富的科学内涵和具体的实践要求。创新发展注重的是解决发展动力问题，协调发展注重的是解决发展不平衡问题，绿色发展注重的是解决人与自然和谐共生问题，开放发展注重的是解决发展内外联动问题，共享发展注重的是解决社会公平正义问题。BD 正确，AC 错误。 9\\. 高质量发展关系我国社会主义现代化建设全局，具有重大战略意义。高质量发展（）。 A. 为全面建设社会主义现代化国家提供更为坚实的物质基础 B. 是不断满足人民对美好生活需要的重要保证 C. 是维护国家长治久安的必然要求 D. 是民族复兴的根基、国家强盛的前提", "id": 153},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面建设社会主义现代化国家，教育是根本，科技是关键，人才是基础。其中，科技是（）。", "options": {"A": "第一生产力", "B": "第一资源", "C": "第一动力", "D": "第一路径"}, "answer": "A", "explanation": "【解析】科技是第一生产力，人才是第一资源，创新是第一动力，A 正确。 3．科技是国之利器，国家赖之以强，企业赖之以赢，人民生活赖之以好。中国要强，中国人民生活要好，必须有强大科技。创新始终是一个国家、一个民族发展的不竭动力。科技创新的源头是（）。 A. 国家战略科技力量 B. 现代工程技术、颠覆性技术创新 C. 关键共性技术、前沿引领技术创新 D. 基础研究", "id": 154},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "坚持教育优先发展，要办好人民满意的教育，落实（ ）根本任务。", "options": {"A": "培养创新人才", "B": "立德树人", "C": "素质教育", "D": "教育公平"}, "answer": "B", "explanation": "【解析】办好人民满意的教育，要落实立德树人根本任务，培养德智体美劳全面发展的社会主义建设者和接班人，所以 B 选项正确。", "id": 155},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "在加快实施创新驱动发展战略中，要强化（）科技创新主体地位。", "options": {"A": "高校", "B": "科研机构", "C": "企业", "D": "政府"}, "answer": "C", "explanation": "【解析】加快实施创新驱动发展战略，要强化企业科技创新主体地位，发挥科技型骨干企业引领支撑作用，营造有利于科技型中小微企业成长的良好环境，推动创新链产业链资金链人才链深度融合，故 C 选项正确。", "id": 156},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "深入实施人才强国战略，要坚持（）是第一资源。", "options": {"A": "创新", "B": "科技", "C": "人才", "D": "教育"}, "answer": "C", "explanation": "【解析】深入实施人才强国战略，必须坚持人才是第一资源，把各方面优秀人才集聚到党和人民事业中来，所以 C 选项正确。 #### 多项选择题", "id": 157},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "千秋基业，人才为先。全面建设社会主义现代化国家，要聚天下英才而用之，推动我国由人才大国迈向人才强国。人才是（）。", "options": {"A": "人力资源中能力和素质较高的劳动者", "B": "实现民族振兴、赢得国际竞争主动的战略资源", "C": "我们党执政的最大底气和最深厚的根基", "D": "引领发展的第一动力"}, "answer": "AB", "explanation": "【解析】人民是我们党执政的最大底气，也是党执政最深厚的根基。C 错误。创新是引领发展的第一动力。D 错误。AB 正确。", "id": 158},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "加快建设科技强国，实现高水平科技自立自强，是（）。", "options": {"A": "国家强盛和民族复兴的战略基石", "B": "应对风险挑战和维护国家利益的必然选择", "C": "发展经济的着力点", "D": "构建新发展格局、推动高质量发展、满足人民美好生活需要的内在要求"}, "answer": "ABD", "explanation": "【解析】实体经济是发展经济的着力点。C 错误，ABD 正确。 3．自力更生是中华民族自立于世界民族之林的奋斗基点，自主创新是我们攀登世界科技高峰的必由之路。实现高水平科技自立自强，必须增强自主创新能力。自主创新，就是从增强国家创新能力出发，加强（）。 A. 原始创新 B. 集成创新 C. 开放创新 D. 改革创新", "id": 159},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "科技自立自强是国家强盛之基、安全之要。加快建设科技强国，必须坚持走中国特色自主创新道路，发挥新型举国体制优势，完善国家创新体系，加快关键核心技术攻关，实现高水平科技自立自强。要打赢关键核心技术攻坚战，这是因为（）。", "options": {"A": "关键核心技术是要不来、买不来、讨不来的", "B": "关键核心技术是国之重器", "C": "关键核心技术必须掌握在自己手中", "D": "掌握最关键最核心的技术才能从根本上保障国家经济安全、国防安全和其他安全"}, "answer": "ABCD", "explanation": "【解析】关键核心技术是国之重器，关键核心技术必须掌握在自己手中。关键核心技术是要不来、买不来、讨不来的。只有把最关键最核心的技术掌握在自己手中，才能从根本上保障国家经济安全、国防安全和其他安全。核心技术受制于人是我们最大的隐患，尤其是在激烈的国际竞争面前，在单边主义、保护主义上升的大背景下，不掌握核心技术，我们就会被“卡脖子”“牵鼻子”。建设世界科技强国，需要标志性科技成就。ABCD全选。", "id": 160},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "中共十八届三中全会提出：“坚持用制度管权管事管人，让人民监督权力，让权力在阳光下运行，是把权力关进制度笼子的根本之策。必须构建决策科学、执行坚决、监督有力的权力运行体系，健全惩治和预防腐败体系，建设廉洁政治，努力实现干部清正、政府清廉、政治清明。”社会主义民主政治的本质特征是（）。", "options": {"A": "人民当家作主", "B": "中国共产党的领导", "C": "民主集中制", "D": "中国特色社会主义道路"}, "answer": "A", "explanation": "【解析】本题考查社会主义民主政治的本质特征。人民当家作主是社会主义民主政治的本质特征。因此，选项 A 正确。选项 B，是人民当家作主和依法治国的根本保证，故不选。选项 C，是马克思主义政党的组织原则，故不选。选项 D，是实现我国社会主义现代化的必由之路，故不选。 3．发展社会主义民主政治，建设社会主义政治文明，是社会主义现代化建设的重要目标。社会主义政治文明建设包含着丰富的内容，其核心和精髓就是建设高度的社会主义民主，保证最广大人民当家作主的理想目标得以实现。中国社会主义政治文明的重要制度 载体是（）。 A. 民主集中制 B．中国共产党领导的多党合作和政治协商制度 C. 基层群众自治制度 D. 人民代表大会制度", "id": 161},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "多民族是我国的一大特色，也是我国发展的一大有利因素。中华民族和各民族的关系，是一个大家庭和家庭成员的关系，各民族的关系是一个大家庭里不同成员的关系。民族团结之本是（）。", "options": {"A": "民族区域自治制度", "B": "各民族共同团结奋斗、共同繁荣发展", "C": "保障少数民族当家作主，管理本民族、本地区事务的权利", "D": "中华民族共同体意识"}, "answer": "D", "explanation": "【解析】民族团结是我国各族人民的生命线，中华民族共同体意识是民族团结之本。D 正确，ABC 错误。 6．统一战线是中国共产党夺取革命、建设、改革事业胜利的重要法宝，也是实现中华民族伟大复兴的重要法宝。统战工作的本质要求是（）。 A. 大团结大联合 B. 围绕中心、服务大局 C. 在尊重多样性中寻求一致性 D. 统一思想", "id": 162},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党的二十大报告把统一战线由过去的“重要法宝”表述为“强大法宝”，凸显了新时代统一战线的地位和作用。新时代爱国统一战线的历史责任是（）。", "options": {"A": "发扬“团结—批评—团结”的优良传统", "B": "坚持求同存异", "C": "坚持党的领导", "D": "促进中华儿女大团结"}, "answer": "D", "explanation": "【解析】本题考查新时代爱国统一战线的历史责任。促进中华儿女大团结是新时代爱国统一战线的历史责任。因此，选项 D 正确。选项 A，B，统战工作的关键是要坚持求同存异，发扬 “团结—批评—团结” 的优良传统，在尊重多样性中寻求一致性，找到最大公约数、画出最大同心圆。选项 C，党的领导是统一战线最鲜明的特征，坚持党的领导是统一战线最核心最根本的问题。 8．统一战线是中国共产党夺取革命、建设、改革事业胜利的重要法宝，也是实现中华民族伟大复兴的重要法宝。统一战线最核心最根本的问题是（）。 A. 大团结大联合 B. 坚持求同存异 C. 壮大共同奋斗的力量 D. 坚持党的领导", "id": 163},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "多民族是我国的一大特色。在历史演进中，我国各民族之间形成了你中有我、我中有你、谁也离不开谁的多元一体格局。因此，要促进各民族像石榴籽一样紧紧抱在一起，就必须（）。", "options": {"A": "加强各民族交往交流交融，逐渐消除各民族之间的差别", "B": "倡导各民族独立自治，巩固和发展平等团结互助和谐的社会主义民族关系", "C": "深化民族团结进步教育，铸牢中华民族共同体意识", "D": "强化政策激励，促进少数民族同胞优先发展"}, "answer": "C", "explanation": "11\\. 制度优势是一个政党、一个国家的最大优势。坚定中国特色社会主义制度自信，首先要（）。 A. 坚定对社会主义基本经济制度的自信 B．坚定对中国特色社会主义政治制度的自信 C．坚定对中国传统文化的自信 D．坚定对马克思主义立场观点方法的自信", "id": 164},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "在发展全过程人民民主中，协商民主是实践全过程人民民主的（）。", "options": {"A": "重要方式", "B": "唯一形式", "C": "次要途径", "D": "补充手段"}, "answer": "A", "explanation": "【解析】协商民主在中国是实践全过程人民民主极为重要的方式，通过广泛协商，不同 群体、党派等交流沟通，凝聚共识，助力科学决策、民主决策，为国家发展、社会事务处理吸纳各方智慧，它绝不是次要或补充性的，更不是唯一形式，民主还有选举民主等多元实现路径协同发力推动全过程人民民主发展。 ##### 多项选择题 1\\. 中国特色社会主义政治发展道路，是党领导中国人民长期奋斗历史逻辑、理论逻辑、实践逻辑的必然结果，是坚持党的本质属性、践行党的根本宗旨的必然要求。走中国特色社会主义政治发展道路（）。 A. 最根本的是坚持党的领导 B．必须积极稳妥推进政治体制改革 C. 必须始终保持政治定力 D．必须坚持党的领导、人民当家作主、依法治国有机统一", "id": 165},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "1949 年 9 月，中国人民政治协商会议第一届全体会议代行全国人民代表大会的职权，代表全国人民的意志，宣告中华人民共和国的成立。新中国成立后，中国人民政治协商会议继续在国家的政治生活和社会生活以及对外友好活动中进行了许多工作，在推进改革开放和社会主义现代化建设，争取实现祖国统一，反对霸权主义、维护世界和平的斗争中，进一步发挥了重要作用。中国人民政治协商会议是（）。", "options": {"A": "社会主义民主政治建设的基础", "B": "社会主义协商民主的重要渠道和专门协商机构", "C": "爱国统一战线组织", "D": "具有中国特色的制度安排"}, "answer": "BCD", "explanation": "【解析】本题考查中国人民政治协商会议。中国人民政治协商会议是实行中国共产党领导的多党合作和政治协商制度的重要机构，是具有中国特色的制度安排，但它并不是国家机关，而是党领导下的爱国统一战线组织。因此，选项 BCD 正确。选项 A，基层群众自治制度是社会主义民主政治建设的基础。 3．中国特色社会主义政治制度是由根本政治制度、基本政治制度、重要政治制度等组成的制度体系。它们的关系是（）。 A. 重要政治制度是建立在我国根本政治制度和基本政治制度基础上的 B. 重要政治制度是由根本政治制度和基本政治制度派生而来的 C. 重要政治制度与我国根本政治制度、基本政治制度相衔接 D. 共同构成了中国特色社会主义政治制度的四梁八柱", "id": 166},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平强调，新时代我们要巩固和发展最广泛的爱国统一战线，坚持和完善中国共产党领导的多党合作和政治协商制度，不断为事业发展凝聚人心、增添力量。人民政协要建真言、谋良策、出实招，为加快推进社会主义现代化作出新的更大贡献。巩固和发展爱国统一战线就要（）。", "options": {"A": "支持民主党派按照中国特色社会主义参政党要求更好履行职能", "B": "深化民族团结进步教育，铸牢中华民族共同体意识", "C": "全面贯彻党的宗教工作基本方针", "D": "牢牢把握大团结大联合的主题，做好统战工作"}, "answer": "ABCD", "explanation": "【解析】本题考查巩固和发展爱国统一战线。新时期爱国统一战线的指导方针是“长期共存，互相监督，肝胆相照，荣辱与共”。具体内容主要包括：支持民主党派按照中国特色社会主义参政党要求更好履行职能；深化民族团结进步教育，铸牢中华民族共同体意识；全面贯彻党的宗教工作基本方针；牢牢把握大团结大联合的主题，做好统战工作。因此，选项 ABCD 正确。", "id": 167},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "改革开放 40 多年来，人民代表大会制度为党领导人民创造经济快速发展奇迹和社会长期稳定奇迹提供了重要制度保障。实践证明，人民代表大会制度是我们党领导人民在人类政治制度史上的伟大创造，是在我国政治发展史乃至世界政治发展史上具有重大意义的全新政治制度。人民代表大会制度（）。", "options": {"A": "有效保证国家沿着社会主义道路前进", "B": "有效保证国家治理跳出治乱兴衰的历史周期率", "C": "有效保证全体人民直接参与国家管理", "D": "有效保证国家政治生活既充满活力又安定有序"}, "answer": "ABD", "explanation": "【解析】人民代表大会制度，坚持中国共产党领导，坚持马克思主义国家学说的基本原则，适应人民民主专政的国体，有效保证国家沿着社会主义道路前进；人民代表大会制度，坚持国家一切权力属于人民，最大限度保障人民当家作主，把党的领导、人民当家作主、依法治国有机统一起来，有效保证国家治理跳出治乱兴衰的历史周期率；人民代表大会制度，正确处理事关国家前途命运的一系列重大政治关系，实现国家统一高效组织各项事业，维护国家统一和民族团结，有效保证国家政治生活既充满活力又安定有序（“三个有效保证”）。ABD 正确。人民代表大会制度是人民通过选举代表管理国家，并不是全体人民直接参与国家管理，C 错误。", "id": 168},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "民主首先而且主要是一种国家制度。中国特色社会主义政治制度（）。", "options": {"A": "是中国共产党带领中国人民在革命、建设、改革的长期实践中形成的", "B": "集中体现了我国人民民主的本质属性", "C": "是保证人民当家作主科学有效的制度安排", "D": "具有鲜明的中国特色、民族特色、时代特色"}, "answer": "ABCD", "explanation": "【解析】中国特色社会主义政治制度是中国共产党带领中国人民在革命、建设、改革的长期实践中形成的，集中体现了我国人民民主的本质属性，是保证人民当家作主科学有效的制度安排。这一政治制度具有鲜明的中国特色、民族特色、时代特色。ABCD 全选。 7\\. 中国特色社会主义进入新时代以来，我们深化了对民主政治发展规律的认识，提出全过程人民民主的重大理念。我国全过程人民民主不仅有完整的制度程序，而且有完整的参与实践。全过程人民民主，起始于人民意愿充分表达，落实于人民意愿有效实现，实现了（）。 A. 过程民主和成果民主相统一 B. 程序民主和实质民主相统一 C. 直接民主和间接民主相统一 D. 人民民主和国家意志相统一", "id": 169},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "全过程人民民主，是中国共产党团结带领人民追求民主、发展民主、实现民主的伟大创造，是新时代我国民主政治领域具有重大创新意义的标志性成果。全过程人民民主是（）。", "options": {"A": "全链条的民主", "B": "全方位的民主", "C": "全覆盖的民主", "D": "全负荷的民主"}, "answer": "ABC", "explanation": "【解析】全过程人民民主是全链条、全方位、全覆盖的民主；是最广泛、最真实、最管用的民主。ABC 正确，D 错误。 9\\. 社会主义协商民主，是在中国共产党领导下，人民内部各方面围绕改革、发展、稳定重大问题和涉及群众切身利益的实际问题，在决策之前和决策实施之中开展广泛协商，努力形成共识的重要民主形式。协商民主是中国社会主义民主政治中（）。 A. 独特的民主形式 B．独有的民主形式 C. 独到的民主形式 D．与选举民主共同构成制度特点和优势的一种民主形式", "id": 170},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "建设法治中国的总体目标，就是实现法律规范科学完备统一，执法司法公正高效权威，权力运行受到有效制约监督，人民合法权益得到充分尊重保障，法治信仰普遍确立，法治国家、法治政府、法治社会全面建成。具体来说，就是到2025年（）。", "options": {"A": "中国特色社会主义法治体系初步形成", "B": "法治国家、法治政府、法治社会基本建成", "C": "中国特色社会主义法治体系基本形成", "D": "国家治理体系和治理能力现代化基本实现"}, "answer": "A", "explanation": "【解析】本题考查建设法治中国的总体目标。建设法治中国的总体目标，就是到2025年，党领导全面依法治国体制机制更加健全，以宪法为核心的中国特色社会主义法律体系更加完备，职责明确、依法行政的政府治理体系日益健全，相互配合、相互制约的司法权运行机制更加科学有效，法治社会建设取得重大进展，党内法规体系更加完善，中国特色社会主义法治体系初步形成；到2035年，法治国家、法治政府、法治社会基本建成，中国特色社会主义法治体系基本形成，人民平等参与、平等发展权利得到充分保障，国家治理体系和治理能力现代化基本实现。因此，选项A正确。选项BCD，均为2035年的目标。 3．习近平指出：“全面推进依法治国，必须走对路。如果路走错了，南辕北辙了，那再提什么要求和举措也都没有意义了。”我们党领导人民长期探索走出的中国特色社会主义法治道路，是全面依法治国的唯一正确道路。中国特色社会主义法治之魂是（）。 A. 依法治国和以德治国相结合 B. 以人民为中心 C. 党的领导 D. 法律面前人人平等", "id": 171},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面推进依法治国涉及很多方面，在实际工作中必须有一个总揽全局、牵引各方的总抓手，这个总抓手就是（）。", "options": {"A": "建设中国特色社会主义法治体系", "B": "建设社会主义法治国家", "C": "坚持依法治国、依法执政、依法行政共同推进", "D": "坚持法治国家、法治政府、法治社会一体建设"}, "answer": "A", "explanation": "【解析】习近平指出：“全面推进依法治国涉及很多方面，在实际工作中必须有一个总揽全局、牵引各方的总抓手，这个总抓手就是建设中国特色社会主义法治体系。依法治国各项工作都要围绕这个总抓手来谋划、来推进。” A 正确。建设中国特色社会主义法治体系，建设社会主义法治国家，是全面推进依法治国的总目标；坚持依法治国、依法执政、依法行政共同推进，坚持法治国家、法治政府、法治社会一体建设，坚持统筹推进国内法治和涉外法治，是法治中国建设的工作布局。BCD 错误。 6．统一战线是凝聚人心、汇聚力量的强大法宝。统一战线最鲜明的特征（或：统一战线最核心最根本的问题）是（）。 A. 人民至上 B. 求同存异 C. 党的领导 D. 团结奋斗", "id": 172},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "全面依法治国是“四个全面”战略布局的重要内容之一。推进全面依法治国，根本目的是（）。", "options": {"A": "依法保障人民权益", "B": "努力让人民群众在每一个司法案件中感受到公平正义", "C": "提高依法执政水平", "D": "保证法律面前人人平等"}, "answer": "A", "explanation": "8\\. 走中国特色社会主义法治道路，必须坚持法律面前人人平等。平等是（）。 A. 推进全面依法治国的根本目的 B．我们的法治同西方资本主义国家的法治最大的区别 C. 社会主义法律的基本属性 D. 全面依法治国的关键", "id": 173},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "“全面推进依法治国，必须走对路。如果路走错了，南辕北辙了，那再提什么要求和举措也都没有意义了。”我们党长期探索走出的中国特色社会主义道路，是全面依法治国的唯一正确道路。中国特色社会主义法治道路的核心要义就是（）。", "options": {"A": "传承中华优秀传统法律文化", "B": "坚持中国特色社会主义制度", "C": "坚持党的领导", "D": "贯彻中国特色社会主义法治理论"}, "answer": "BCD", "explanation": "【解析】本题考查全面依法治国的内容。该题目为固定说法，中国特色社会主义法治道路的核心要义，就是要坚持党的领导，坚持中国特色社会主义制度，贯彻中国特色社会主义法治理论。因此，选项 BCD 正确。选项 A，说法正确，但不是中国特色社会主义法治道路的核心要义。 3．中国特色社会主义法治道路是全面依法治国的唯一正确道路。坚持和拓展中国特色社会主义法治道路，必须毫不动摇坚持的原则有（）。 A. 坚持中国共产党的领导 B. 坚持以人民为中心 C. 坚持法律面前人人平等 D. 坚持依法治国和以德治国相结合", "id": 174},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "建设法治中国，是全面建设社会主义现代化国家的重要组成部分。加快建设法治中国，必须坚持统筹兼顾、把握重点、整体谋划，更加注重系统性、整体性、协同性。法治中国建设的工作布局是（）。", "options": {"A": "坚持依法治国、依法执政、依法行政共同推进", "B": "坚持法治国家、法治政府、法治社会一体建设", "C": "坚持科学立法、严格执法、公正司法、全民守法", "D": "坚持统筹推进国内法治和涉外法治"}, "answer": "ABD", "explanation": "【解析】法治中国建设的工作布局是：坚持依法治国、依法执政、依法行政共同推进，坚持法治国家、法治政府、法治社会一体建设，坚持统筹推进国内法治和涉外法治。ABD 正确。“坚持全面推进科学立法、严格执法、公正司法、全民守法”是习近平法治思想的主要内容（“十一个坚持”）之一，C 不符合题意。", "id": 175},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平总书记深刻指出：“意识形态工作是为国家立心、为民族立魂的工作。”之所以要建设具有强大凝聚力和引领力的社会主义意识形态，是因为（）。", "options": {"A": "做好意识形态工作是中国共产党的中心任务", "B": "意识形态关乎旗帜、关乎道路、关乎国家政治安全，决定文化前进方向和发展道路", "C": "意识形态领域的矛盾是当前我国社会的主要矛盾", "D": "做好意识形态工作是全面建设社会主义现代化国家的基础性、战略性支撑"}, "answer": "B", "explanation": "【解析】本题考查意识形态问题。习近平总书记在党的二十大报告中强调：“意识形态工作是为国家立心、为民族立魂的工作。”意识形态关乎旗帜、关乎道路、关乎国家政治安 全，决定文化前进方向和发展道路。因此，选项 B 正确。选项 A，中国共产党的中心任务是以中国式现代化全面推进中华民族伟大复兴，而不是做好意识形态工作，故不选。选项 C，当前我国社会的主要矛盾是人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾，而不是意识形态领域的矛盾，故不选。选项 D，教育、科技、人才是全面建设社会主义现代化国家的基础性、战略性支撑，而不是做好意识形态工作，故不选。 3．文化自信是更基础、更广泛、更深厚的自信，是一个国家、一个民族发展中最基本、最深沉、最持久的力量。建设社会主义文化强国、推动社会主义文化繁荣兴盛，关键在于（）。 A. 坚持百花齐放、百家争鸣 B. 坚持为人民服务、为社会主义服务 C. 坚定中国特色社会主义文化自信 D. 坚定创新创造", "id": 176},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "中华优秀传统文化有很多重要元素，共同塑造出中华文明的突出特性，即连续性、创新性、统一性、包容性、和平性。其中，从根本上决定了中华民族必然走自己的路的突出特性是（）。", "options": {"A": "连续性", "B": "创新性", "C": "统一性", "D": "包容性"}, "answer": "A", "explanation": "【解析】本题考查中华文明的突出特性，属于理解与识记相结合的试题，难度较小。中华优秀传统文化有很多重要元素，共同塑造出中华文明的突出特性。其中，连续性从根本上决定了中华民族必然走自己的路。因此，选项 A 正确。选项 B，创新性从根本上决定了中华民族守正不守旧、尊古不复古的进取精神，决定了中华民族不惧新挑战、勇于接受新事物的无畏品格。选项 C，统一性从根本上决定了中华民族各民族文化融为一体、即使遭遇重大挫折也牢固凝聚，决定了国土不可分、国家不可乱、民族不可散、文明不可断的共同信念，决定了国家统一永远是中国核心利益的核心，决定了一个坚强统一的国家是各族人民的命运所系。选项 D，包容性从根本上决定了中华民族交往交流交融的历史取向，决定了中国各宗教信仰多元并存的和谐格局，决定了中华文化对世界文明兼收并蓄的开放胸怀。", "id": 177},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "“当今世界，要说哪个政党、哪个国家、哪个民族能够自信的话，那中国共产党、中华人民共和国、中华民族是最有理由自信的。”我们坚定文化自信的深厚基础是（）。", "options": {"A": "中华优秀传统文化", "B": "中国特色社会主义伟大实践", "C": "革命文化", "D": "社会主义先进文化"}, "answer": "A", "explanation": "【解析】本题考查坚定文化自信。中华优秀传统文化是我们坚定文化自信的深厚基础。因此，选项正确。选项 B，中国特色社会主义伟大实践是我们坚定文化自信的现实基础。选项 CD，党带领人民在伟大斗争中孕育的革命文化和社会主义先进文化是我们坚定文化自信的坚强基石。 6．新闻舆论工作处在意识形态斗争前沿，是治国理政、定国安邦的大事。舆论导向正确，就能凝聚人心、汇聚力量，推动事业发展；舆论导向错误，就会动摇人心、瓦解斗志，危害党和人民事业。做好新闻舆论工作的第一位要求是（）。 A. 坚持正确的政治方向 B. 做大做强主流舆论阵地 C. 管好用好互联网 D. 提高网络综合治理能力", "id": 178},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "新闻舆论工作处在意识形态斗争前沿，是治国理政、定国安邦的大事。意识形态工作的主阵地、主战场、最前沿是（）。", "options": {"A": "互联网", "B": "精品读物", "C": "宗教活动", "D": "传统节日纪念活动"}, "answer": "A", "explanation": "【解析】本题考查意识形态的内容。互联网是意识形态工作的主阵地、主战场、最前沿，管好用好互联网是新形势下做好新闻舆论工作的关键。因此，选项 A 正确。选项 BCD，并不能作为主阵地，本题考查固定搭配。 8．文化软实力集中体现了一个国家基于文化而具有的凝聚力和生命力，以及由此产生的吸引力和影响力。一个国家的文化软实力，从根本上说，取决于（）。 A. 实施公民道德建设工程 B．其核心价值观的生命力、凝聚力、感召力 C．举精神旗帜、立精神支柱、建精神家园 D．发展文化事业、提升公共文化服务水平", "id": 179},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "文化认同是最深层次的认同，是民族团结之根、民族和睦之魂。一般认为，文化认同主要包括三个层面：一是各民族对自身的文化认同；二是各民族间的相互认同；三是中华共性文化认同。历史无论怎样发展，中华民族融为一体的状态没有改变，有着对中华文明的高度认同。这种对中华文明的高度认同体现了中华文明具有突出的（）。", "options": {"A": "连续性", "B": "统一性", "C": "包容性", "D": "创新性"}, "answer": "B", "explanation": "【解析】本题考查中华文明的突出特性。中华文明具有突出的统一性，从根本上决定了中华民族各民族文化融为一体、即使遭遇重大挫折也牢固凝聚，决定了国家统一永远是中国核心利益的核心，决定了一个坚强统一的国家是各族人民的命运所系。所以对中华文明的高度认同体现了中华文明具有突出的统一性。因此，选项 B 正确。选项 A，连续性从根本上决定了中华民族必然走自己的路。选项 C，包容性从根本上决定了中华民族交往交流交融的历史取向，决定了中国各宗教信仰多元并存的和谐格局，决定了中华文化对世界文明兼收并蓄的开放胸怀。选项 D，创新性从根本上决定了中华民族守正不守旧、尊古不复古的进取精神，决定了中华民族不惧新挑战、勇于接受新事物的无畏品格。 10\\. 文化是一个国家、一个民族的灵魂。国家的富强，民族的振兴，无不伴随着文化的历史性进步。建设社会主义文化强国、推动社会主义文化繁荣兴盛，关键在于（）。 A. 坚定中国特色社会主义文化自信 B．坚持马克思主义在意识形态领域的指导地位 C．以社会主义核心价值观引领文化建设 D．缩小城乡公共文化服务差距", "id": 180},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "人类社会发展的历史表明，对一个民族、一个国家来说，最持久、最深层次的力量是全社会共同认可的核心价值观。面对世界范围思想文化交流交融交锋形势下价值观较 量的新态势，面对改革开放和发展社会主义市场经济条件下思想意识多元多样多变的新特点，积极培育和践行社会主义核心价值观，有利于（）。", "options": {"A": "巩固马克思主义在意识形态领域的指导地位", "B": "巩固全党全国人民团结奋斗的共同思想基础", "C": "聚集实现中华民族伟大复兴中国梦的强大正能量", "D": "促进人的全面发展和引领社会全面进步"}, "answer": "ABCD", "explanation": "【解析】本题考查社会主义核心价值观，属于分析理解题。社会主义核心价值观体现了社会主义意识形态的本质要求，体现了社会主义制度在思想和精神层面的质的规定性，凝结着社会主义先进文化的精髓，是中国特色社会主义道路、理论体系和制度的价值表达，是实现中华民族伟大复兴的中国梦的价值引领。社会主义核心价值观既体现了社会主义本质要求，继承了中华优秀传统文化，也吸收了世界文明有益成果，体现了时代精神，回答了我们要建设什么样的国家、建设什么样的社会、培育什么样的公民的重大问题。积极培育和践行社会主义核心价值观，有利于巩固马克思主义在意识形态领域的指导地位，有利于巩固全党全国人民团结奋斗的共同思想基础，有利于聚集实现中华民族伟大复兴中国梦的强大正能量，有利于促进人的全面发展和引领社会全面进步。因此，选项 ABCD 正确。", "id": 181},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平总书记强调：“把培育和弘扬社会主义核心价值观作为凝魂聚气、强基固本的基础工程。”这是因为（）。", "options": {"A": "中国特色社会主义需要一个能够被全社会共同接受和认同的价值观来引领", "B": "核心价值观是一个国家的重要稳定器", "C": "坚守社会主义核心价值观是实现人民当家作主的根本保证", "D": "社会主义核心价值观能够内化为人们的精神追求，外化为人们的自觉行动"}, "answer": "ABD", "explanation": "【解析】本题考查社会主义核心价值观。建设和发展中国特色社会主义，需要有一个能够被全社会共同接受和认同的社会主义核心价值体系和核心价值观来引领。核心价值体系和核心价值观，是决定文化性质和方向的最深层次要素，是一个国家的重要稳定器。坚守社会主义核心价值体系和社会主义核心价值观就是通过教育引导、舆论宣传、文化熏陶、实践养成、制度保障等，使社会主义核心价值观内化为人们的精神追求，外化为人们的自觉行动。因此，选项 ABD 正确。选项 C，中国共产党的领导是人民当家作主和依法治国的根本保证，故不选。", "id": 182},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "2023 年是毛泽东等老一辈革命家为雷锋同志题词 60 周年。60 年来，学雷锋活动在全国持续深入开展，雷锋的名字家喻户晓，雷锋的事迹深入人心，雷锋精神滋养着一代代中华儿女的心灵。实践证明，无论时代如何变迁，雷锋精神永不过时。党中央通过培育先进典型榜样，抓好社会主义精神文明建设的意义在于（）。", "options": {"A": "为实现中华民族伟大复兴的中国梦提供坚实的制度基础", "B": "为全面建成社会主义现代化强国提供丰润的道德滋养", "C": "为中国特色社会主义建设提供强大的精神力量", "D": "为全国各族人民不断前进提供坚强的思想保证"}, "answer": "BCD", "explanation": "【解析】本题考查社会主义文化建设。文化作为上层建筑，先进的文化可以为全面建成社会主义现代化强国提供丰润的道德滋养；为中国特色社会主义建设提供强大的精神力量；为全国各族人民不断前进提供坚强的思想保证。因此，选项 BCD 正确。选项 A，文化建设提供的是精神动力和思想保证，提供不了制度基础，故不选。 4．文化自信是更基础、更广泛、更深厚的自信，是一个国家、一个民族发展中最基本、最深沉、最持久的力量。坚定中国特色社会主义文化自信的依据是（）。 A. 中华优秀传统文化 B．党带领人民在伟大斗争中孕育的革命文化 C．党带领人民在伟大斗争中孕育的社会主义先进文化 D．中国特色社会主义伟大实践", "id": 183},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "文化是一个国家、一个民族的灵魂。国家的富强，民族的振兴，无不伴随着文化的历史性进步。新时代新的文化使命，是在新的起点上（）。", "options": {"A": "弘扬中国精神、传播中国价值、凝聚中国力量", "B": "继续推动文化繁荣", "C": "建设文化强国", "D": "建设中华民族现代文明"}, "answer": "BCD", "explanation": "【解析】新时代新的文化使命是，在新的起点上继续推动文化繁荣、建设文化强国、建设中华民族现代文明。BCD 正确。弘扬中国精神、传播中国价值、凝聚中国力量是文艺工作者的神圣职责，A 错误。", "id": 184},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "党的十八大以来在中共中央政治局举行的集体学习中，中华优秀传统文化多次成为重要内容：“我国历史上的反腐倡廉”“我国历史上的国家治理”“我国历史上的法治和德治”“中国历史上的吏治”“我国考古最新发现及其意义”“深化中华文明探源工程”……这份“课程表”背后，是对中华文化的深切思考。中华优秀传统文化是（）。", "options": {"A": "中华文明的智慧结晶和精华所在", "B": "中华民族的根和魂", "C": "我们在世界文化激荡中站稳脚跟的根基", "D": "全党全国各族人民团结奋斗的共同思想基础"}, "answer": "ABC", "explanation": "【解析】中华优秀传统文化是中华文明的智慧结晶和精华所在，是中华民族的根和魂，是我们在世界文化激荡中站稳脚跟的根基。ABC 正确。习近平新时代中国特色社会主义思想是全党全国各族人民团结奋斗的共同思想基础，D 错误。 8．对历史最好的继承，就是创造新的历史。铸就社会主义文化新辉煌，就要推动中华优秀传统文化创造性转化、创新性发展。要通过创造性转化和创新性发展，使中华民族最基本的文化基因（）。 A. 同当代中国相适应 B. 同现代社会相协调 C. 同现实文化相融通 D. 同国际社会接轨", "id": 185},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "在新的历史起点上继续推动文化繁荣、建设文化强国、建设中华民族现代文明，要（）。", "options": {"A": "坚定文化自信", "B": "秉持开放包容", "C": "坚持守正创新", "D": "坚持胸怀天下"}, "answer": "ABC", "explanation": "【解析】在新的历史起点上继续推动文化繁荣、建设文化强国、建设中华民族现代文明：第一，要坚定文化自信，坚持走自己的路，实现精神上的独立自主。第二，要秉持开放包容。第三，要坚持守正创新，以守正创新的正气和锐气，赓续历史文脉、谱写当代华章。ABC正确，D错误。", "id": 186},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "江山就是人民，人民就是江山。我们要实现好、维护好、发展好最广大人民根本利益，就必须紧紧抓住人民最关心最直接最现实的利益问题。要坚持在发展中保障和改善民生，其中，关乎最基本民生问题的举措是（）。", "options": {"A": "实施就业优先战略", "B": "健全社会保障体系", "C": "推进健康中国建设", "D": "办好人民满意的教育"}, "answer": "A", "explanation": "【解析】本题考查在发展中保障和改善民生。习近平总书记在党的二十大报告中强调：“就业是最基本的民生。”因此，选项 A 正确。选项 BCD，都是保障和改善民生的具体举措，但不是“最基本的民生问题”，故不选。 2．共同富裕是全体人民共同富裕，是人民群众物质生活和精神生活都富裕，不是少数人的富裕，也不是整齐划一的平均主义。促进共同富裕的基础性制度是（）。 A. 社会主义基本经济制度 B. 所有制制度 C. 分配制度 D. 社会主义市场经济体制", "id": 187},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "民生事关人民的生存生活生计，事关民心所向、民情所系、民意所指，决定党的事业成败和国家命运兴衰。保障和改善民生的重要方针是（）。", "options": {"A": "坚持尽力而为、量力而行", "B": "坚守底线、突出重点", "C": "完善制度、引导预期", "D": "坚持人人尽责、人人享有"}, "answer": "A", "explanation": "【解析】坚持尽力而为、量力而行，是保障和改善民生的重要方针。A 正确。坚守底线、突出重点、完善制度、引导预期，是保障和改善民生的工作思路；坚持人人尽责、人人享有，让所有劳动者在推动发展中分享发展成果，是保障和改善民生的重要原则；解决人民群众最关心、最直接、最现实的利益问题，是保障和改善民生的重中之重。BCD 错误。 4\\. 改善民生、实现发展成果由人民共享最重要最直接的方式是（）。 A. 稳就业 B. 城镇化 C. 社会保障 D. 收入分配", "id": 188},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "理念是完善社会治理体系的先导，必须坚持共建共治共享的社会治理理念。其中，共建是社会治理的（）。", "options": {"A": "关键", "B": "基础", "C": "核心", "D": "目标"}, "answer": "B", "explanation": "【解析】理念是完善社会治理体系的先导，必须坚持共建共治共享的社会治理理念。共建是共同参与社会建设，要求突出制度和体系建设的基础性、战略性地位，是社会治理的基础；共治是共同参与社会治理，要求树立大社会观、大治理观，打造全民参与的开放治理体系，是社会治理的关键；共享是共同享有社会治理成果，要求社会治理的成效更多更公平惠及全体人民，是社会治理的目标。B 正确，ACD 错误。", "id": 189},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "经过接续奋斗，我国社会建设全面加强，人民安居乐业、社会安定有序的良好局面不断巩固发展，人民对美好生活的向往不断变为现实。新时代加强社会建设的重要着力点是（）。", "options": {"A": "健全和完善社会保障体系", "B": "正确把握民生和发展的关系", "C": "全面推进健康中国建设", "D": "防范化解重大风险"}, "answer": "A", "explanation": "【解析】健全和完善社会保障体系是新时代加强社会建设的重要着力点，A 正确。正确把握民生和发展的关系，是保障和改善民生的重要前提。BCD 错误。", "id": 190},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "基础不牢，地动山摇。习近平指出，基层强则国家强，基层安则天下安，必须抓好基层治理现代化这项基础性工作。基层治理是国家治理的基石，社会治理最基本的单元是（）。", "options": {"A": "城乡社区", "B": "县级政府", "C": "市级政府", "D": "基层党组织"}, "answer": "A", "explanation": "【解析】本题考查社会治理。基层治理是国家治理的基石，城乡社区是社会治理最基本的单元，是党和政府联系、服务居民群众的“最后一公里”。社会治理的重心必须向基层下移，落实到城乡社区，有效防范化解社会矛盾和风险。因此，选项 A 正确。选项 BCD，均不符合题意，故不选。 ##### 多项选择题", "id": 191},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "社会主义分配制度既有利于鼓励先进、促进效率、最大限度激发活力，又有利于防止两极分化，逐步实现共同富裕，使人民群众共享改革发展成果。因此，坚持和完善社会主义分配制度，就要（）。", "options": {"A": "坚持多劳多得，着重保护劳动所得，提高劳动报酬在初次分配中的比重", "B": "健全劳动、资本、土地、知识、技术、管理、数据等生产要素由市场评价贡献、按贡献决定报酬的机制", "C": "健全以税收、社会保障、转移支付等为主要手段的再分配调节机制", "D": "重视发挥第三次分配作用，发展慈善等社会公益事业"}, "answer": "ABCD", "explanation": "【解析】本题考查社会主义分配制度。党的十九届四中全会将“坚持按劳分配为主体、多种分配方式并存”纳入社会主义基本经济制度范畴，提出“第三次分配”的新表述，同学们需要特别注意。一是完善初次分配制度，要坚持多劳多得，着重保护劳动所得：增加劳动者特别是一线劳动者劳动报酬，提高劳动报酬在初次分配中的比重。健全劳动、资本、土地、知识、技术、管理、数据等生产要素由市场评价贡献、按贡献决定报酬的机制。二是健全再分配调节机制，健全以税收、社会保障、转移支付等为主要手段的再分配调节机制，强化税收调节，完善直接税制度并逐步提高其比重。完善相关制度和政策，合理调节城乡、区域、不同群体间分配关系。三是重视发挥第三次分配作用，发展慈善等社会公益事业。第三次分配是在道德、文化、习惯等影响下，社会力量自愿通过民间捐赠、慈善事业、志愿行动等方式济困扶弱的行为，是对再分配的有益补充。随着我国经济发展和社会文明程度提高，全社会公益慈善意识日渐增强，所以首次在中央文件中提出了“第三次分配”的概念。因此，选项 ABCD 正确。 2．增进人民福祉、促进人的全面发展是我们党立党为公、执政为民的本质要求。党的十九届四中全会提出“完善覆盖全民的社会保障体系”，建立健全社会保障体系的必要性在于（）。 A. 是社会主义市场经济发展的客观需要 B．是实现社会全面进步的需要 C．是转换企业经营机制，搞活企业的需要 D．是保持社会稳定和国家", "id": 192},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "保障和改善民生的重要前提，是正确把握民生和发展的关系。以下说法正确的有()。", "options": {"A": "发展是解决民生问题的“总钥匙”", "B": "民生是发展的“指南针”", "C": "发展是改善民生的物质基础", "D": "持续不断改善民生能够调动人们发展生产的积极性"}, "answer": "ABCD", "explanation": "【解析】正确把握民生和发展的关系，是保障和改善民生的重要前提。发展是解决民生问题的“总钥匙”，民生是发展的“指南针”。发展是改善民生的物质基础，离开发展谈改善民生是无源之水、无本之木。如果发展不能回应人民的期待，不能让群众得到实际利益，这样的发展就失去意义，也不可能持续。民生连着内需、连着发展。抓民生也是抓发展，持续不断改善民生，能够有效解决群众后顾之忧，调动人们发展生产的积极性，增进社会消费预期，利于扩大内需，催生新的增长点。ABCD全选。 4．社会治理体系是进行社会治理的基础，也是提高社会治理效能的保障。加快完善社会治理体系，是一项系统性工程，要根据社会治理实际和人民新期待，进一步创新社会治理理念，健全社会治理制度，改进社会治理方式，不断推进社会治理体系和治理能力现代化。完善社会治理体系必须（）。 A. 坚持共建共治共享的社会治理理念 B. 健全社会治理制度，提升社会治理效能 C. 不断创新社会治理方式、途径和手段 D. 以制度建设为先导", "id": 193},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "中国特色社会主义进入新时代以来，我国经济社会发展取得了举世瞩目的重大成就。居民收入增长与经济增长基本同步，全国居民人均可支配收入年均增长5.1%。居民消费价格年均上涨2.1%。新增劳动力平均受教育年限从13.5年提高到14年。基本养老保险参保人数增加1.4亿、覆盖10.5亿人，基本医保水平稳步提高。多年累计改造棚户区住房4200多万套，上亿人出棚进楼、实现安居。我国人民生活水平不断提高表明，增进民生福祉是（）。", "options": {"A": "坚持立党为公、执政为民的本质要求", "B": "社会主义生产的根本目的", "C": "当前中国共产党的中心任务", "D": "全面建设社会主义现代化国家的应有之义"}, "answer": "ABD", "explanation": "【解析】本题考查增进民生福祉。第一，增进民生福祉是坚持立党为公、执政为民的本质要求。第二，增进民生福祉是社会主义生产的根本目的。第三，增进民生福祉是全面建设社会主义现代化国家的应有之义。因此，选项 ABD 正确。选项 C，当前中国共产党的中心任务是以中国式现代化全面推进中华民族伟大复兴，而不是增进民生福祉。", "id": 194},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "进入新时代，党和国家持续实施就业优先战略和积极的就业政策，我国就业形势保持总体稳定。就业（）。", "options": {"A": "是最基本的民生", "B": "是劳动者赖以生存和发展的基础、共享经济发展成果的基本条件", "C": "是改善民生、实现发展成果由人民共享最重要、最直接的方式", "D": "关系到亿万劳动者及其家庭的切身利益"}, "answer": "ABD", "explanation": "【解析】收入分配是民生之源，是改善民生、实现发展成果由人民共享最重要、最直接的方式。C 错误。ABD 正确。", "id": 195},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "建设生态文明、推动绿色低碳循环发展，不仅可以满足人民日益增长的优美生态 环境需要，而且可以推动实现更高质量、更有效率、更加公平、更可持续、更为安全的发展，走出一条生产发展、生活富裕、生态良好的文明发展道路。因此（）。", "options": {"A": "生态环境保护和经济发展是彼此孤立、各自为战的", "B": "发展了经济，就等于保护好了生态环境", "C": "生态环境保护和经济发展是辩证统一、相辅相成的", "D": "保护好生态环境，就等于发展了经济"}, "answer": "C", "explanation": "【解析】本题考查建设生态文明、推动绿色发展。习近平总书记指出：“我们既要绿水青山，也要金山银山。宁要绿水青山，不要金山银山，而且绿水青山就是金山银山。”这段话揭示了生态环境保护和经济发展是辩证统一、相辅相成的，保护生态环境就是保护生产力、改善生态环境就是发展生产力的道理。因此，选项 C 正确。选项 A，只看到了生态和经济的对立面，没有看到二者之间的统一面，故不选。选项 BD，将生态和经济简单地等同是不对的，二者是在发展中保护，在保护中发展，故不选。 3．发达国家和发展中国家处于不同发展阶段，在环境问题上的历史责任和现实能力存在差异。根据国际能源署、世界银行等机构的统计数据，在居民人均消费碳排放方面，发展中国家大多只是“生存型”排放，而发达国家早已是“奢侈型”或“浪费型”排放。必须充分考虑历史责任、各国国情和生态治理能力，坚持各尽所能、国家自主决定贡献的制度安排。这说明建设人与自然和谐共生的地球家园必须（）。 A. 坚持科学治理 B. 坚持多边主义 C. 坚持共同但有区别的责任原则 D. 坚持以人为本", "id": 196},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "建设美丽中国，是全面建设社会主义现代化国家的重要目标，也是满足人民日益增长的优美生态环境需要的必然要求。我国美丽中国建设目标基本实现是在（）。", "options": {"A": "2025 年", "B": "2035 年", "C": "2050 年", "D": "2060 年"}, "answer": "B", "explanation": "【解析】本题考查美丽中国建设。党的二十大进一步明确，全面建成社会主义现代化强国总的战略安排是分两步走：从2020年到2035年基本实现社会主义现代化；从2035年到21世纪中叶把我国建成富强民主文明和谐美丽的社会主义现代化强国。到2035年，我国发展的总体目标，体现在生态方面是广泛形成绿色生产生活方式，碳排放达峰后稳中有降，生态环境根本好转，美丽中国建设目标基本实现。因此，选项B正确。 5\\. 生态环境变化直接影响文明的兴衰演替。生态环境问题归根到底是（）。 A. 政府与市场的关系问题 B. 人与社会的关系问题 C. 人与人的关系问题 D. 经济发展方式和生活方式问题", "id": 197},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "改革开放以来，我国经济发展取得巨大成就，也积累了大量生态环境问题。如果不抓紧扭转生态环境恶化趋势，必将付出极其沉重的代价。解决生态环境问题的治本之策是（）。", "options": {"A": "全面建立资源高效利用制度", "B": "绿色低碳发展", "C": "实行最严格的生态环境保护制度", "D": "坚持山水林田湖草沙一体化保护和系统治理"}, "answer": "B", "explanation": "", "id": 198},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "习近平总书记指出，环境就是民生，青山就是美丽，蓝天也是幸福。要着力推动生态环境保护，像保护眼睛一样保护生态环境，像对待生命一样对待生态环境。着力解决突出的环境问题，打赢环境治理攻坚战，要求我们（）。", "options": {"A": "强化土壤污染管控和修复", "B": "加快水污染治理", "C": "打赢蓝天保卫战", "D": "持续实施大气污染防治行动"}, "answer": "ABCD", "explanation": "【解析】本题考查解决突出环境问题的措施。着力解决突出的环境问题，聚焦环境保护的重点，打赢环境治理攻坚战，要求我们坚持全民共治、源头防治，持续实施大气污染防治行动，打赢蓝天保卫战，加快水污染治理，强化土壤污染管控和修复。因此，选项ABCD正确。", "id": 199},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "2023 年 1 月 19 日，国务院新闻办公室发布《新时代的中国绿色发展》白皮书。该白皮书指出，绿色是生命的象征、大自然的底色，良好生态环境是美好生活的基础、人民共同的期盼。绿色发展是顺应自然、促进人与自然和谐共生的发展，是用最少资源环境代价取得最大经济社会效益的发展，是高质量、可持续的发展，已经成为各国共识。我国高度重视生态文明建设的原因在于（）。", "options": {"A": "大自然是人类赖以生存发展的基本条件", "B": "尊重自然、顺应自然、保护自然，是全面建设社会主义现代化国家的内在要求", "C": "建设美丽中国是全面建设社会主义现代化国家的首要任务", "D": "中国承诺必须成为世界上最快实现碳达峰碳中和的国家"}, "answer": "AB", "explanation": "【解析】本题考查生态文明建设。党的二十大报告指出：“大自然是人类赖以生存发展的基本条件。尊重自然、顺应自然、保护自然，是全面建设社会主义现代化国家的内在要求。必须牢固树立和践行绿水青山就是金山银山的理念，站在人与自然和谐共生的高度谋划发展。”因此，选项 AB 正确。选项 C，高质量发展是全面建设社会主义现代化国家的首要任务，故不选。选项 D，说法违背政治常识，我们的目标不是成为世界上最快实现碳达峰碳中和的国家。事实上，根据我国的实际情况，我们有清晰的规划，力争 2030 年前实现碳达峰，2060 年前实现碳中和。故不选。", "id": 200},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "绿水青山就是金山银山，这是重要的发展理念，也是推进现代化建设的重大原则。这一理念，阐明了经济发展与生态环境保护之间的关系。生态环境问题归根到底是（）。", "options": {"A": "经济发展方式问题", "B": "生活方式问题", "C": "文化问题", "D": "历史问题"}, "answer": "AB", "explanation": "【解析】本题考查生态环境问题。生态环境问题归根到底是经济发展方式和生活方式问题。绿水青山就是金山银山，这是重要的发展理念，也是推进现代化建设的重大原则。因此，选项 AB 正确。选项 CD，生态问题着眼于当前和未来，因此不能归结为历史问题，更不是文化问题。 4．面对资源约束趋紧、环境污染严重、生态系统退化的严峻形势，必须树立尊重自然、顺应自然、保护自然的生态文明理念。其中，保护自然是人与自然相处时应承担的重要责任，要求人们（）。 A. 保护自然生态系统 B．把人类活动控制在自然能够承受的限度之内 C. 实现人类对自然获取和给予的平衡 D. 防止出现生态赤字和生态灾难", "id": 201},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "坚持总体国家安全观关键在“总体”，突出的是“大安全”理念，涵盖政治、军事、国土、经济、文化、社会、科技等诸多领域。其中，总体国家安全观的根本是（）。", "options": {"A": "政治安全", "B": "经济安全", "C": "人民安全", "D": "军事、文化、社会安全"}, "answer": "A", "explanation": "【解析】本题考查坚持总体国家安全观。坚持总体国家安全观，必须坚持国家利益至上，以人民安全为宗旨，以政治安全为根本，以经济安全为基础，以军事、文化、社会安全为保障，完善国家安全制度体系，加强国家安全能力建设，坚决维护国家主权、安全、发展利益。因此，选项 A 正确。选项 BCD，坚持总体国家安全观，经济安全是基础，人民安全是宗旨，军事、文化、社会安全是保障，故不选。 2．产业链供应链是现代经济的重要形态，近年来，我国围绕产业链供应链的韧性和安全水平提升开展一系列补链强链延链工作，但也要看到，我国产业链供应链大而不强、全而不精、韧中有脆，仍存在一系列亟待解决的问题，比如，关键环节创新能力不足，生产要素运输效率不高，数字经济赋能效果有待提升，需求端驱动力不足，等等。我国之所以聚焦这些短板弱项，打通产业链供应链卡点、堵点、断点，确保产业链供应链安全稳定，是因为（）。 A. 只要提升产业链供应链韧性和安全水平就能保证经济安全 B. 产业链供应链稳定安全是增强维护国家安全能力的重要环节 C. 经济安全是人民群众安全感的晴雨表 D. 我国产业链供应链安全问题已经外溢为区域性安全问题", "id": 202},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "总体国家安全观从战略和全局的高度看待国家各层面、各领域安全问题，统筹运用各方面资源和手段予以综合解决，实现国家安全多方面内容和要求的有机统一。其中，总体国家安全观的宗旨是（）。 下篇 > 练习题", "options": {"A": "人民安全", "B": "政治安全", "C": "经济安全", "D": "国际安全"}, "answer": "A", "explanation": "【解析】本题考查坚持总体国家安全观。坚持总体国家安全观以人民安全为宗旨。因此，选项 A 正确。选项 B，总体国家安全观以政治安全为根本。选项 C，总体国家安全观以经济安全为基础。选项 D，总体国家安全观以促进国际安全为依托。 4．全面推进中华民族伟大复兴，既无比光荣又困难重重。民族复兴的根基是（）。 A. 国家安全 B. 社会稳定 C. 民族团结 D. 人民幸福", "id": 203},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "党的二十大首次将“推进国家安全体系和能力现代化，坚决维护国家安全和社会稳定”作为独立部分，对国家安全作了系统阐述，体现了党治国理政总体布局的新拓展，为我们做好维护国家安全工作指明了方向，提供了根本遵循。开创新时代国家安全工作新局面的主要举措有（）。", "options": {"A": "走军民融合式发展路子", "B": "推进国家安全体系和能力现代化", "C": "建设更高水平的平安中国", "D": "提高防范化解重大风险能力"}, "answer": "BCD", "explanation": "【解析】本题考查开创新时代国家安全工作新局面。开创新时代国家安全工作新局面，要正确认识和把握重大国家安全问题，推进国家安全体系和能力现代化，推动建设更高水平的平安中国，着力提高防范化解重大风险能力和水平，不断塑造总体有利的国家安全战 略态势。因此，选项 BCD 正确。选项 A，走军民融合式发展路子是实现富国和强军相统一的重要途径，而不是国家安全工作的举措。 3．党的十九届五中全会把统筹发展和安全纳入“十四五”时期我国经济社会发展的指导思想。党的十九届六中全会再次强调要统筹发展和安全。党的二十大报告提出，以新安全格局保障新发展格局。目前，社会上对统筹发展和安全问题还存在一些误区，必须从理论、实践及战略等层面厘清各种误区，走出统筹发展和安全更加强调安全、不重视发展的认识误区。要走出“更加强调安全，不重视发展”的误区，就必须认识到（）。 A. 发展就是最大的安全 B．发展解决的是动力问题，是推动国家和民族赓续绵延的根本支撑 C．发展和安全是两件大事，必须统筹发展和安全 D．安全具有基础性、根本性", "id": 204},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "构建统筹各领域安全的新安全格局，必须把维护政治安全作为应对各领域安全风险挑战的首要任务。这是因为（）。", "options": {"A": "政治安全是国家安全的根本", "B": "政治安全是一切国家生存和发展的基础条件", "C": "政治安全决定和影响着国家其他各个领域的安全", "D": "政治安全是立国之基"}, "answer": "ABC", "explanation": "【解析】国土安全是立国之基，老祖宗留下来的领土一寸也不能丢，我们决不会坐视领土完整受到侵犯。D 错误。ABC 正确。 5\\. 维护政治安全的主要内容包括（）。 A. 维护政权安全 B. 维护制度安全 C. 维护国土安全 D. 维护意识形态安全", "id": 205},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党在会议报告中对全面推进国防和军队现代化作出新的战略安排：到 2020 年，国防和军队建设要基本实现机械化，信息化建设取得重大进展，战略能力有大的提升；到 2035 年，基本实现国防和军队现代化；到 21 世纪中叶，把人民军队全面建成世界一流军队。这一部署，绘就了建设强大人民军队的路线图、时间表。有效履行我军根本职能的内在要求的唯一标准是（）。", "options": {"A": "政治建军", "B": "战斗力", "C": "依法治军、从严治军", "D": "改革"}, "answer": "B", "explanation": "【解析】本题考查国防和军队建设，属于记忆题。军队强不强，关键看打仗；战场打不赢，一切等于零。把战斗力作为唯一的根本的标准，是有效履行人民军队根本职能的要求，也是提高军队建设质量和效益的要求，无论过去、现在和将来，战斗力标准始终是军事领域衡量利弊得失的重要标准。因此，选项 B 正确。选项 A，政治建军是人民军队的立军之本。与题意不符，故不选。选项 C，依法治军、从严治军是我们党建军治军的基本方略。与题意不符，故不选。选项 D，改革是决定人民军队发展壮大、制胜未来的关键一招。与题意不符，故不选。", "id": 206},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "“强国必须强军，军强才能国安”，“建设一支听党指挥、能打胜仗、作风优良的人民军队，是实现‘两个一百年’奋斗目标、实现中华民族伟大复兴的战略支撑。”人民军队的建军之本、强军之魂是（）。", "options": {"A": "党对人民军队的绝对领导", "B": "国防和军队现代化", "C": "为人民服务", "D": "能打胜仗"}, "answer": "A", "explanation": "【解析】本题考查坚持党对人民军队的绝对领导。党对人民军队的绝对领导，是人民军队建军之本、强军之魂，必须全面贯彻党领导军队的一系列根本原则和制度，确保部队绝对忠诚、绝对纯洁、绝对可靠。因此，选项 A 正确。选项 B，国防和军队现代化是我们党的战略任务和奋斗目标，与题干无关，故不选。选项 C，为人民服务是人民军队的宗旨。选项 D，党在新时代的强军目标是建设一支听党指挥、能打胜仗、作风优良的人民军队，其中，能打胜仗是核心。 3．党的十八大以来，以习近平同志为核心的党中央深刻把握强国对强军的战略需求，围绕新时代建设一支什么样的强大人民军队、怎样建设强大人民军队，深入进行理论探索和实践创造，形成习近平强军思想并不断丰富和发展。习近平强军思想明确军民融合发展 是（）。 A. 建军之本、强军之魂 B. 党建军治军基本方式 C. 我军鲜明特色和政治优势 D. 兴国之举、强军之策", "id": 207},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "人民军队的鲜明特色和政治优势，也是人民军队战无不胜、攻无不克的重要保证的是（）。", "options": {"A": "听党指挥", "B": "能打胜仗", "C": "作风优良", "D": "本领过硬"}, "answer": "C", "explanation": "【解析】作风优良是保证，关系军队的性质、宗旨、本色，是人民军队的鲜明特色和政治优势，也是人民军队战无不胜、攻无不克的重要保证。C 正确。听党指挥是灵魂，决定军队建设的政治方向；能打胜仗是核心，反映军队的根本职能和军队建设的根本指向。ABD 不符合题意。 5．新的征程上，开创国防和军队现代化新局面，必须全面推进政治建军、改革强军、科技强军、人才强军、依法治军，加快把人民军队建设成为世界一流军队。其中，推动人民军队高质量发展、赢得军事竞争和未来战争主动的关键因素是（）。 A. 改革 B. 科技 C. 人才 D. 军事法治体系", "id": 208},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "坚持党对人民军队的绝对领导，是马克思主义建党建军的一条基本原则。习近平指出：“坚持党指挥枪、建设自己的人民军队，是党在血与火的斗争中得出的颠扑不破的真理。”坚持党对人民军队绝对领导的根本制度和根本实现形式是（）。", "options": {"A": "政治建军", "B": "首长分工负责制", "C": "科技强军战略", "D": "军委主席负责制"}, "answer": "D", "explanation": "【解析】本题考查坚持党对人民军队的绝对领导。军委主席负责制是坚持党对人民军队绝对领导的根本制度和根本实现形式，在党领导军队的一整套制度体系中处于最高层次，居于统领地位。因此，选项 D 正确。选项 A，政治建军是人民军队的立军之本：抓军队建 设首先要从政治上看。与题意不符，故不选。选项 B，坚持党对军队的绝对领导必须有一整套制度作保证，实行党委（支部）统一的集体领导下的首长分工负责制是其中之一。与题意不符，故不选。选项 C，一流军队要求一流科技，必须全面实施科技强军战略。与题意不符，故不选。 #### 多项选择题", "id": 209},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "人民军队是执行党的政治任务的武装集团，党和人民所需就是军队使命任务所系。人民军队自成立起，就始终为争取民族独立、人民解放和实现国家富强、人民幸福而英勇奋斗。进入新时代，人民军队的使命任务是（）。", "options": {"A": "为促进世界和平与发展提供战略支撑", "B": "为维护我国海外利益提供战略支撑", "C": "为捍卫国家主权、统一和领土完整提供战略支撑", "D": "为巩固中国共产党领导和我国社会主义制度提供战略支撑"}, "answer": "ABCD", "explanation": "【解析】本题考查新时代人民军队使命任务。进入新时代，人民军队的使命任务概括起来就是“四个战略支撑”：为巩固中国共产党领导和我国社会主义制度提供战略支撑；为捍卫国家主权、统一和领土完整提供战略支撑；为维护我国海外利益提供战略支撑；为促进世界和平与发展提供战略支撑。因此，选项 ABCD 正确。", "id": 210},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "我们的军队是人民军队，我们的国防是全民国防。巩固提高一体化国家战略体系和能力，是党中央把握强国强军面临的新形势新任务新要求。要统筹全局，突出重点，以重点突破带动整体推进。必须向改革创新要动力，要坚持问题导向，持续优化体制机制，完善政策制度：形成各司其职、紧密协作、规范有序的工作格局，更好推进一体化国家战略体系和能力建设。为此应该（）。", "options": {"A": "把国防和军队建设融入经济社会发展大体系", "B": "加强国防动员和后备力量建设，增强打赢未来战争的国防潜力", "C": "坚持军民合力共建边海空防，发挥党政军警民合力强边固防的独特优势", "D": "大力弘扬拥政爱民、拥军优属的光荣传统"}, "answer": "ABCD", "explanation": "【解析】本题考查巩固提高一体化国家战略体系和能力。巩固提高一体化国家战略体系和能力，是党中央把握强国强军面临的新形势新任务新要求，必须把国防和军队现代化融入国家现代化，把国防和军队建设融入经济社会发展大体系；加强国防动员和后备力量建设，增强打赢未来战争的国防潜力；坚持军民合力共建边海空防，发挥党政军警民合力强边固防的独特优势，周密组织边境管控和海上维权行动，建设强大稳固的现代边海空防； 大力弘扬拥政爱民、拥军优属的光荣传统，巩固发展军政军民团结，为推进强国强军汇聚强大力量。因此，选项 ABCD 正确。 3．习近平指出：“我们捍卫和平、维护安全、慑止战争的手段和选择有多种多样，但军事手段始终是保底手段。”只有以强大军事实力为后盾（）。 A. 政治安全、国土安全等其他安全才能托底 B．国家的总体安全和人民的幸福生活才有保障 C. 实现国家繁荣富强的主动权才能牢牢掌握在自己手中 D. 当代中国价值观念才能走向世界", "id": 211},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "解决台湾问题、实现祖国完全统一，是全体中华儿女的共同愿望，是中华民族根本利益所在。党的十八大以来，在以习近平同志为核心的党中央坚强领导下，在两岸同胞共同努力下，两岸关系取得重要积极成果。两岸关系和平发展的政治基础是（）。", "options": {"A": "深化两岸利益融合，共创两岸互利双赢，增进两岸同胞福祉", "B": "坚持 “九二共识”，反对 “台独”", "C": "增强两岸同胞的民族认同、文化认同、国家认同", "D": "相互尊重，求同存异"}, "answer": "B", "explanation": "【解析】本题考查两岸关系和平发展的政治基础，属于记忆题。党的十八大以来，在以习近平同志为核心的党中央坚强领导下，在两岸同胞共同努力下，两岸关系取得重要积极成果，两岸关系和平发展的政治基础是坚持“九二共识”，反对“台独”。深化两岸利益融合，共创两岸互利双赢，增进两岸同胞福祉是推动两岸关系和平发展的宗旨。因此，选项B正确。选项A，“深化两岸利益融合，共创两岸互利双赢，增进两岸同胞福祉”是推动两岸关系和平发展的宗旨，故不选。选项C，“增强两岸同胞的民族认同、文化认同、国家认同”是两岸关系和平发展的人文交流方面的内容，故不选。选项D，“相互尊重，求同存异”是我国处理国与国之间关系的方针，两岸关系不属于“国与国”之间的关系，故不选。 2．习近平在庆祝香港回归祖国25周年大会暨香港特别行政区第六届政府就职典礼上强调，“一国两制”方针是一个完整的体系，其最高原则是（）。 A. 维护国家主权、安全、发展利益 B. 保证香港享有高度自治权 C. 保持原有的资本主义制度长期不变 D. 保持香港的独特地位和优势", "id": 212},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "新时代党解决台湾问题的总体方略内涵丰富、逻辑严密、系统完备，深刻回答了推进祖国统一的一系列重大理论和实践问题，是我们党对台大政方针的继承发展和集大成。其中，统一的历史方位是（）。", "options": {"A": "坚持团结台湾同胞、争取台湾民心", "B": "坚持在祖国大陆发展进步基础上解决台湾问题", "C": "坚持在中华民族伟大复兴进程中推进祖国统一", "D": "坚持推动两岸关系和平发展、融合发展"}, "answer": "C", "explanation": "【解析】本题考查新时代党解决台湾问题的总体方略。坚持在中华民族伟大复兴进程中推进祖国统一，这是统一的历史方位。因此，选项 C 正确。选项 A，坚持团结台湾同胞、争取台湾民心，这是统一的根本动力。选项 B，坚持在祖国大陆发展进步基础上解决台湾问题，这是统一的战略思路。选项 D，坚持推动两岸关系和平发展、融合发展，这是统一的实践途径。 4．香港和澳门必须坚持中央全面管治权和保障特别行政区高度自治权相统一。全面管治权是授权特别行政区高度自治的前提和基础，高度自治权是中央行使全面管治权的体现。香港和澳门的高度自治权实质上是（）。 A. 港澳的完全自治 B. 中央对港澳进行分权 C. 中央授予的地方事务管理权 D. 中央权力以外的“剩余权力”", "id": 213},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "在新时代党解决台湾问题的总体方略中，作为统一的战略支撑的是（）。", "options": {"A": "坚持决不承诺放弃使用武力", "B": "坚持粉碎“台独”分裂图谋", "C": "坚持团结台湾同胞、争取台湾民心", "D": "坚持反对外部势力干涉"}, "answer": "A", "explanation": "【解析】坚持团结台湾同胞、争取台湾民心，这是统一的根本动力；坚持粉碎“台独”分裂图谋，这是统一的必然要求；坚持反对外部势力干涉，这是统一的外部条件；坚持决不承诺放弃使用武力，这是统一的战略支撑。A 正确，BCD 错误。 #### 多项选择题", "id": 214},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "“和平统一、一国两制”的构想是充分尊重历史和现实、照顾各方利益、维护民族团结、实现祖国完全统一的科学构想。其具体含义包括（）。", "options": {"A": "以祖国统一为前提", "B": "国家的主体坚持社会主义制度", "C": "“九二共识”是台海两岸的选项之一", "D": "香港、澳门、台湾保持原有的资本主义制度长期不变"}, "answer": "ABD", "explanation": "【解析】本题考查“一国两制”。“和平统一、一国两制”是一个完整的体系，其基本内容就是在祖国统一的前提下，国家的主体坚持社会主义制度，同时在香港、澳门、台湾保持原有的资本主义制度长期不变。因此，选项 ABD 正确。选项 C，“九二共识”是台海两岸关系发展的基础和前提，不是选项之一，而是唯一选项，故不选。 2．习近平在庆祝香港回归祖国25周年大会暨香港特别行政区第六届政府就职典礼上指出：“‘一国两制’在香港的丰富实践给我们留下很多宝贵经验，也留下不少深刻启示。”这些启示有（）。 A. 必须全面准确贯彻 “一国两制” 方针 B．必须坚持中央全面管治权和保障特别行政区高度自治权相统一 C. 必须落实“爱国者治港” D．必须保持香港的独特地位和优势", "id": 215},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "准确把握“一国两制”科学内涵，必须坚持中央全面管治权和保障特别行政区高度自治权相统一。我国是单一制国家，中央对包括香港、澳门特别行政区在内的所有地方 行政区域拥有全面管治权。全面管治权与高度自治权在本质上是统一的（）。", "options": {"A": "全面管治权是授权特别行政区高度自治的前提和基础", "B": "高度自治权是中央行使全面管治权的体现", "C": "它们之间是源与流、本与末的关系", "D": "特别行政区不存在所谓“剩余权力”"}, "answer": "ABCD", "explanation": "【解析】坚持中央全面管治权和保障特别行政区高度自治权相统一。我国是单一制国家，中央对包括香港、澳门特别行政区在内的所有地方行政区域拥有全面管治权。全面管治权与高度自治权在本质上是统一的。全面管治权是授权特别行政区高度自治的前提和基础，高度自治权是中央行使全面管治权的体现。它们之间是源与流、本与末的关系。高度自治不是完全自治，也不是分权，而是中央授予的地方事务管理权。中央授予多少权力，特别行政区就享有多少权力，不存在所谓“剩余权力”。ABCD全选。", "id": 216},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "要始终坚持 “爱国者治港” “爱国者治澳”，把特别行政区管治权牢牢掌握在爱国者手中，这是（）。", "options": {"A": "事关国家主权、安全、发展利益的根本原则", "B": "事关香港、澳门长期繁荣稳定的根本原则", "C": "保证香港、澳门长治久安的必然要求", "D": "人民当家作主和依法治国的根本保证"}, "answer": "ABC", "explanation": "【解析】党的领导是人民当家作主和依法治国的根本保证。D 错误。ABC 正确。 （十七）中国特色大国外交和推动构建人类命运共同体 ##### 单项选择题", "id": 217},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "2023 年，从中国—中亚峰会到第三届“一带一路”国际合作高峰论坛，从对俄罗斯进行国事访问到出席南非金砖国家领导人第十五次会晤，中国特色大国外交牢牢把握的主线是（）。", "options": {"A": "为中国人民谋幸福、为中华民族谋复兴", "B": "服务民族复兴、促进人类进步", "C": "坚持走和平发展道路", "D": "推动构建人类命运共同体"}, "answer": "B", "explanation": "【解析】本题考查中国特色大国外交。中国特色大国外交牢牢把握服务民族复兴、促进人类进步这条主线。因此，选项 B 正确。选项 A，为中国人民谋幸福、为中华民族谋复兴 是中国共产党人的初心和使命。选项 C，坚持走和平发展道路是新时代中国外交的基本原则。选项 D，推动构建人类命运共同体是新时代对外工作的总目标。 2．周边是我国安身立命之所、发展繁荣之基。无论从地理方位、自然环境还是相互关系看，周边对我国都具有极为重要的战略意义。我国始终将周边置于外交全局的首要位置，秉持的周边外交理念是（）。 A. 与邻为善、以邻为伴 B. 真实亲诚 C. 亲诚惠容 D. 求同存异、相互尊重、互学互鉴", "id": 218},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "海南博鳌，从一个名不见经传的小镇变成了一个盛会的代名词。从2001年第一届博鳌亚洲论坛举办以来，借助一年一度的年会论坛平台，中国向世界展现了对外开放的勇气和魄力，为应对保护主义和逆全球化挑战作出了表率。我国之所以坚定不移地实施对外开放的基本国策，是因为（）。", "options": {"A": "实事求是是对外开放的根本立足点", "B": "我国全方面、宽领域、多层次的对外开放格局已彻底形成", "C": "全面开放是实现国家繁荣富强的根本出路", "D": "全面对外开放的总目标是完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化"}, "answer": "C", "explanation": "【解析】本题考查对外开放。对外开放是我国的基本国策，以开放促改革、促发展，是我国现代化建设不断取得新成就的重要法宝。全面开放是实现国家繁荣富强的根本出路。因此，选项 C 正确。选项 A，独立自主、自力更生是我国对外开放的立足点，故不选。选项 B，“已彻底形成”的说法过于绝对，一切还在进行中，故不选。选项 D，完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化是全面深化改革的总目标，故不选。 4．进入新时代，我国面临的国际环境和外交工作担负的使命任务发生新的变化，我国对外工作需要展现新气象、实现新作为。新时代，我国对外工作的总目标是（）。 A. 维护国家主权、安全、发展利益 B．推动构建人类命运共同体 C. 高质量共建“一带一路” D. 坚持走和平发展道路", "id": 219},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "2023 年 10 月 10 日，国务院新闻办公室发布《共建 “一带一路”：构建人类命运共同体的重大实践》白皮书。共建 “一带一路” 不仅给相关国家带来实实在在的利益，也为推进经济全球化健康发展、破解全球发展难题和完善全球治理体系作出积极贡献。共建 “一带一路” 的主线是（）。", "options": {"A": "高标准、可持续、惠民生", "B": "共商、共建、共享", "C": "开放、绿色、廉洁", "D": "互联互通"}, "answer": "D", "explanation": "【解析】本题考查共建“一带一路”。“一带一路”倡议的初心，是借鉴古丝绸之路，以互联互通为主线，同各国加强政策沟通、设施联通、贸易畅通、资金融通、民心相通，为世界经济增长注入新动能，为全球发展开辟新空间，为国际经济合作打造新平台。因此，选项D正确。选项ABC，共建“一带一路”，秉持共商共建共享原则，坚持开放、绿色、廉洁理念，以高标准、可持续、惠民生为目标，故不选。 ##### 多项选择题", "id": 220},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "2023 年 10 月，习近平主席出席第三届 “一带一路” 国际合作高峰论坛开幕式并发表主旨演讲。中国正在以中国式现代化全面推进强国建设、民族复兴伟业。我们追求的不是中国独善其身的现代化，而是期待同广大发展中国家在内的各国一道，共同实现现代化。中国向世界宣示走和平发展道路的意义在于（）。", "options": {"A": "和平发展道路对中国有利，对亚洲有利，对世界也有利", "B": "既积极争取和平的国际环境发展自己，又以自身发展促进世界和平", "C": "既让中国更好利用世界的机遇，又让世界更好分享中国的机遇", "D": "促进中国和世界各国良性互动、互利共赢"}, "answer": "ABCD", "explanation": "【解析】本题考查坚持走和平发展道路。中国走和平发展道路的自信和自觉来源于中华文明的深厚渊源，来源于对实现中国发展目标条件的认知，来源于对世界发展大势的把握。 其意义在于：中国坚持走和平发展道路，既积极争取和平的国际环境发展自己，又以自身发展促进世界和平；既让中国更好利用世界的机遇，又让世界更好分享中国的机遇；促进中国和世界各国良性互动、互利共赢。对中国有利，对亚洲有利，对世界也有利。因此，选项 ABCD 正确。 2．坚持走和平发展道路，是我们党根据时代发展潮流和我国根本利益作出的战略抉择。走和平发展道路（）。 A. 是由中国共产党性质宗旨和我国社会主义制度决定的 B．是基于中国历史文化传统作出的必然选择 C. 是新时代对外工作的总目标 D．符合历史潮流、顺应世界大势", "id": 221},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "近年来，世界经济下行压力加大，我国进出口面临的外部环境趋紧，外贸形势不容乐观。针对这种形势，全面提高对外开放水平，就要把握世界发展大势，实施更为主动的开放战略。这表现为（）。", "options": {"A": "完善互利共赢、多元平衡、安全高效的开放型经济体系", "B": "坚持“引进来”和“走出去”并重", "C": "深化投资、贸易体制改革，完善法律法规", "D": "建设自由贸易试验区"}, "answer": "ABCD", "explanation": "【解析】本题考查全面提高对外开放水平。当今世界正发生复杂深刻的变化，必须实施更加主动的开放战略，完善互利共赢、多元平衡、安全高效的开放型经济体系；坚持出口和进口并重，推动贸易平衡发展；坚持“引进来”和“走出去”并重，提高国际投资合作水平；深化投资、贸易体制改革，完善法律法规，为各国在华企业创造公平经营的法治环境；建设自由贸易试验区，牢牢把握国际通行规则，加快形成与国际投资、贸易通行规则相衔接的基本制度体系和监管模式，既充分发挥市场在资源配置中的决定性作用，又更好发挥政府作用。因此，选项 ABCD 正确。", "id": 222},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "中国共产党已走过百年奋斗历程。我们党立志于中华民族千秋伟业，致力于人类和平与发展崇高事业，责任无比重大，使命无上光荣。全党同志务必不忘初心、牢记使 命，务必谦虚谨慎、艰苦奋斗，务必敢于斗争、善于斗争，坚定历史自信，增强历史主动，谱写新时代中国特色社会主义更加绚丽的华章。党的初心和使命是（）。", "options": {"A": "为中国人民谋幸福，为中华民族谋复兴", "B": "全心全意为人民服务", "C": "实现共产主义社会", "D": "实现共同富裕"}, "answer": "A", "explanation": "【解析】本题考查党的初心和使命，属于记忆题。在党的十九大报告中，习近平总书记开宗明义，强调了中国共产党人的初心和使命是“为中国人民谋幸福，为中华民族谋复兴”。这个初心和使命是激励中国共产党人不断前进的根本动力。因此，选项 A 正确。选项 BCD，与题意不符，故不选。 2\\. 中国特色社会主义最本质的特征、中国特色社会主义制度的最大优势是（）。 A. 人民民主专政 B. 中国共产党领导 C. 依法治国 D. 人民代表大会制度", "id": 223},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "习近平总书记指出：“如果不坚决纠正不良风气，任其发展下去，就会像一座无形的墙把我们党和人民群众隔开，我们党就会失去根基、失去血脉、失去力量。”这表明( )。", "options": {"A": "艰苦奋斗、勤俭节约是我们党的优良作风", "B": "全体党员必须同党中央保持高度一致，自觉维护党中央权威", "C": "党的作风关系人心向背、关系党的生死存亡", "D": "我们要造就高素质的党员干部队伍"}, "answer": "C", "explanation": "【解析】本题考查以严的基调强化正风肃纪。习近平总书记指出的是作风问题的核心，即保持党同人民群众的血肉联系。党的作风关系人心向背、关系党的生死存亡。在任何时候任何情况下，与人民同呼吸共命运的立场不能变，全心全意为人民服务的宗旨不能忘，群众是真正英雄的历史唯物主义观点不能丢，始终坚持立党为公、执政为民。因此，选项C正确。选项ABD，都不是题干表达的意思，故不选。", "id": 224},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "党内政治生活的首要任务是（）。", "options": {"A": "保证全党服从中央", "B": "维护党中央权威和集中统一领导", "C": "营造良好政治生态、提高政治能力", "D": "加强思想教育和理论武装"}, "answer": "D", "explanation": "【解析】加强思想建设是保持政治上清醒坚定、行动上团结统一的要求。政治上坚强根源于思想上坚定，意志上凝聚决定于认识上统一。习近平指出：“欲事立，须是心立。”加强思想教育和理论武装，是党内政治生活的首要任务，是保证全党步调一致的前提。D 正确。保证全党服从中央，维护党中央权威和集中统一领导，是党的政治建设的首要任务。发挥党的政治建设的统领性作用，必须把准政治方向、站稳政治立场、营造良好政治生态、提高政治能力。ABC 错误。 5．全面从严治党是党永葆生机活力、走好新的赶考之路的必由之路，是新时代党的建设的鲜明主题。全面从严治党是一项管党治党的系统工程，全面从严治党的治本之策是( )。 A. 加强制度建设 B. 加强纪律建设 C. 加强作风建设 D. 加强思想建设", "id": 225},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "反腐败是全面从严治党的“必答题”。新时代推进反腐败斗争的鲜明特征是（）。", "options": {"A": "“打虎”“拍蝇”“猎狐”多管齐下", "B": "无禁区、全覆盖、零容忍", "C": "标本兼治", "D": "把权力关进制度的笼子里"}, "answer": "C", "explanation": "【解析】标本兼治是新时代推进反腐败斗争的鲜明特征，既以治标遏制腐败势头，更注重治本夯实防腐的基础。C 正确。ABD 是依靠制度优势、法治优势反腐败的具体内容。", "id": 226},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "把党的建设作为一项伟大工程来推进，是我们党的一大创举，是我们党领导人民进行伟大社会革命的重要法宝。党的建设的一贯要求和根本方针是（）。", "options": {"A": "坚持思想建党和制度治党相统一", "B": "坚持党内监督和群众监督相统一", "C": "自我净化、自我完善、自我革新、自我提高", "D": "党要管党、从严治党"}, "answer": "D", "explanation": "【解析】党的建设的一贯要求和根本方针是党要管党、从严治党，D 正确。AB 是全面 从严治党六条重要经验的其中两条，不符合题意。“四个自我”是实现伟大自我革命的重要途径，C 不符合题意。", "id": 227},{"section": "习近平新时代中国特色社会主义思想概论", "type": "单选题", "stem": "著名民主人士黄炎培先生曾说：“一部历史，‘政怠宦成’的也有，‘人亡政息’的也有，‘求荣取辱’的也有。总之，没有能跳出这个周期率。”如何跳出“其兴也勃焉，其亡也忽焉”的历史周期率，毛泽东给出的答案是“民主”，“只有让人民来监督政府，政府才不敢松懈”。经过不懈努力，我们党找到了跳出治乱兴衰历史周期率的第二个答案，这就是（）。", "options": {"A": "艰苦奋斗", "B": "自我革命", "C": "全面深化改革", "D": "全面依法治国"}, "answer": "B", "explanation": "【解析】本题考查党的自我革命。习近平总书记在中国共产党第二十次全国代表大会上强调：“经过不懈努力，党找到了自我革命这一跳出治乱兴衰历史周期率的第二个答案，确保党永远不变质、不变色、不变味。”因此，选项 B 正确。选项 A，艰苦奋斗是中国共产党的作风之一，故不选。选项 C，全面深化改革是解决中国现实问题的根本途径，故不选。选项 D，全面依法治国是中国特色社会主义的本质要求和重要保障，故不选。 9\\. 把党的建设作为一项伟大工程来推进，是我们党的一大创举，是我们党领导人民进行伟大社会革命的重要法宝。深入推进党的建设，摆在首位的是（）。 A. 政治建设 B. 思想建设 C. 作风建设 D. 制度建设", "id": 228},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "近代以来，为了拯救民族危亡，中国人民奋起反抗，仁人志士奔走呐喊，太平天国农民战争、戊戌维新运动、义和团运动、辛亥革命接连而起，各种救国方案轮番出台，但都以失败而告终。在中国人民和中华民族的伟大觉醒中，在马克思列宁主义同中国工人运动的紧密结合中，中国共产党应运而生，最终成为担当民族复兴重任的时代先锋和民族脊梁。党和人民百年奋斗，书写了中华民族几千年历史上最恢宏的史诗。这些重大成就包括（）。", "options": {"A": "浴血奋战、百折不挠，创造了新民主主义革命的伟大成就", "B": "自力更生、发愤图强，创造了社会主义革命和建设的伟大成就", "C": "解放思想、锐意进取，创造了改革开放和社会主义现代化建设的伟大成就", "D": "自信自强、守正创新，创造了新时代中国特色社会主义的伟大成就"}, "answer": "ABCD", "explanation": "【解析】本题考查党的百年奋斗重大成就。党的十九届六中全会通过的《中共中央关于党的百年奋斗重大成就和历史经验的决议》指出：“一百年来，党领导人民浴血奋战、百折不挠，创造了新民主主义革命的伟大成就；自力更生、发愤图强，创造了社会主义革命和建设的伟大成就；解放思想、锐意进取，创造了改革开放和社会主义现代化建设的伟大成就；自信自强、守正创新，创造了新时代中国特色社会主义的伟大成就。”因此，选项ABCD正确。 2．党的二十大报告指出，中国共产党已走过百年奋斗历程。我们党立志于中华民族千秋伟业，致力于人类和平与发展崇高事业，责任无比重大，使命无上光荣。要坚定历史自信，增强历史主动，谱写新时代中国特色社会主义更加绚丽的华章，要求全党同志（）。 A. 务必不忘初心、牢记使命 B. 务必不骄不躁、勇毅前行 C. 务必谦虚谨慎、艰苦奋斗 D. 务必敢于斗争、善于斗争", "id": 229},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "坚持思想建党、理论强党，坚持加强马克思主义武装，使全党始终保持统一的思想、坚定的意志、协调的行动、强大的战斗力，是党的事业发展的重要法宝。加强思想建 设是（）。", "options": {"A": "坚守理想信念、坚定革命意志的前提", "B": "保持政治上清醒坚定、行动上团结统一的要求", "C": "贯彻党的理论和路线方针政策、推进党和国家事业发展的重要保障", "D": "我们党最大的优势、最鲜明的品格"}, "answer": "ABC", "explanation": "【解析】勇于自我革命，是中国共产党区别于其他政党的显著标志，也是我们党最大的优势、最鲜明的品格。D 错误。ABC 正确。 4．以伟大自我革命引领伟大社会革命是新时代中国特色社会主义发展的显著特点。实现伟大自我革命的重要途径是（）。 A. 自我管理 B. 自我完善 C. 自我革新 D. 自我提高", "id": 230},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "全面建设社会主义现代化国家、全面推进中华民族伟大复兴，关键在党。我们党作为世界上最大的马克思主义执政党，要始终赢得人民拥护、巩固长期执政地位，必须()。", "options": {"A": "时刻保持解决大党独有难题的清醒和坚定", "B": "持之以恒推进全面从严治党", "C": "深入推进新时代党的建设新的伟大工程", "D": "以社会革命引领党的自我革命"}, "answer": "ABC", "explanation": "【解析】本题考查全面从严治党。习近平总书记在党的二十大报告中提出，我们党作为世界上最大的马克思主义执政党，要始终赢得人民拥护、巩固长期执政地位，必须时刻保持解决大党独有难题的清醒和坚定。全党必须牢记，全面从严治党永远在路上，党的自我革命永远在路上，决不能有松劲歇脚、疲劳厌战的情绪，必须持之以恒推进全面从严治党，深入推进新时代党的建设新的伟大工程，以党的自我革命引领社会革命。因此，选项 ABC 正确。选项 D，混淆了“党的自我革命”和“社会革命”之间的关系，应该是“以党的自我革命引领社会革命”，故不选。", "id": 231},{"section": "习近平新时代中国特色社会主义思想概论", "type": "多选题", "stem": "党要管党、从严治党，是党的建设的一贯要求和根本方针。全面从严治党是）。", "options": {"A": "党永葆生机活力、走好新的赶考之路的必由之路", "B": "新时代党的建设的鲜明主题", "C": "党的政治建设的首要任务", "D": "新时代党的自我革命的伟大实践"}, "answer": "ABD", "explanation": "【解析】全面从严治党是党永葆生机活力、走好新的赶考之路的必由之路，是新时代党的建设的鲜明主题。AB 正确。如何跳出历史周期率？如何实现长期执政？党始终在思索、一直在探索。毛泽东在延安的窑洞里给出了第一个答案，这就是“让人民来监督政府”。经过百年奋斗特别是党的十八大以来新的实践，党又给出了第二个答案，这就是自我革命。全面从严治党是新时代党的自我革命的伟大实践，开辟了百年大党自我革命的新境界。D 正确。保证全党服从中央，维护党中央权威和集中统一领导，是党的政治建设的首要任务。C 错误。", "id": 232},{"section": "中国近现代史纲要", "type": "单选题", "stem": "下列最能说明清政府已成为“洋人的朝廷”的是（）。", "options": {"A": "外国公使进驻北京", "B": "列强控制京津地区", "C": "保证严禁中国人民反对外国侵略", "D": "改总理衙门为外务部"}, "answer": "C", "explanation": "【解析】20世纪初，帝国主义列强在中国的侵略日益扩大。它们在迫使清政府签订《辛丑条约》以后，加强了对清政府的政治控制，多方扩展在华经济势力。1901年签订的", "id": 233}];